import Long from "long";
import protobuf from "protobufjs";

//=============================================================
// 引擎
import {
_decorator, Component, Node, Button, log, Tween, KeyCode, Input, input, EventKeyboard,
SpriteAtlas, ResolutionPolicy, view, Event, sys, EventTouch, screen, SpriteFrame, Animation, AudioClip, error,
BufferAsset, Label, tween, v3, sp, Sprite,
JsonAsset
} from "cc";

//=============================================================
// 框架
import { AstarteInit } from "db://astarte-framework/System";
import { SwitchOffKeyDefine } from "db://astarte-framework/License/LicenseSetting";
import { ConnectionManager } from "db://astarte-framework/net/ConnectionManager";
import {
msgBoxManager, MsgBoxSetting, localeStringManager, newBottombarManager, newExtraManager,
SlotBottomBarState, stateManager, BottomBar_UIName, commonGameManager, eventManager, CommonEventName, giftCodeManager,
backpackManager, missionManager, gaiaManager, iframeCommandManager, AutoplayType_ORG, BetValueChange, buyBonusManager, debrisManager
} from "db://astarte-framework/Managers";
import { CommonBuyBonus } from "db://astarte-framework/Component/BuyBonus/CommonBuyBonus";
import ManualComponent from "db://astarte-framework/Component/ManualComponent";
import { tools, Define, CommonState, extraBetController } from "db://astarte-framework/utilis";
import BigWinComponent, { BigWinAnimName } from "db://astarte-framework/Component/BigWinComponent";
import ExtraBetComponent from "db://astarte-framework/Component/ExtraBetComponent";

//=============================================================
// 遊戲定義
import Game_Define, { FeverGameType, GAME_EVENT } from "./Game_Define";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "./MultBase/MultiplierBaseManager";

//=============================================================
// 遊戲狀態
import { WaitResState } from "./GameState/WaitResState";
import { WaitReadyState } from "./GameState/WaitReadyState";
import { PlateShowState } from "./GameState/PlateShowState";
import { IdleState } from "./GameState/IdleState";
import { SpinState } from "./GameState/SpinState";
import { AwardState } from "./GameState/AwardState";
import { RoundEndState } from "./GameState/RoundEndState";
import { RoundShowEndState } from "./GameState/RoundShowEndState";
import { UnshowPrepareState } from "./GameState/UnshowPrepareState";
import { FeatureShowState } from "./GameState/FeatureShowState";
import { CheckState } from "./GameState/CheckState";
import { EnterFreeState } from "./GameState/EnterFreeState";
import { FreePickRouletteState } from "./GameState/FreePickRouletteState";
import { EffectStartState } from "./GameState/EffectStartState";
import { ScatterShowState } from "./GameState/ScatterShowState";
import { AddFreeState } from "./GameState/AddFreeState";
import { FullRewardState } from "./GameState/FullRewardState";
import { LeaveFreeState } from "./GameState/LeaveFreeState";
import { ExplodeState } from "./GameState/ExplodeState";
import { MatchingPatchUpState } from "./GameState/MatchingPatchUpState";
import { CountMultState } from "./GameState/CountMultState";
import { WantedPosterState } from "./GameState/WantedPosterState";

//=============================================================
// 協定
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { RecoverSpinAck } from "./RecoverSpinAck";

//=============================================================
// 遊戲介面
import { SlotReel } from "./SlotReels";
import { GAME_INTRO_MANAGER_EVENT } from "./GameIntroManager";

//=============================================================
// 遊戲效果
import EffectPlate from "./EffectPlate/EffectPlate";

//=============================================================
// 音樂音效
import { AudioManager, ConcurrentOverflowStrategy } from "./Audio/AudioManager";

//=============================================================
// 其他
import { Common } from "./Common/Common";
import { PopupSpine } from "./Spine/PopupSpine";
import { DEBUG_TOOL_EVENT } from "./DebugToolManager";
import { REEL_UI_MANAGER_EVENT } from "./Reel/ReelManager";
import { FREE_GAME_DECLARE_MANAGER_EVENT } from "./FreeGame/FreeGameDeclareManager";
import { RT_EVENT } from "./RTCtrl";
import { BS_SPINE_CTRL_EVENT } from "./BSSpineCtrl";
import { WANTED_POSTER_MANAGER_EVENT } from "./WantedPoster/WantedPosterManager";
import { BS_SPINE_TYPE } from "./BSSpineCtrl";
import { CHARACTER_ANIM_NAME } from "./BSSpineCtrl";
import { ExtraBetWindow } from "./ExtraBet/ExtraBetWindow";
import { AddSpinFlyEffect } from "./FreeGame/AddSpinFlyEffect";
//=============================================================
//#region 變數
/**@ch 設計寬度 */
const WIDTH = 1136;

/**@ch 設計高度 */
const HEIGHT = 640;

/**@ch 旋轉動畫 橫版 */
const ROTATION_ANIMATION_LANDSCAPE = "MainGame_L";

/**@ch 旋轉動畫 直版 */
const ROTATION_ANIMATION_PORTRAIT = "MainGame_S";

/**@ch 作弊鍵 */
const CHEAT_KEY = {
    FREE_GAME: 92111,
}
//#endregion 變數

const { ccclass, property } = _decorator;

@ccclass('GameView')
export default class GameView extends Component {

    @property( {
        type: Animation,
        tooltip: "主遊戲動畫"
    } )
    private m_mainGameAnimation: Animation = null;

    @property( {
        type: CommonBuyBonus,
        tooltip: "購買Bonus"
    } )
    private m_buyBonus: CommonBuyBonus = null;
    public get BuyBonus(): CommonBuyBonus
    {
        return this.m_buyBonus;
    }

     @property({
        type: ExtraBetComponent,
        tooltip: "Extra Bet 加倍投注元件"
    })
    private m_extraBetComp: ExtraBetComponent = null;

    @property( {
        type: ExtraBetWindow,
        tooltip: "Extra Bet 兩步驟選擇跳窗"
    } )
    private m_extraBetWindow: ExtraBetWindow = null;

    @property( {
        type: Animation,
        tooltip: "ExtraBet EX 節點(ExtraBetNode 根)的 Animation：兩步驟取消時補播 ExtraBet_OFF 熄滅發亮用"
    } )
    private a_extraBetAnimation: Animation = null;

    /** @ch 押注倍率表（info.Mul）：Mul[0]=基礎倍率，Mul[1..]=ExtraBet 各種倍率。unshow 還原時用來反推當初選的 type */
    private m_betMultipliers: number[] = [];

    /** @ch ExtraBet type → 乘倍底板 index 對映（下標即 type）：type0(關)→0、type1→1、type2→2、type3→6 */
    private static readonly EXTRA_BET_BASE_INDEX: number[] = [ 0, 1, 2, 6 ];

    /** @ch 目前 ExtraBet type（0=關閉）；供 SpinState 開轉時判斷是否維持 ExtraBet 底板 */
    private m_curExtraBetType: number = 0;
    public get CurExtraBetType(): number { return this.m_curExtraBetType; }

    /** @ch 本次連線 server 是否提供 ExtraBet 功能（info.ShowExtra）；false 則整個 ExtraBet 不顯示/不還原 */
    private m_showExtra: boolean = false;

    @property( {
        type: SlotReel,
        tooltip: "轉輪"
    } )
    private m_slotReels: SlotReel = null;
    public get SlotReels(): Readonly<SlotReel>
    {
        return this.m_slotReels;
    }

    @property( {
        type: EffectPlate,
        tooltip: "盤面表演"
    } )
    private m_effectPlate: EffectPlate = null;
    public get EffectPlate(): EffectPlate
    {
        return this.m_effectPlate;
    }

    @property( {
        type: Button,
        tooltip: "盤面spin"
    } )
    private m_plateSpinBtn: Button = null;

    @property( {
        type: SpriteAtlas,
        tooltip: "標題合圖"
    } )
    private m_titleSpriteAtlas: SpriteAtlas = null;

    @property( {
        type: ManualComponent,
        tooltip: "ManualComponent"
    } )
    private m_manual: ManualComponent = null;
    public get Manual()
    {
        return this.m_manual;
    }

    @property({
        type: BigWinComponent,
        tooltip: "big win"
    })
    private m_bigWin: BigWinComponent = null;
    public get BigWin(): BigWinComponent {
        return this.m_bigWin;
    }

    @property({
        type: PopupSpine,
        tooltip: "小獎/乘倍贏分 Spine 面板"
    })
    private m_popupBoard: PopupSpine = null;
    public get PopupBoard(): PopupSpine {
        return this.m_popupBoard;
    }

    @property({
        type: AddSpinFlyEffect,
        tooltip: "免費遊戲加手數光拖尾演出"
    })
    private m_addSpinFlyEffect: AddSpinFlyEffect = null;
    public get AddSpinFlyEffect(): AddSpinFlyEffect {
        return this.m_addSpinFlyEffect;
    }

    // 小贏分
    @property( {
        type: Node,
        tooltip: "SmallWin 動畫節點"
    } )
    private m_smallWinNode: Node = null;
    @property( {
        type: Label,
        tooltip: "SmallWin Label"
    } )
    private m_winLabel: Label = null;

    /*************************************************** 各遊戲特色區 ***************************************************/
    @property({ type: Node, tooltip: "RouletteSpine 節點（FGBoard_Wheel）" })
    public RouletteSpineNode: Node = null;

    @property({ type: Node, tooltip: "Roulette 父節點（轉輪顯示位置）" })
    public RouletteNode: Node = null;

    @property({ type: Node, tooltip: "Roulette_Down 節點（RouletteSpine 預設位置）" })
    public RouletteDownNode: Node = null;

    @property({ type: Node, tooltip: "UpdateBoardSpine 節點（Update面板 Spine）" })
    public UpdateBoardSpineNode: Node = null;

    @property({ type: Node, tooltip: "FeatureIconSpine 節點（UpdateBoard 底下的 feature icon）" })
    public FeatureIconSpineNode: Node = null;



    @property({ type: Node, tooltip: "Explode 節點（UpdateBoard 底下的爆炸動畫）" })
    public ExplodeSpineNode: Node = null;

    @property({ type: sp.Skeleton, tooltip: "FGBoard_Upgrades_In Spine（直版進場特效）" })
    public UpgradesInSpine: sp.Skeleton = null;

    @property({ type: sp.Skeleton, tooltip: "RouletteSpine" })
    public RouletteSpine: sp.Skeleton = null;

    @property({ type: sp.Skeleton, tooltip: "FGBoard_Rudder_Base Spine（橫版轉盤底座）" })
    public RudderBaseSpine: sp.Skeleton = null;

    @property({ type: sp.Skeleton, tooltip: "FGBoard_Upgrade_Cannon Spine" })
    public UpgradeCannonSpine: sp.Skeleton = null;

    @property({ type: sp.Skeleton, tooltip: "Feature 選定效果 Spine（Icon Bingo/Black）" })
    public FeatureSelectSpine: sp.Skeleton = null;

    @property({ type: Node, tooltip: "轉盤進場時開啟、退場後關閉的提示節點" })
    public RouletteNoteNode: Node = null;



    @property({ type: sp.Skeleton, tooltip: "PointerSpine（指針 Spine，與轉盤同步 In/Loop/Out）" })
    public PointerSpine: sp.Skeleton = null;

    @property({
        type: String,
        tooltip: "動態載入資源路徑，game資料夾以後的路徑，結尾帶/，一般版留空"
    })
    private m_loadPath = "";

    //自動玩
    private m_autoplayInfos: AutoplayType_ORG = null;
    public get AutoplayInfos(): AutoplayType_ORG
    {
        return this.m_autoplayInfos;
    }

    //狀態
    private m_isLandscape: boolean = false;
    public get IsLandscape(): Readonly<boolean>
    {
        return this.m_isLandscape;
    }   

    /**@ch 是否鎖定旋轉 */
    private m_isLockRotation: boolean = false;
    public get IsLockRotation(): boolean {
        return this.m_isLockRotation;
    }
    public set IsLockRotation(v: boolean) {
        this.m_isLockRotation = v;
    }

    private m_isBottombarFinished: boolean = false;
    public get IsBottombarFinished(): boolean
    {
        return this.m_isBottombarFinished;
    }

    private m_isFirstPlateSpin: boolean = true;

    private m_isHardStop: boolean = false;
    public set IsHardStop( v: boolean )
    {
        this.m_isHardStop = v;
    }

    public get IsHardStop(): boolean
    {
        return this.m_isHardStop;
    }

    /**@ch 目前spinAck */


    /**@ch 目前spinAck_Test */
    private m_spinAck_Test: protocol.ar2pq9Proto.ISpinAck = null;
    public get SpinAck(): Readonly<protocol.ar2pq9Proto.ISpinAck>
    {
        return this.m_spinAck_Test;
    }
    public set SpinAck( v: protocol.ar2pq9Proto.ISpinAck )
    {
        this.m_spinAck_Test = v;
    }

    /**@ch 斷線重連的spinAck */
    private m_unshowSpinAck: protocol.ar2pq9Proto.ISpinAck = null;
    public set UnshowSpinAck( v: protocol.ar2pq9Proto.ISpinAck )
    {
        this.m_unshowSpinAck = v;
    }
    public get UnshowSpinAck(): protocol.ar2pq9Proto.ISpinAck
    {
        return this.m_unshowSpinAck;
    }

    private m_curRoundIndex: number = -1;
    /**@ch 目前局數 */
    public get CurRoundIndex(): Readonly<number>
    {
        return this.m_curRoundIndex;
    }
    public set CurRoundIndex( v: number )
    {
        this.m_curRoundIndex = v;
        if (v < 0) {
            this.m_curPlateIndex = 0;
        }
    }

    private m_curPlateIndex: number = 0;
    /**@ch 目前盤數 */
    public get CurPlateIndex(): Readonly<number>
    {
        return this.m_curPlateIndex;
    }
    public set CurPlateIndex( v: number )
    {
        this.m_curPlateIndex = v;
    }

    private m_curExplodeDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
    public get CurExplodeDataVec(): protocol.ar2pq9Proto.IAwardData[]
    {
        return this.m_curExplodeDataVec;
    }
    public set CurExplodeDataVec( v: protocol.ar2pq9Proto.IAwardData[] )
    {
        this.m_curExplodeDataVec = v;
    }
    public get CurExplodeDataVecLength(): Readonly<number>
    {
        return this.m_curExplodeDataVec.length;
    }

    /**@ch 暫存待顯示結果的 award 資訊（等 EXPLODE 後顯示）*/
    public PendingAwardResults: { pos: number, win: number, fullResult: string, isLeft: boolean }[] = [];

    /**@ch 已 POP 的乘倍位置，等 symbol 消除時才 PUSH 沉回去*/
    public PendingMultiplierPushPositions: number[] = [];

    //log
    private m_spinClickEvent: number = 0;

    /** BGM ID*/
    private m_bgmId: number = -1;
    public set BgmId( v: number )
    {
        this.m_bgmId = v;
    }
    public get BgmId(): number
    {
        return this.m_bgmId;
    }

    private m_freeBgmId: number = -1;
    public set FreeBgmId( v: number )
    {
        this.m_freeBgmId = v;
    }
    public get FreeBgmId(): number
    {
        return this.m_freeBgmId;
    }

    /** 大獎音效ID*/
    private m_bigWinSoundId: number = null;
    public get BigWnSoundId()
    {
        return this.m_bigWinSoundId;
    }
    public set BigWnSoundId( v: number )
    {
        this.m_bigWinSoundId = v;
    }

    /**@ch 空白鍵按停 */
    private m_canSpaceStop: boolean = true;
    public set CanSpaceStop( v: boolean )
    {
        this.m_canSpaceStop = v;
    }
    public get CanSpaceStop()
    {
        return this.m_canSpaceStop;
    }

    /**@ch 盤面按停 */
    private m_canPlateStop: boolean = true;
    public set CanPlateStop( v: boolean )
    {
        this.m_canPlateStop = v;
    }
    public get CanPlateStop()
    {
        return this.m_canPlateStop;
    }

    /**@ch 大獎跳過保護（0.5s 後才允許跳過） */
    private m_canStopBigWin: boolean = false;
    public set CanStopBigWin( v: boolean )
    {
        this.m_canStopBigWin = v;
    }
    public get CanStopBigWin()
    {
        return this.m_canStopBigWin;
    }

    /**@ch 實際的特色spinAck */
    private m_realFeatureSpinAck: Array<protocol.ar2pq9Proto.ISpinAck> = null;

    //自動顯示特色
    private m_isAutoShowFeatures: boolean = false;
    public set IsAutoShowFeatures( v: boolean )
    {
        this.m_isAutoShowFeatures = v;
    }
    public get IsAutoShowFeatures()
    {
        return this.m_isAutoShowFeatures;
    }

    /**@ch 現在在FG中 */
    private m_isFreeGame: boolean = false;
    /**@ch 是否在FG中 */
    public get IsFreeGame(): boolean
    {
        return this.m_isFreeGame;
    }
     public set IsFreeGame( v: boolean )
    {
        this.m_isFreeGame = v;
    }

    /**@ch 舊盤面For斷線重連 */
    private m_oldRealPlate: Array<protocol.ar2pq9Proto.Column> = new Array<protocol.ar2pq9Proto.Column>();
    public set OldRealPlate( v: Array<protocol.ar2pq9Proto.Column> )
    {
        this.m_oldRealPlate = v;
    }
    public get OldRealPlate()
    {
        return this.m_oldRealPlate;
    }

    private m_isManualHardStop: boolean = false;
    public get IsManualHardStop(): boolean
    {
        return this.m_isManualHardStop;
    }

    /**@ch 是否為FG第一局 */
    private m_isFirstRound: boolean = true;
    public get IsFirstRound()
    {
        return this.m_isFirstRound;
    }
    public set IsFirstRound( v: boolean )
    {
        this.m_isFirstRound = v;
    }

    /**@ch 要進FG之旗標 */
    private m_isGoingToFree: boolean = false;
    public get IsGoingToFree()
    {
        return this.m_isGoingToFree;
    }
    public set IsGoingToFree( v: boolean )
    {
        this.m_isGoingToFree = v;
    }

    /**@ch 當局資料 */
    private m_roundInfo: protocol.ar2pq9Proto.IRoundInfo = null;
    public get RoundInfo()
    {
        return this.m_roundInfo;
    }
    public set RoundInfo( v: protocol.ar2pq9Proto.IRoundInfo )
    {
        this.m_roundInfo = v;
    }

    /**@ch 累積贏分 */
    private m_AccumulatedWin: number = 0;
    public get AccumulatedWin() {
        return this.m_AccumulatedWin;
    }
    public set AccumulatedWin(v: number) {
        this.m_AccumulatedWin = v;
    }

    /**@ch Scatter中獎資料 */
    private m_scatterAward: protocol.ar2pq9Proto.IAwardData = null;
    public get ScatterAward(): protocol.ar2pq9Proto.IAwardData
    {
        return this.m_scatterAward;
    }
    public set ScatterAward( v: protocol.ar2pq9Proto.IAwardData )
    {
        this.m_scatterAward = v;
    }

    /**@ch 免費遊戲總局數 */
    private m_freeTotalRound: number = 0;
    public set FreeTotalRound( v: number )
    {
        this.m_freeTotalRound = v;
    }
    public get FreeTotalRound(): number
    {
        return this.m_freeTotalRound;
    }

    /** @ch FG 轉盤強化結果（進 FG 時存，整個 FG 期間有效） */
    private m_freePickItems: number[] = [];
    public get FreePickItems(): number[] { return this.m_freePickItems; }
    public set FreePickItems(v: number[]) { this.m_freePickItems = v || []; }

    /** @ch 是否有 ScatterBoost 強化 */
    public get HasScatterBoost(): boolean { return this.m_freePickItems.indexOf(2) >= 0; }

    private m_bigWinId: number = null;
    /** 震動緩動 */
    private m_bigHintShake: Tween<Node> = null;
    private m_shakeOriginX: number = 0;
    private m_shakeOriginY: number = 0;


    /************************************************** INFO DATA **************************************************/

    /**@ch Symbol圖*/
    private m_symbolSpriteFrames: SpriteFrame[] = [];

    /**@ch Symbol背景圖*/
    @property({
        type: SpriteFrame,
        tooltip: "Symbol背景圖"
    })
    private m_symbolBackgroundSpriteFrames: SpriteFrame[] = [];

    /**@ch 出此表演時不能按停 */
    private m_isMgOmen: boolean = false;
    public set IsMgOmen( v: boolean )
    {
        this.CanPlateStop = !v;
        this.CanSpaceStop = !v;
        this.m_isMgOmen = v;
    }
    public get IsMgOmen()
    {
        return this.m_isMgOmen;
    }

    private m_logoSpriteFrame: SpriteFrame = null;
    public get LogoSprite(): SpriteFrame
    {
        return this.m_logoSpriteFrame;
    }

    private m_version: string = Game_Define.Ver;
    public get Version()
    {
        return this.m_version;
    }

    // 總贏分
    private m_win: number = 0;
    public get Win(): number
    {
        return this.m_win;
    }
    public set Win( v: number )
    {
        this.m_win = v;
    }

    /** 單局贏分 */
    private m_roundWin: number = 0;
    public get RoundWin(): number
    {
        return this.m_roundWin;
    }
    public set RoundWin( v: number )
    {
        this.m_roundWin = v;
    }

    @property({
        type: BufferAsset,
        displayName: "二進制資料給Demo用"
    })
    private m_BinaryFileForDemo: BufferAsset[] = [];



    onLoad() {

        protobuf.util.Long = Long;
        protobuf.configure();
        AstarteInit();

        Define.IsInMG = (): boolean => {
            return !this.IsFreeGame;
        };

        Define.CURRENCY_CHANGE_ENABLE = true;

        // 系統初始化
        Common.Init( this );
        this.m_slotReels.Init( this );
        this.m_effectPlate.Init( this );

        // 音效並發限制設定，避免音源池滿擠掉 BGM
        AudioManager.SetDefaultConcurrentLimit(24);
        AudioManager.SetOverflowStrategy(ConcurrentOverflowStrategy.REPLACE_OLDEST);
        AudioManager.SetConcurrentLimit("symboldrop", 6);

        // BigWin 初始化（音效回調 + 幣別顯示）
        this.m_bigWin?.Init(
            ( name: string, strValue: string, animName: string ) =>
            {
                switch ( strValue )
                {
                    case "Sound1":
                        if ( this.m_bigWinSoundId == null )
                        {
                            this.PauseMainGameBgm();
                            this.m_bigWinSoundId = AudioManager.Play( AudioManager.AudioClips.win_count_in, true );
                        }
                        else
                        {
                            if ( animName === BigWinAnimName.Mega.Start )
                            {
                                AudioManager.Play( AudioManager.AudioClips.win_up_1 );
                            }
                            else if ( animName === BigWinAnimName.Super.Start )
                            {
                                AudioManager.Play( AudioManager.AudioClips.win_up_2 );
                            }
                        }
                        break;
                    case "Sound2":
                        if ( this.m_bigWinSoundId != null )
                        {
                            AudioManager.Stop( this.m_bigWinSoundId );
                            this.m_bigWinSoundId = null;
                        }
                        AudioManager.Play( AudioManager.AudioClips.win_count_end, false, () =>
                        {
                            this.ResumeMainGameBgm();
                        } );
                        break;
                }
            },
            ( value: number ) =>
            {
                return newBottombarManager.GetDisplayValue( value );
            }
        );

        this.OnRotation();
        tools.AddOnRotationCb(() => {
            this.OnRotation();
        });

        if (!sys.isNative) {
            window.onbeforeunload = () => {

            };

            window.onerror = (errorMessage, scriptURI, lineNumber, columnNumber, errorObj) => {
                let id = "-1";
                let apiId = 0;
                if (Define.APP) {
                    id = Define.APP.GetAID();
                    apiId = Number(Define.APP.GetApiID());
                }
                let params = ConnectionManager.FormErrorParams(
                    id,
                    apiId,
                    Number(Define.NOW_GAME_ID),
                    Game_Define.Ver,
                    errorObj
                );
                ConnectionManager.SendErrorLog(params);
            };
        }
    }

    start() {
        this.LoadSymbol();

        if (!tools.CheckSwitchOff(SwitchOffKeyDefine.NoQuickSpin)) {
            input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {
                switch (event.keyCode) {
                    case KeyCode.SPACE:
                        if (
                            msgBoxManager.IsShow()
                            || !newBottombarManager
                            || newExtraManager.IsShowBackpack()
                        ) {
                            break;
                        }

                        newBottombarManager.SendSpinLog();
                        this.ClickSpin();
                        this.ClickStop();
                        break;
                }
            });
        }

        this.m_bigWin.Init(
            ( name: string, strValue: string, animName: string ) =>
            {
                switch ( strValue )
                {
                    case "Sound1":
                        if ( this.m_bigWinId == null )
                        {
                            if ( this.m_bgmId != null )
                            {
                                AudioManager.SetVolume( this.m_bgmId, 0 );
                            }
                            this.m_bigWinId = AudioManager.Play( AudioManager.AudioClips.Big_Win );
                        }
                        else
                        {
                            if ( animName == BigWinAnimName.Mega.Start )
                            {
                                AudioManager.Play( AudioManager.AudioClips.Change_Win );
                            }
                            else if ( animName == BigWinAnimName.Super.Start )
                            {
                                AudioManager.Play( AudioManager.AudioClips.Change_Win_2 );
                            }
                        }
                        break;
                    case "Sound2":
                        if ( this.m_bigWinId != null )
                        {
                            AudioManager.Stop( this.m_bigWinId );
                            this.m_bigWinId = null;
                        }
                        AudioManager.Play( AudioManager.AudioClips.Big_Win_End, false, () =>
                        {
                            if ( this.m_bgmId != null )
                            {
                                AudioManager.SetVolume( this.m_bgmId, 1 );
                            }
                        } );

                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
                            CHARACTER_ANIM_NAME.Win0, false, () => {});

                        break;
                }
            },
            ( value: number ) =>
            {
                return newBottombarManager.GetDisplayValue( value );
            } );

        this.SetStateMachine();

        if (tools.CheckSwitchOff(SwitchOffKeyDefine.CloseManual)) {
            if (this.m_manual) {
                this.m_manual.node.active = false;
            }
        }

        commonGameManager.SetGameCb(this);

        eventManager.Dispatch(FREE_GAME_DECLARE_MANAGER_EVENT.INIT, this);

        eventManager.Dispatch(RT_EVENT.INIT);

        // 初始化Extra Bet
        this.InitExtraBet();
    }

