    //#region 裝置旋轉
    /**@ch 裝置旋轉 */
    OnRotation() {
        // 取得螢幕寬高
        let size = screen.windowSize;


        // // 判斷橫版
        if (!this.m_isLockRotation) {
            this.m_isLandscape = size.width > size.height;
            eventManager.Dispatch(RT_EVENT.INIT);
        }

        if (!this.m_isLockRotation) {
            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.SET_IS_LANDSCAPE, this.m_isLandscape);
        }

        // 預設值
        let designWidth = WIDTH;
        let designHeight = HEIGHT;
        let policy = ResolutionPolicy.FIXED_WIDTH;
        let animation = this.m_isLandscape ? ROTATION_ANIMATION_LANDSCAPE : ROTATION_ANIMATION_PORTRAIT;

        // 直版
        if (!this.m_isLandscape) {
            designWidth = HEIGHT;
            designHeight = WIDTH;
            // 依照高寬比決定策略
            policy = (size.height / size.width <= WIDTH / HEIGHT)
                ? ResolutionPolicy.FIXED_HEIGHT
                : ResolutionPolicy.FIXED_WIDTH;
        }
        // 橫版
        else {
            // 依照寬高比決定策略
            policy = (size.width / size.height <= WIDTH / HEIGHT)
                ? ResolutionPolicy.FIXED_WIDTH
                : ResolutionPolicy.FIXED_HEIGHT;
        }

        // 旋轉動畫
        if (!this.m_isLockRotation) {
            this.m_mainGameAnimation?.play(animation);
        }

        view.setDesignResolutionSize(designWidth, designHeight, policy);
        newBottombarManager.OnRotation(this.m_isLandscape, () => {}, true);
        newExtraManager?.OnRotation(this.m_isLandscape, true, false);
        msgBoxManager?.OnRotate(this.m_isLandscape);
        this.m_extraBetComp?.OnRotation();

        /**@ch 發送裝置旋轉事件 */
        eventManager.Dispatch(GAME_EVENT.DEVICE_ROTATION, this.m_isLandscape);
    }
