1827	        // 載入音效混音設定檔（BGM_SFX.json），讓 AudioManager 套用每個 clip 的 volume / loop / limit
1828	        const loadSettingJson = () =>
1829	        {
1830	            Define.GameBundle.load( "Sound/audio_config", JsonAsset, ( err: Error | null, jsonAsset: JsonAsset ) =>
1831	            {
1832	                if ( err )
1833	                {
1834	                    error( err.message || err );
1835	                    loadSettingJson();
1836	                    return;
1837	                }
1838	                AudioManager.SetSettingJson( jsonAsset );
1839	            } );
1840	        };
1841	        loadSettingJson();
1842	            
1843	        //音效
1844	        let load = ( path: string, cb: ( clip: AudioClip ) => void ) =>
1845	        {
1846	            Define.GameBundle.load( path, ( err: Error, audioClip: AudioClip ) =>
1847	            {
1848	                if ( err )
1849	                {
1850	                    error( err.message || err );
1851	                    load( path, cb );
1852	                    return;
1853	                }
1854	                cb && cb( audioClip );
1855	            } );
1856	        };
1857	
1858	        for ( const key in AudioManager.AudioClips )
1859	        {
1860	            if ( AudioManager.AudioClips.hasOwnProperty( key ) )
1861	            {
1862	                const audioClip = AudioManager.AudioClips[ key ];
1863	                load( AudioManager.AudioFileRoot + audioClip.FileName, ( audioClip: AudioClip ) =>
1864	                {
1865	                    AudioManager.AudioClips[ key ].Clip = audioClip;
1866	                    AudioManager.AddAudioClips([audioClip]);
1867	                } );
1868	            }
1869	        }
1870	
1871	        // Wanted_in、Wanted_burn、Wanted_MultiAdd 同時間最多只能播放 1 次（避免多組並行刷新時重疊）
1872	        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_in.FileName, 1 );
1873	        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_burn.FileName, 1 );
1874	        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_MultiAdd.FileName, 1 );
1875	    }
