2005	    private InitExtraBet() {
2006	        this.m_extraBetComp?.Init(
2007	            async (_isActive: boolean, _isForce: boolean) =>
2008	            {
2009	                this.ClearAllForExtraBet();
2010	                if (_isActive && !_isForce) {
2011	                    await this.PlayExtraBetActiveAnimation();
2012	                    // ShowAndWait：Promise.all 在此等待，使 m_ExtraBetAniPlaying=true 直到使用者操作完畢
2013	                    const result = await this.m_extraBetWindow?.ShowAndWait();
2014	                    const confirmed = result?.confirmed ?? false;
2015	                    const type = result?.type ?? 0;
2016	                    // 由 GameView 呼叫 SetTwoStepMulti，確保在 Promise.all 解鎖前完成 bet 切換或復原
2017	                    await this.m_extraBetComp?.SetTwoStepMulti( confirmed, type );
2018	                    // 依選中 type 切換乘倍底板（取消時 type=0，自然切回關閉）
2019	                    this.SetMultiplierBaseByExtraBetType( type );
2020	                    // 取消（未選/×/未選即 Confirm，confirmed=false）時：公版 ChangeBetMode 會在本
2021	                    // callback 結束後無條件 play "ExtraBet_Active" 重新點亮 EX 按鈕（公版 :507 漏判
2022	                    // m_isExtra，不可改公版）。於次幀（晚於公版那行）直接在 EX 節點 Animation 補播
2023	                    // "ExtraBet_OFF" 並跳到結尾，蓋掉那次誤點亮、熄滅 FX 發亮（bar 維持展開不收回）。
2024	                    // 註：公版 OnRotation 播的 "ExtraBet_Stop" 在本專案無對應 .anim，故直接控 Animation。
2025	                    if ( !confirmed ) {
2026	                        this.scheduleOnce( () => {
2027	                            if ( this.a_extraBetAnimation ) {
2028	                                this.a_extraBetAnimation.play( "ExtraBet_OFF" );
2029	                                const state = this.a_extraBetAnimation.getState( "ExtraBet_OFF" );
2030	                                if ( state ) state.setTime( state.duration );
2031	                            }
2032	                        }, 0 );
2033	                    }
2034	                } else if (!_isActive) {
2035	                    // 關閉 ExtraBet → 乘倍底板切回 index 0 並隱藏
2036	                    this.SetMultiplierBaseByExtraBetType( 0 );
2037	                }
