2053	    public async RestoreExtraBetState() {
2054	        if ( !this.m_showExtra ) return;   // server 未開放 ExtraBet → 不還原
2055	
2056	        // (A) 治本：先確保 EX 節點 active。framework ForceSetExtraBet 內部會 await
