2067	        const EXTRA_BET_FORCE_TIMEOUT_SEC = 2;
2068	        await Promise.race( [
2069	            this.m_extraBetComp?.ForceSetExtraBet( true, type ) ?? Promise.resolve(),
2070	            new Promise<void>( resolve => this.scheduleOnce( resolve, EXTRA_BET_FORCE_TIMEOUT_SEC ) ),
2071	        ] );
2072	
2073	        // 強制還原路徑 callback 拿不到 type，在此依還原的 type 補切乘倍底板
2074	        this.SetMultiplierBaseByExtraBetType( type );
2075	    }
