2089	            error( `[GameView] ExtraBet 還原資料不足 (mul=${mul}, baseBet=${baseBet})，保底用 type=${FALLBACK_TYPE}` );
2090	            return FALLBACK_TYPE;
2091	        }
2092	
2093	        const target = tools.times( realBet, mul[ 0 ] );
2094	        for ( let type = 1; type < mul.length; type++ ) {
2095	            if ( tools.times( baseBet, mul[ type ] ) === target ) {
2096	                return type;
2097	            }
2098	        }
