2100	        error( `[GameView] ExtraBet 倍率對不上 (baseBet=${baseBet}, realBet=${realBet}, mul=${mul})，保底用 type=${FALLBACK_TYPE}` );
2101	        return FALLBACK_TYPE;
2102	    }
