    /**
     * @ch 處理從伺服器接收到的轉輪結果
     * @param ack 轉輪結果
     * @param isUnshow 是否為斷線重連
     */
    async OnRecvSpinAck( ack, isUnshow = false )
    {
        error( "SpinAck before :", ack );

        // 處理從伺服器接收到的轉輪結果
        let info = RecoverSpinAck.getInstance().RecoverFromSpinAck( ack );
        error( "SpinAck after:", info );

        this.SpinAck = info;
        this.m_buyBonus?.CleanInfo();
        if (!isUnshow) {
            this.AccumulatedWin = 0;
        }

        // 判斷是否要進入FG
        if (this.SpinAck.RoundQueue.length > 1) {
            if ( !isUnshow || this.CurRoundIndex === 0 ) {
                const firstRoundInfo = this.SpinAck.RoundQueue[0];
                if (firstRoundInfo.NextFeverGameType === FeverGameType.FreeGame) {
                    this.IsGoingToFree = true;
                    // 存 FreePickItem 供整個 FG 期間使用
                    if (firstRoundInfo.FreePickItem && firstRoundInfo.FreePickItem.length > 0) {
                        this.FreePickItems = firstRoundInfo.FreePickItem as number[];
                    }
                }
            }
        }

        // 地Bar按鈕狀態
        if ( newBottombarManager.IsAutoSpin && !this.m_isHardStop )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
        }

        // 掉出已在 StartSpin（按 Spin 時）觸發，此處等舊盤掉完 → 播大獎預告（蓋空盤）→ 新盤進場。
        // unshow 走同函式自動受惠（StartSpin 在 OnEnter 已觸發掉出）。
        await this.m_slotReels.WaitDropOutComplete();

        // 大獎預告（預中演出）
        await this.ShowBigAwardHint( this.SpinAck.RoundQueue[ 0 ] );

        // 設定當局盤面資訊（drop-in 內層再 await 已 resolved 的掉出 promise，無 await-null 競態）
        this.SetNowRoundInfo( this.SpinAck.RoundQueue[ this.CurRoundIndex ] );



        // 如果開啟快停
        if ( this.m_isHardStop )
        {
            if ( this.IsFreeGame )
            {
                this.m_slotReels.ClickStopBtn();
            }
            else
            {
                if ( !this.m_isMgOmen )
                {
                    this.m_slotReels.ClickStopBtn();
                }
            }
            newBottombarManager.SetSpinWithSpeed();
        }
        else
        {
            // 這款天降模式不需要有點擊快停
            // if ( !newBottombarManager.IsAutoSpin )
            // {
            //     newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
            // }
        }
    }

    OnRecvSpinAck_Test( ack, isUnshow = false )
    {
        // 處理從伺服器接收到的轉輪結果
        let info = RecoverSpinAck.getInstance().RecoverFromSpinAck( ack );
        error( "SpinAck after:", info );

        this.SpinAck = info;

        this.m_buyBonus?.CleanInfo();
        if (!isUnshow) {
            this.AccumulatedWin = 0;
        }

        // 判斷是否要進入FG
        if (this.SpinAck.RoundQueue.length > 1) {
            if ( !isUnshow || this.CurRoundIndex === 0 ) {
                const firstRoundInfo = this.SpinAck.RoundQueue[0];
                if (firstRoundInfo.NextFeverGameType === FeverGameType.FreeGame) {
                    this.IsGoingToFree = true;
                }
            }
        }

        // 地Bar按鈕狀態
        if ( newBottombarManager.IsAutoSpin && !this.m_isHardStop )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
        }

        // 設定當局盤面資訊
        this.SetNowRoundInfo( this.SpinAck.RoundQueue[ this.CurRoundIndex ] );



        // 如果開啟快停
        if ( this.m_isHardStop )
        {
            if ( this.IsFreeGame )
            {
                this.m_slotReels.ClickStopBtn();
            }
            else
            {
                if ( !this.m_isMgOmen )
                {
                    this.m_slotReels.ClickStopBtn();
                }
            }
            newBottombarManager.SetSpinWithSpeed();
        }
        else
        {
            if ( !newBottombarManager.IsAutoSpin )
            {
                newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
            }
        }
    }

    /**
     * @ch 設定當局盤面資訊
     * @param round 當局盤面資訊
     */
    SetNowRoundInfo( round: protocol.ar2pq9Proto.IRoundInfo )
    {
        this.m_roundInfo = round;

        // 從 PlateQueue 的第一個元素取得 PlateInfo
        const plateInfo = (this.m_roundInfo && this.m_roundInfo.PlateQueue && this.m_roundInfo.PlateQueue.length > 0)
        ? this.m_roundInfo.PlateQueue[0]
        : null;

        // 新一局 → isNewRound=true，懸賞令整批重建（不延續上一局符號）
        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, plateInfo?.BountyDataVec || [], true);

        this.m_slotReels.SetPlateInfo( plateInfo );
    }
    //endregion 接收資料
    //=============================================================

    //=============================================================
    //#region 事件處理
    /**
     * @ch 事件處理
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        switch ( event )
        {
            case CommonEventName.OpenExtraBet:
            case CommonEventName.TriggerFreeSpin:
                this.m_buyBonus?.SetBuyBtnVisible( false );
                break;

            case CommonEventName.CloseExtraBet:
            case CommonEventName.FreeSpinTotalWinEnd:
                this.m_buyBonus?.SetBuyBtnVisible( true );
                break;
        }
    }
    //#endregion 事件處理
    //=============================================================

    //=============================================================
    //#region 音樂音效
    //音效
    private LoadSound()
    {
        // 載入音效混音設定檔（BGM_SFX.json），讓 AudioManager 套用每個 clip 的 volume / loop / limit
        const loadSettingJson = () =>
        {
            Define.GameBundle.load( "Sound/audio_config", JsonAsset, ( err: Error | null, jsonAsset: JsonAsset ) =>
            {
                if ( err )
                {
                    error( err.message || err );
                    loadSettingJson();
                    return;
                }
                AudioManager.SetSettingJson( jsonAsset );
            } );
        };
        loadSettingJson();

        //音效
        let load = ( path: string, cb: ( clip: AudioClip ) => void ) =>
        {
            Define.GameBundle.load( path, ( err: Error, audioClip: AudioClip ) =>
            {
                if ( err )
                {
                    error( err.message || err );
                    load( path, cb );
                    return;
                }
                cb && cb( audioClip );
            } );
        };

        for ( const key in AudioManager.AudioClips )
        {
            if ( AudioManager.AudioClips.hasOwnProperty( key ) )
            {
                const audioClip = AudioManager.AudioClips[ key ];
                load( AudioManager.AudioFileRoot + audioClip.FileName, ( audioClip: AudioClip ) =>
                {
                    AudioManager.AudioClips[ key ].Clip = audioClip;
                    AudioManager.AddAudioClips([audioClip]);
                } );
            }
        }

        // Wanted_in、Wanted_burn、Wanted_MultiAdd 同時間最多只能播放 1 次（避免多組並行刷新時重疊）
        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_in.FileName, 1 );
        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_burn.FileName, 1 );
        AudioManager.SetConcurrentLimit( AudioManager.AudioClips.Wanted_MultiAdd.FileName, 1 );
    }

    /**
     * @ch 播放主遊戲背景音樂
     */
    PlayMainGameBgm()
    {
        if (this.m_bgmId !== -1)
        {
            AudioManager.Stop(this.m_bgmId);
        }
        this.m_bgmId = AudioManager.PlayBackGround( AudioManager.AudioClips.MG_Bgm, true );
    }

    /**
     * @ch 停止主遊戲背景音樂
     */
    StopMainGameBgm()
    {
        if (this.m_bgmId !== -1)
        {
            AudioManager.Stop(this.m_bgmId);
            this.m_bgmId = -1;
        }
    }

    /**
     * @ch 暫停主遊戲背景音樂
     */
    PauseMainGameBgm()
    {
        if (this.m_bgmId !== -1)
        {
            AudioManager.Pause(this.m_bgmId);
        }
    }

    /**
     * @ch 恢復主遊戲背景音樂
     */
    ResumeMainGameBgm()
    {
        if (this.m_bgmId !== -1)
        {
            AudioManager.Resume(this.m_bgmId);
        }
    }

    /**
     * @ch 播放免費遊戲背景音樂
     */
    PlayFreeGameBgm()
    {
        if (this.m_freeBgmId !== -1)
        {
            AudioManager.Stop(this.m_freeBgmId);
        }
        this.m_freeBgmId = AudioManager.PlayBackGround( AudioManager.AudioClips.FG_Bgm, true );
    }

    /**
     * @ch 停止免費遊戲背景音樂
     */
    StopFreeGameBgm()
    {
        if (this.m_freeBgmId !== -1)
        {
            AudioManager.Stop(this.m_freeBgmId);
            this.m_freeBgmId = -1;
        }
    }

    /**
     * @ch 暫停免費遊戲背景音樂
     */
    PauseFreeGameBgm()
    {
        if (this.m_freeBgmId !== -1)
        {
            AudioManager.Pause(this.m_freeBgmId);
        }
    }

    /**
     * @ch 恢復免費遊戲背景音樂
     */
    ResumeFreeGameBgm()
    {
        if (this.m_freeBgmId !== -1)
        {
            AudioManager.Resume(this.m_freeBgmId);
        }
    }

    /** @ch BGM 淡出（duration 秒） */
    FadeBgmOut(duration: number = 0.5): void {
        if (this.m_bgmId !== -1) AudioManager.SetMusicFadeOut(this.m_bgmId, duration);
        if (this.m_freeBgmId !== -1) AudioManager.SetMusicFadeOut(this.m_freeBgmId, duration);
    }

    /** @ch BGM 淡入（duration 秒） */
    FadeBgmIn(duration: number = 0.5): void {
        if (this.m_bgmId !== -1) AudioManager.SetMusicFadeIn(this.m_bgmId, duration, 1);
        if (this.m_freeBgmId !== -1) AudioManager.SetMusicFadeIn(this.m_freeBgmId, duration, 1);
    }
    //#endregion 音樂音效
    //=============================================================

    //#region Extra Bet    
    /**
     * @ch 初始化Extra Bet
     */
    /**
     * @ch 依 ExtraBet type 切換乘倍底板：套用對應 index 並顯隱（type=0 表關閉 → index 0 + 隱藏）
     * @param type ExtraBet type（0=關閉，1~3=各倍率）
     */
    private SetMultiplierBaseByExtraBetType( type: number ) {
        this.m_curExtraBetType = type;
        const idx = GameView.EXTRA_BET_BASE_INDEX[ type ] ?? 0;
        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER, -1, idx );
        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, type > 0 );
    }

    /**
     * @ch 依目前 ExtraBet type 重新套用乘倍底板（供 SpinState 開轉時維持 ExtraBet 底板，避免被 reset 抹掉）
     */
    public RefreshMultiplierBaseForExtraBet() {
        this.SetMultiplierBaseByExtraBetType( this.m_curExtraBetType );
    }

    private InitExtraBet() {
        this.m_extraBetComp?.Init(
            async (_isActive: boolean, _isForce: boolean) =>
            {
                this.ClearAllForExtraBet();
                if (_isActive && !_isForce) {
                    await this.PlayExtraBetActiveAnimation();
                    // ShowAndWait：Promise.all 在此等待，使 m_ExtraBetAniPlaying=true 直到使用者操作完畢
                    const result = await this.m_extraBetWindow?.ShowAndWait();
                    const confirmed = result?.confirmed ?? false;
                    const type = result?.type ?? 0;
                    // 由 GameView 呼叫 SetTwoStepMulti，確保在 Promise.all 解鎖前完成 bet 切換或復原
                    await this.m_extraBetComp?.SetTwoStepMulti( confirmed, type );
                    // 依選中 type 切換乘倍底板（取消時 type=0，自然切回關閉）
                    this.SetMultiplierBaseByExtraBetType( type );
                    // 取消（未選/×/未選即 Confirm，confirmed=false）時：公版 ChangeBetMode 會在本
                    // callback 結束後無條件 play "ExtraBet_Active" 重新點亮 EX 按鈕（公版 :507 漏判
                    // m_isExtra，不可改公版）。於次幀（晚於公版那行）直接在 EX 節點 Animation 補播
                    // "ExtraBet_OFF" 並跳到結尾，蓋掉那次誤點亮、熄滅 FX 發亮（bar 維持展開不收回）。
                    // 註：公版 OnRotation 播的 "ExtraBet_Stop" 在本專案無對應 .anim，故直接控 Animation。
                    if ( !confirmed ) {
                        this.scheduleOnce( () => {
                            if ( this.a_extraBetAnimation ) {
                                this.a_extraBetAnimation.play( "ExtraBet_OFF" );
                                const state = this.a_extraBetAnimation.getState( "ExtraBet_OFF" );
                                if ( state ) state.setTime( state.duration );
                            }
                        }, 0 );
                    }
                } else if (!_isActive) {
                    // 關閉 ExtraBet → 乘倍底板切回 index 0 並隱藏
                    this.SetMultiplierBaseByExtraBetType( 0 );
                }
            },
            Game_Define.StringKey.EXTRA_BET_DESC,
            Game_Define.StringKey.MG_SPECIAL_TXT,
            true  // isTwoStep：不立即 ChangeMultiBet，等跳窗確認
        );

        // 遊戲啟動時先隱藏，等 info ack 到齊後再透過 ShowExtraBet() 顯示
        this.m_extraBetComp?.ShowExtra( false );
    }

    /**
     * @ch unshow 還原時把 ExtraBet 同步成開啟狀態（m_isExtra / 按鈕 UI / multiBet）
     * @description 透過 framework 的 ForceSetExtraBet 強制設值，搭配 InitExtraBet 中 isForce 分支跳過全版宣告動畫；
     * 依當初押注比值反推 type，避免 ExtraBet 有多種倍率時一律還原成第一種
     */
    public async RestoreExtraBetState() {
        if ( !this.m_showExtra ) return;   // server 未開放 ExtraBet → 不還原

        // (A) 治本：先確保 EX 節點 active。framework ForceSetExtraBet 內部會 await
        // ExtraBet_Close 動畫的 FINISHED 事件，節點 inactive 時該事件永不觸發，會讓
        // 整條 unshow 還原鏈卡死、MSGBOX_UNSHOW_BACK 跳不出來。把「節點需 active」
        // 內聚成本函式自身責任，不再依賴呼叫端的隱藏順序（避免日後改錯順序復發）。
        this.SetExtraBetVisible( true );

        const type = this.GetUnshowExtraBetType();

        // (B) 保底：用 timeout 包住 ForceSetExtraBet。按鈕狀態（m_isExtra/ChangeMultiBet）
        // 在 framework 同步段就已設好，掛住的只是後續動畫視覺，逾時放行在功能上安全，
        // 可擋住所有未預期的 inactive / null / 缺 Animation 情況，不讓流程凍死。
        const EXTRA_BET_FORCE_TIMEOUT_SEC = 2;
        await Promise.race( [
            this.m_extraBetComp?.ForceSetExtraBet( true, type ) ?? Promise.resolve(),
            new Promise<void>( resolve => this.scheduleOnce( resolve, EXTRA_BET_FORCE_TIMEOUT_SEC ) ),
        ] );

        // 強制還原路徑 callback 拿不到 type，在此依還原的 type 補切乘倍底板
        this.SetMultiplierBaseByExtraBetType( type );
    }

    /**
     * @ch 依 unshow 的原始/真實押注比值反推 ExtraBet type（即 Mul 索引）
     * @description Mul[type]/Mul[0] === UnshowRealBet/UnshowBaseBet；用交叉相乘（tools.times）避免浮點誤差。
     * 倍率表不足或對不上時保底回 1（Special），維持還原不中斷
     */
    private GetUnshowExtraBetType(): number {
        const FALLBACK_TYPE = 1;
        const baseBet = commonGameManager.UnshowBaseBet;
        const realBet = commonGameManager.UnshowRealBet;
        const mul = this.m_betMultipliers;

        if ( !mul || mul.length <= 1 || baseBet <= 0 ) {
            error( `[GameView] ExtraBet 還原資料不足 (mul=${mul}, baseBet=${baseBet})，保底用 type=${FALLBACK_TYPE}` );
            return FALLBACK_TYPE;
        }

        const target = tools.times( realBet, mul[ 0 ] );
        for ( let type = 1; type < mul.length; type++ ) {
            if ( tools.times( baseBet, mul[ type ] ) === target ) {
                return type;
            }
        }

        error( `[GameView] ExtraBet 倍率對不上 (baseBet=${baseBet}, realBet=${realBet}, mul=${mul})，保底用 type=${FALLBACK_TYPE}` );
        return FALLBACK_TYPE;
    }

    /**
     * @ch 顯示 Extra Bet 按鈕（info ack 就緒後呼叫）
     */
    private ShowExtraBet() {
        this.SetExtraBetVisible( true );
    }

    /**
     * @ch 設定 Extra Bet 按鈕顯隱（ExtraBet 僅在主遊戲顯示，進免費遊戲時隱藏）
     */
    public SetManualVisible( v: boolean ) {
        if ( v && tools.CheckSwitchOff(SwitchOffKeyDefine.CloseManual) ) return;
        if ( this.m_manual ) this.m_manual.node.active = v;
    }

    public SetExtraBetVisible( v: boolean ) {
        if ( v && !this.m_showExtra ) return;   // server 未開放 ExtraBet → 不顯示（隱藏照常放行）
        this.m_extraBetComp?.ShowExtra( v );
    }

    /**
     * @ch 首次進入 IDLE 時自動展開 Extra Bet Bar 並顯示說明
     */
    async ExtraBetFirstShowBar() {
        if ( !this.m_showExtra ) return;   // server 未開放 ExtraBet → 不展開 Bar
        await this.m_extraBetComp?.FirstShowBar();
    }

    /**
     * @ch 播放Extra Bet啟用動畫
     */
    private async PlayExtraBetActiveAnimation() {

        // });
    }

    /**
     * @ch 清除所有狀態（Extra Bet 專用）
     */
    ClearAllForExtraBet() {
        this.ClearAll();
    }
    //#endregion Extra Bet

    //=============================================================
    //#region Demo    
    /**
     * @ch 根據比例改變盤面
     */
    ChangeDemoPlateByRatio()
    {
        // 初始化陣列
        this.m_realFeatureSpinAck = [];

        try {
            const targetBetIndex = newBottombarManager.FindBetIndexByValue( Game_Define.FeatureBetValue );
            const betList = newBottombarManager.GetBetList();
            const targetBet = betList[targetBetIndex];

            // Free Game
            const freeGameData = this.LoadDemoDataSync(CHEAT_KEY.FREE_GAME);
            RecoverSpinAck.getInstance().ConvertDemoAck(freeGameData, targetBet);
            this.m_realFeatureSpinAck.push(freeGameData);
        } catch (loadError) {
            error("載入測試資料檔案失敗:", loadError);
            // 即使載入失敗，也確保陣列已初始化
            this.m_realFeatureSpinAck = [];
        }
    }

    /**
     * @ch 取得特色玩法測試盤面
     * @param featuresType 特色類型
     * @returns 測試盤面
     */
    GetFeatureSpinAckForDemo(featuresType: number): protocol.ar2pq9Proto.ISpinAck
    {
        if (this.m_realFeatureSpinAck.length === 0 || featuresType < 0 || featuresType >= this.m_realFeatureSpinAck.length)
        {
            return null;
        }
        return this.m_realFeatureSpinAck[featuresType];
    }

    /**
     * @ch 取得特色玩法測試盤面數量
     * @returns 特色玩法測試盤面數量
     */
    GetFeatureSpinAckLengthForDemo(): number
    {
        return this.m_realFeatureSpinAck.length;
    }

    /**
     * @ch 載入測試資料（同步版本）
     * @param fileName 檔案名稱（不含副檔名）
     * @returns BufferAsset 資料
     */
    private LoadBinaryFile(fileName: string): BufferAsset
    {
        return this.m_BinaryFileForDemo.find(file => file.name === fileName);
    }

    CheckBigAwardHint( roundInfo: protocol.ar2pq9Proto.IRoundInfo )
    {
        // 只有一般模式（BetType=0, SpinType=0）才觸發大獎預報
        if ( this.SpinAck.BetType !== 0 || this.SpinAck.SpinType !== 0 )
        {
            return false;
        }

        let win = roundInfo.RoundWin ? roundInfo.RoundWin : 0;
        let bet = newBottombarManager.GetNowBetValue();
        let odds = tools.divide( win, bet ); // 贏分倍率
        let rand = Define.HAS_REPLAY ? 0 : Math.random(); // 機率條件(重播固定機率)

        if ( !this.m_isFreeGame )
        {
            // MG
            if ( roundInfo.RoundWin / bet >= 10 && odds >= 20 && rand < 0.2 )
            {
                return true;
            }
            // Enter FG
            if ( roundInfo.FeverTotalRound > 0 && rand < 0.2 )
            {
                return true;
            }
        }
        else
        {
            // FG
            if ( roundInfo.RoundWin / bet >= 15 && odds >= 50 && rand < 0.3 )
            {
                return true;
            }
        }
        return false;
    }

    /** 大獎預告 */
    async ShowBigAwardHint( roundInfo: protocol.ar2pq9Proto.IRoundInfo )
    {
        let show = this.CheckBigAwardHint( roundInfo );
        if ( show )
        {
            await this.m_effectPlate.PlayBigAwardEffect();
        }
    }

    /**
     * @ch 載入測試資料（同步版本）
     * @param fileName 檔案名稱（不含副檔名）
     * @returns protocol.ar2rhProto.ISpinAck 解碼後的 SpinAck 資料
     */
    private LoadDemoDataSync(triggerKey: number): protocol.ar2pq9Proto.ISpinAck
    {
        let fileName = "pirates_queen_triggerkey_" + triggerKey;

        // 使用同步載入方式
        const asset = this.LoadBinaryFile(fileName);

        if (!asset) {
            error(`載入測試檔案 ${fileName} 失敗: 檔案不存在`);
            throw new Error(`測試檔案 ${fileName} 不存在`);
        }

        try {
            let spinAckData: protocol.ar2pq9Proto.ISpinAck;
            if (asset && asset.validate())
            {
                const uint8Array = new Uint8Array(asset.buffer());
                spinAckData = protocol.ar2pq9Proto.SpinAck.decode(uint8Array);
                return spinAckData;
            }
            else
            {
                error(`載入測試檔案 ${fileName} 失敗: 檔案不存在`);
                throw new Error(`測試檔案 ${fileName} 不存在`);
            }
        } catch (parseError) {
            error(`解析測試檔案 ${fileName} 失敗:`, parseError);
            throw parseError;
        }
    }

    // 震動：上下左右震，大瞄準
    BigHintShake( shakeTime: number, distance: number = Game_Define.BIG_SHAKE_DISTANCE )
    {
        let dt = distance;
        let time = Game_Define.BIG_SHAKE_FREQUENCY;
        // 重複次數
        let repeatTimes = shakeTime / ( time * 5 ) - 1;

        // 連續呼叫：先停舊的歸位，保留第一次的原點
        if ( this.m_bigHintShake )
        {
            this.m_bigHintShake.stop();
            this.m_bigHintShake = null;
            this.node.setPosition( this.m_shakeOriginX, this.m_shakeOriginY );
        }
        else
        {
            // 只有第一次才記錄原點
            this.m_shakeOriginX = this.node.getPosition().x;
            this.m_shakeOriginY = this.node.getPosition().y;
        }

        let x = this.m_shakeOriginX;
        let y = this.m_shakeOriginY;
        this.m_isLockRotation = true;
        this.m_bigHintShake = tween( this.node )
            .repeat( repeatTimes,
                tween()
                    .to( time, { position: v3( x, y + dt ) } )
                    .to( time, { position: v3( x, y - dt ) } )
                    .to( time, { position: v3( x + dt, y ) } )
                    .to( time, { position: v3( x - dt, y ) } )
            )
            .call( () =>
            {
                this.node.setPosition( x, y );
                this.m_bigHintShake = null;
                this.IsLockRotation = false;
            }
            )
            .start();
    }

    /** 清除震動 */
    RemoveBigHintShake()
    {
        if ( this.m_bigHintShake )
        {
            this.m_bigHintShake.stop();
            this.m_bigHintShake = null;
            this.node.setPosition( this.m_shakeOriginX, this.m_shakeOriginY );
            this.IsLockRotation = false;
        }
    }

    //#endregion Demo
    //=============================================================
}

