3	import { director, Director, Component, Node } from 'cc';
4	
5	/**
6	 * AsyncUtils 非同步工具函式庫
7	 * 提供與 Cocos Creator 引擎生命週期整合的非同步操作
8	 * 
9	 * ===== 基本使用範例 =====
10	 * 
11	 * // 1. 等待指定秒數
12	 * await WaitForSeconds(1.5);  // 等待 1.5 秒
13	 * 
14	 * // 2. 等待條件滿足
15	 * let isAnimationFinished = false;
16	 * spine.setCompleteListener(() => isAnimationFinished = true);
17	 * await WaitUntil(() => isAnimationFinished);  // 等待動畫完成
18	 * 
19	 * // 3. 等待指定幀數
20	 * await WaitFrames(30);  // 等待 30 幀（約 0.5 秒 @60fps）
21	 * 
22	 * // 4. 等待下一幀
23	 * await WaitNextFrame();  // 等待下一個渲染幀
24	 * 
25	 * ===== CancelToken 進階使用範例 =====
26	 * 
27	 * // 創建取消控制器
28	 * const cancelToken = CreateCancelToken();
29	 * 
30	 * // 在另一個地方取消操作（使用 Cocos 調度器）
31	 * const scheduler = SchedulerManager.getInstance();
32	 * scheduler.scheduleOnce(() => {
33	 *     cancelToken.isCancelled = true;  // 3 秒後取消
34	 * }, 3);
35	 * 
36	 * // 使用取消控制器
37	 * try {
38	 *     await WaitForSeconds(5, cancelToken);  // 等待 5 秒，但可能被提前取消
39	 *     console.log("正常完成");
40	 * } catch (error) {
41	 *     console.log("被取消了");
42	 * }
43	 * 
44	 * ===== 遊戲場景實際應用範例 =====
45	 * 
46	 * // 範例 1: 等待玩家點擊確認
47	 * class GameState {
48	 *     async WaitForPlayerConfirm(): Promise<void> {
49	 *         let isConfirmed = false;
50	 *         const cancelToken = CreateCancelToken();
51	 *         
52	 *         // 設定 10 秒超時（使用 Cocos 調度器）
53	 *         const scheduler = SchedulerManager.getInstance();
54	 *         scheduler.scheduleOnce(() => cancelToken.isCancelled = true, 10);
55	 *         
56	 *         // 監聽點擊事件
57	 *         this.confirmButton.on('click', () => isConfirmed = true);
58	 *         
59	 *         // 等待確認或超時
60	 *         await WaitUntil(() => isConfirmed, cancelToken);
61	 *     }
62	 * }
63	 * 
64	 * // 範例 2: 免費遊戲結束等待大獎動畫
65	 * class LeaveFreeState {
66	 *     async PlayFreeGameTotalWinAward(): Promise<void> {
67	 *         let isPlayAward = true;
68	 *         const cancelToken = CreateCancelToken();
69	 *         
70	 *         // 播放大獎動畫，完成時設定標誌
71	 *         this.gameView.ShowBigWin(totalWin, winType, () => {
72	 *             isPlayAward = false;
73	 *         });
74	 *         
75	 *         // 等待動畫完成，支援玩家點擊跳過
76	 *         this.skipButton.on('click', () => cancelToken.isCancelled = true);
77	 *         await WaitUntil(() => !isPlayAward, cancelToken);
78	 *     }
79	 * }
80	 * 
81	 * // 範例 3: 轉輪停止序列
82	 * class SpinController {
83	 *     async StopReelsSequentially(): Promise<void> {
84	 *         const cancelToken = CreateCancelToken();
85	 *         
86	 *         // 如果玩家按下快速停止，取消延遲
87	 *         this.quickStopButton.on('click', () => cancelToken.isCancelled = true);
88	 *         
89	 *         for (let i = 0; i < 5; i++) {
90	 *             this.stopReel(i);
91	 *             await WaitForSeconds(0.2, cancelToken);  // 每個轉輪間隔 0.2 秒停止
92	 *         }
93	 *     }
94	 * }
95	 * 
96	 * ===== 注意事項 =====
97	 * 
98	 * 1. 所有函式都使用 Cocos Creator 的調度器系統，與引擎生命週期同步
99	 * 2. CancelToken 是簡單的物件，設定 isCancelled = true 即可取消
100	 * 3. 被取消的 Promise 會立即 resolve，不會拋出例外
101	 * 4. 在場景切換時，調度器會自動清理，避免記憶體洩漏
102	 * 5. 使用 await 語法時，確保函式標記為 async
103	 */
104	
105	export type CancelToken = { isCancelled: boolean };
106	
107	/**
108	 * 內部調度器管理器
109	 * 用於管理 Cocos 調度器的實例
110	 */
111	class SchedulerManager {
112	    private static m_instance: SchedulerManager;
113	    private m_dummyComponent: Component;
114	
115	    private constructor() {
116	        // 創建一個虛擬的 Node 和 Component 用於調度
117	        const dummyNode = new Node('AsyncUtilsScheduler');
118	        this.m_dummyComponent = dummyNode.addComponent(Component);
119	        // 將節點添加到場景中，但設為持久化
120	        director.getScene()?.addChild(dummyNode);
121	        director.addPersistRootNode(dummyNode);
122	    }
123	
124	    public static getInstance(): SchedulerManager {
125	        if (!SchedulerManager.m_instance) {
126	            SchedulerManager.m_instance = new SchedulerManager();
127	        }
128	        return SchedulerManager.m_instance;
129	    }
130	
131	    public scheduleOnce(callback: () => void, delay: number): void {
132	        this.m_dummyComponent.scheduleOnce(callback, delay);
133	    }
134	
135	    public unschedule(callback: () => void): void {
136	        this.m_dummyComponent.unschedule(callback);
137	    }
138	}
139	
140	/**
141	 * 等待指定秒數（非阻塞）
142	 * 使用 Cocos Creator 的調度器系統，與引擎生命週期同步
143	 * @param seconds 秒數（例如 1.5）
144	 * @param cancelToken 可選的取消控制
145	 */
146	export function WaitForSeconds(seconds: number, cancelToken?: CancelToken): Promise<void> {
147	    return new Promise(resolve => {
148	        let isResolved = false;
149	        const scheduler = SchedulerManager.getInstance();
150	        
151	        // 創建延遲回調函數
152	        const delayCallback = () => {
153	            if (!cancelToken?.isCancelled && !isResolved) {
154	                isResolved = true;
155	                resolve();
156	            }
157	        };
158	        
159	        // 使用 Cocos 調度器
160	        scheduler.scheduleOnce(delayCallback, seconds);
161	        
162	        // 如果有取消控制，使用 frame 檢查
163	        if (cancelToken) {
164	            const cancelCheck = () => {
165	                if (cancelToken.isCancelled) {
166	                    if (!isResolved) {
167	                        scheduler.unschedule(delayCallback);
168	                        isResolved = true;
169	                        resolve();
170	                    }
171	                } else if (!isResolved) {
172	                    // 使用 director 的下一幀事件繼續檢查
173	                    director.once(Director.EVENT_AFTER_UPDATE, cancelCheck);
174	                }
175	            };
176	            cancelCheck();
177	        }
178	    });
179	}
180	
181	/**
182	 * 每 frame 檢查條件直到為 true 為止
183	 * @param condition 條件函式
184	 * @param cancelToken 可選的取消控制
185	 */
186	export function WaitUntil(condition: () => boolean, cancelToken?: CancelToken): Promise<void> {
187	    return new Promise(resolve => {
188	        function check() {
189	            if (cancelToken?.isCancelled) { resolve(); return; }
190	            if (condition()) {
191	                resolve();
192	            } else {
193	                director.once(Director.EVENT_AFTER_UPDATE, check);
194	            }
195	        }
196	        check();
197	    });
198	}
199	
200	/**
201	 * 每 frame 檢查條件直到為 false 為止
202	 */
203	export function WaitWhile(condition: () => boolean, cancelToken?: CancelToken): Promise<void> {
204	    return WaitUntil(() => !condition(), cancelToken);
205	}
206	
207	/**
208	 * 等待下一個 frame
209	 */
210	export function WaitNextFrame(cancelToken?: CancelToken): Promise<void> {
211	    return new Promise(resolve => {
212	        if (cancelToken?.isCancelled) { resolve(); return; }
213	        director.once(Director.EVENT_AFTER_UPDATE, () => {
214	            if (cancelToken?.isCancelled) { resolve(); return; }
215	            resolve();
216	        });
217	    });
218	}
219	
220	/**
221	 * 等待指定 frame 數
222	 */
223	export function WaitFrames(frameCount: number, cancelToken?: CancelToken): Promise<void> {
224	    return new Promise(resolve => {
225	        let count = 0;
226	        function next() {
227	            if (cancelToken?.isCancelled) { resolve(); return; }
228	            count++;
229	            if (count >= frameCount) {
230	                resolve();
231	            } else {
232	                director.once(Director.EVENT_AFTER_UPDATE, next);
233	            }
234	        }
235	        next();
236	    });
237	}
238	
239	/**
240	 * 建立取消控制器
241	 */
242	export function CreateCancelToken(): CancelToken {
243	    return { isCancelled: false };
244	}
