1	import { error, log } from "cc";
2	import { BaseState, eventManager, msgBoxManager, newBottombarManager, SlotBottomBarState } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define, { FeaturePosQueueType } from "../Game_Define";
5	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
6	// import protocol from "../Test/ar2pq9Proto.js";
7	import { REEL_UI_MANAGER_EVENT } from "../Reel/ReelManager";
8	import { AudioManager } from "../Audio/AudioManager";
9	import { Define } from "db://astarte-framework/utilis";
10	import { tools } from "db://astarte-framework/utilis";
11	import { RT_EVENT } from "../RTCtrl";
12	
13	export class AwardState extends BaseState
14	{
15	    private m_gameView: GameView = null;
16	    private m_processTick: number = 0;
17	    
18	    /**
19	     * @ch 現在盤面資訊
20	     */
21	    private m_currentPlateInfo: protocol.ar2pq9Proto.IPlateInfo = null;
22	
23	    constructor( gameView: GameView )
24	    {
25	        super();
26	        this.m_gameView = gameView;
27	    }
28	
29	    public OnEnter()
30	    {
31	
32	        log( "OnEnter State : AWARD" );
33	        this.m_processTick = 0;
34	        
35	
36	        const spinAck = this.m_gameView.SpinAck;
37	        const winValue = spinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].RoundWin;
38	        const totalWin = spinAck.TotalWin;
39	
40	        /**@ch 設定盤面符號不暗 */
41	        this.m_gameView.SlotReels.SetSymbolDark( false, -1 );
42	
43	        if ( winValue > 0 && !this.m_gameView.IsGoingToFree )
44	        {
45	            this.ProcessFinalAward( winValue,totalWin, false );
46	        }
47	    }
48	
49	    public OnProcess( dt: number )
50	    {
51	        if ( this.m_processTick > 0 )
52	        {
53	            this.m_processTick -= dt;
54	            if ( this.m_processTick > 0 ) return;
55	        }
56	        if ( this.m_gameView.BigWin.IsEnd )
57	        {
58	            this.m_gameView.BigWin.node.active = false;
59	            this.m_gameView.FadeBgmIn();
60	            // RT 解鎖：BigWin 演出結束
61	            eventManager.Dispatch(RT_EVENT.AWARD_OUT_RT);
62	            this.m_gameView.AfterShowWin();
63	        }
64	    }
65	
66	    public OnLeave()
67	    {
68	        this.m_currentPlateInfo = null;
69	        this.m_gameView.CanStopBigWin = false;
70	    }
71	
72	    
73	
74	    /**
75	     * @ch 處理最後報獎
76	     * @param totalWin 總贏分
77	     * @param isNotShowNormalWin 是否不顯示NormalWin
78	     */
79	    private ProcessFinalAward(winValue: number, totalWin: number, isNotShowNormalWin: boolean) : void {
80	
81	        const bet: number = Game_Define.GetNowBetValue();
82	        const rate = winValue / bet;
83	
84	        if ( winValue <= 0 ) return;
85	
86	        // 小獎（倍率 < BigWin 門檻）
87	        if ( rate < Game_Define.BigWinWinRule.BIG_WIN_MIN )
88	        {
89	            if ( isNotShowNormalWin ) return;
90	
91	            // 小獎音效
92	            if (rate < 3) {
93	                AudioManager.Play(AudioManager.AudioClips.Small_Win01);
94	            } else if (rate < 5) {
95	                AudioManager.Play(AudioManager.AudioClips.Small_Win02);
96	            } else {
97	                AudioManager.Play(AudioManager.AudioClips.Small_Win03);
98	            }
99	            this.m_gameView.ShowSmallWinLabel( winValue, Game_Define.SMALLWIN_TIME );
100	            this.m_processTick = Game_Define.SMALLWIN_TIME;
101	            
102	        }
103	        // 大獎
104	        else
105	        {
106	            // RT 鎖旋轉：BigWin 演出一開始就鎖
107	            eventManager.Dispatch(RT_EVENT.AWARD_IN_RT);
108	
109	            this.m_gameView.SetManualVisible( false );
110	            let lvl = 0;
111	            // SUPER >= 50x, MEGA >= 25x, BIG >= 10x
112	            if ( rate >= Game_Define.BigWinWinRule.SUPER_WIN_MIN )
113	            {
114	                lvl = 3; // SUPER
115	            }
116	            else if ( rate >= Game_Define.BigWinWinRule.MEGA_WIN_MIN )
117	            {
118	                lvl = 2; // MEGA
119	            }
120	            else
121	            {
122	                lvl = 1; // BIG
123	            }
124	
125	            this.m_gameView.ShowBigWin( winValue, lvl );
126	            this.m_gameView.FadeBgmOut();
127	
128	            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );
129	
130	            // 0.5s 延遲保護：防止玩家太快跳過看不到動畫
131	            this.m_gameView.CanStopBigWin = false;
132	            Define.Wait( this.m_gameView, 0.5 ).then( () =>
133	            {
134	                this.m_gameView.CanStopBigWin = true;
135	                if ( newBottombarManager.IsAutoSpin )
136	                {
137	                    newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
138	                }
139	                else
140	                {
141	                    newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
142	                }
143	            } );
144	        }
145	        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_gameView.AccumulatedWin + this.m_gameView.RoundWin } );
146	    }
147	
148	    
149	
150	    /**@ch 取得Scatter中獎位置
151	     * @returns Scatter中獎位置
152	     */
153	    private GetScatterPositions(): number[] {
154	        let scatterPositions: number[] = [];
155	       
156	        if (this.m_currentPlateInfo.FeaturePosQueue.length > 0) {
157	            const featurePosQueue = this.m_currentPlateInfo.FeaturePosQueue[FeaturePosQueueType.Scatter];
158	            for (let position of featurePosQueue.Data) {
159	                scatterPositions.push(position);
160	            }
161	        }
162	        return scatterPositions;
163	    }
164	
165	    
166	
167	    /**
168	     * @ch 設定Reel黑幕顯示
169	     * @param isShow 是否顯示
