1	import { Label, log, UITransform, Vec3 } from "cc";
2	import { BaseState, newBottombarManager, stateManager } from "db://astarte-framework/Managers";
3	import GameView from "../GameView";
4	import Game_Define from "../Game_Define";
5	import { eventManager } from "db://astarte-framework/Managers";
6	import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
7	import { Define, tools } from "db://astarte-framework/utilis";
8	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
9	import { AudioManager } from "../Audio/AudioManager";
10	import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CANNON_ANIM_NAME, CHARACTER_ANIM_NAME } from "../BSSpineCtrl";
11	
12	export class CountMultState extends BaseState
13	{
14	    private m_gameView: GameView = null;
15	
16	    /** @ch GC 優化：類別層級復用，避免每盤 new Map */
17	    private _posOwnerMap: Map<number, number> = new Map();
18	
19	    constructor( gameView: GameView )
20	    {
21	        super();
22	        this.m_gameView = gameView;
23	    }
24	
25	    public async OnEnter()
26	    {
27	
28	        log( "OnEnter State : COUNT_MULT" );
29	        let plateInfoData = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].PlateQueue;
30	        let plateIdx = this.m_gameView.CurPlateIndex;
31	        if(plateIdx < plateInfoData.length )
32	        {
33	            let awardDataVec = plateInfoData[ plateIdx ].AwardDataVec ? plateInfoData[ plateIdx ].AwardDataVec : [];
34	
35	            let explodeDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
36	            let targetDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
37	            //加入標靶消除範圍
38	            if(plateInfoData[plateIdx].TargetDataVec.length > 0)
39	            {
40	                for(let i = 0; i < plateInfoData[plateIdx].TargetDataVec.length; i++)
41	                {
42	                    let eliminatePos: number[] = [];
43	                    for(let pos of plateInfoData[plateIdx].TargetDataVec[i].EliminatePos)
44	                    {
45	                        eliminatePos.push(pos);
46	                    }
47	
48	                    //標靶消除範圍
49	                    explodeDataVec.push( {
50	                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
51	                        EliminatePos: eliminatePos
52	                    } );
53	
54	                    //標靶演出用
55	                    targetDataVec.push( {
56	                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
57	                        EliminatePos: [plateInfoData[plateIdx].TargetDataVec[i].Pos]
58	                    } );
59	                }
60	            }
61	
62	            for ( let i = 0; i < awardDataVec.length; i++ )
63	            {
64	                if(awardDataVec[i].EliminatePos.length > 0)
65	                {
66	                    explodeDataVec.push( awardDataVec[ i ] );
67	                    
68	                }
69	            }
70	            this.m_gameView.CurExplodeDataVec = explodeDataVec;
71	
72	       
73	
74	            // 計算乘倍
75	            this.m_gameView.PendingAwardResults = [];
76	            this.m_gameView.PendingMultiplierPushPositions = [];
77	
78	            // Combo 音效
79	            if (awardDataVec.length > 0) {
80	                const comboCount = Math.min(plateIdx + 1, 5);
81	                const suffix = this.m_gameView.IsFreeGame ? '_F' : '';
82	                AudioManager.Play(AudioManager.AudioClips[`Combo_0${comboCount}${suffix}`]);
83	            }
84	
85	            // ── 所有 award 的 Win 動畫一次同步播完 ──
86	            if (awardDataVec.length > 0) {
87	                const hasAnyMult = awardDataVec.some(a => a.Multiple > 1);
88	
89	                // 砲台動畫：SymbolWinEffect 結束前 ~0.5 秒觸發（Win 動畫約 1s，提前 0.5s 播砲台）
90	                // 有乘倍時砲台改在 UpdateStaticAndFlyUp 開始時觸發（乘倍結束前 ~0.4s）
91	                const cannonDelay = this.m_gameView.IsHardStop ? 0.25 : 0.5;
92	                if (!hasAnyMult) {
93	                    this.m_gameView.scheduleOnce(() => {
94	                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER,
95	                            CHARACTER_ANIM_NAME.Symbol_Remove, false, () => {});
96	                        const cannonDelay2 = this.m_gameView.IsLandscape ? 0 : 0.5;
97	                        this.m_gameView.scheduleOnce(() => {
98	                            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON,
99	                                CANNON_ANIM_NAME.Symbol_Remove, false, () => {});
100	                        }, cannonDelay2);
101	                    }, cannonDelay);
102	                }
103	
104	                // FG 中有加局時，symbol win 演出前先隱藏 scatter 和標靶 effect（顯示靜態章）
105	                if (this.m_gameView.IsFreeGame &&
106	                    this.m_gameView.RoundInfo.FeverTotalRound > this.m_gameView.FreeTotalRound) {
107	                    this.m_gameView.EffectPlate.SetScatterSpinesVisible(false);
108	                    this.m_gameView.EffectPlate.SetTargetSpinesVisible(false);
109	                    this.m_gameView.SlotReels.RestoreHiddenScatterSymbols();
110	                }
111	
112	                await this.m_gameView.EffectPlate.SymbolWinEffect(awardDataVec, hasAnyMult);
113	
114	
115	                // ── 各 award 乘倍流程（並行） ──
116	                let promises: Promise<void>[] = [];
117	                let cannonFired = !hasAnyMult; // 無乘倍時已由 scheduleOnce 處理
118	                // Wild 去重：同一個 pos 可能出現在多個 award 的 EliminatePos（Wild 格共用），
119	                // 只有「第一個遇到該 pos 的 award」才真正 POP+FLY，其他直接 resolve，
120	                // 防止並行 tween 互相 stopAllByTarget 導致 callback 永不觸發。
121	                const posOwnerMap = this._posOwnerMap;
122	                posOwnerMap.clear(); // GC 優化：復用 Map 而非每盤 new
123	                for (let i = 0; i < awardDataVec.length; i++) {
124	                    if (awardDataVec[i].Multiple > 1) {
125	                        for (const pos of awardDataVec[i].EliminatePos) {
126	                            if (!posOwnerMap.has(pos)) {
127	                                posOwnerMap.set(pos, i);
128	                            }
129	                        }
130	                    }
131	                }
132	                for ( let i = 0; i < awardDataVec.length; i++ )
133	                {
134	                    let col = Math.floor(awardDataVec[i].EliminatePos[0] / Game_Define.ROW);
135	                    let isLeft = col < Game_Define.COL / 2;
136	                    let pos0 = awardDataVec[i].EliminatePos[0];
137	
138	                    if (awardDataVec[i].Multiple > 1) {
139	                        promises.push((async () => {
140	
141	                            // 1. 顯示 ODD*Bet
142	                            let bet = Game_Define.GetNowBetValue();
