import { Label, log, UITransform, Vec3 } from "cc";
import { BaseState, newBottombarManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { eventManager } from "db://astarte-framework/Managers";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
import { Define, tools } from "db://astarte-framework/utilis";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { AudioManager } from "../Audio/AudioManager";
import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CANNON_ANIM_NAME, CHARACTER_ANIM_NAME } from "../BSSpineCtrl";

export class CountMultState extends BaseState
{
    private m_gameView: GameView = null;

    /** @ch GC 優化：類別層級復用，避免每盤 new Map */
    private _posOwnerMap: Map<number, number> = new Map();

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : COUNT_MULT" );
        let plateInfoData = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].PlateQueue;
        let plateIdx = this.m_gameView.CurPlateIndex;
        if(plateIdx < plateInfoData.length )
        {
            let awardDataVec = plateInfoData[ plateIdx ].AwardDataVec ? plateInfoData[ plateIdx ].AwardDataVec : [];

            let explodeDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
            let targetDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
            //加入標靶消除範圍
            if(plateInfoData[plateIdx].TargetDataVec.length > 0)
            {
                for(let i = 0; i < plateInfoData[plateIdx].TargetDataVec.length; i++)
                {
                    let eliminatePos: number[] = [];
                    for(let pos of plateInfoData[plateIdx].TargetDataVec[i].EliminatePos)
                    {
                        eliminatePos.push(pos);
                    }

                    //標靶消除範圍
                    explodeDataVec.push( {
                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
                        EliminatePos: eliminatePos
                    } );

                    //標靶演出用
                    targetDataVec.push( {
                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
                        EliminatePos: [plateInfoData[plateIdx].TargetDataVec[i].Pos]
                    } );
                }
            }

            for ( let i = 0; i < awardDataVec.length; i++ )
            {
                if(awardDataVec[i].EliminatePos.length > 0)
                {
                    explodeDataVec.push( awardDataVec[ i ] );

                }
            }
            this.m_gameView.CurExplodeDataVec = explodeDataVec;



            // 計算乘倍
            this.m_gameView.PendingAwardResults = [];
            this.m_gameView.PendingMultiplierPushPositions = [];

            // Combo 音效
            if (awardDataVec.length > 0) {
                const comboCount = Math.min(plateIdx + 1, 5);
                const suffix = this.m_gameView.IsFreeGame ? '_F' : '';
                AudioManager.Play(AudioManager.AudioClips[`Combo_0${comboCount}${suffix}`]);
            }

            // ── 所有 award 的 Win 動畫一次同步播完 ──
            if (awardDataVec.length > 0) {
                const hasAnyMult = awardDataVec.some(a => a.Multiple > 1);

                // 砲台動畫：SymbolWinEffect 結束前 ~0.5 秒觸發（Win 動畫約 1s，提前 0.5s 播砲台）
                // 有乘倍時砲台改在 UpdateStaticAndFlyUp 開始時觸發（乘倍結束前 ~0.4s）
                const cannonDelay = this.m_gameView.IsHardStop ? 0.25 : 0.5;
                if (!hasAnyMult) {
                    this.m_gameView.scheduleOnce(() => {
                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER,
                            CHARACTER_ANIM_NAME.Symbol_Remove, false, () => {});
                        const cannonDelay2 = this.m_gameView.IsLandscape ? 0 : 0.5;
                        this.m_gameView.scheduleOnce(() => {
                            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON,
                                CANNON_ANIM_NAME.Symbol_Remove, false, () => {});
                        }, cannonDelay2);
                    }, cannonDelay);
                }

                // FG 中有加局時，symbol win 演出前先隱藏 scatter 和標靶 effect（顯示靜態章）
                if (this.m_gameView.IsFreeGame &&
                    this.m_gameView.RoundInfo.FeverTotalRound > this.m_gameView.FreeTotalRound) {
                    this.m_gameView.EffectPlate.SetScatterSpinesVisible(false);
                    this.m_gameView.EffectPlate.SetTargetSpinesVisible(false);
                    this.m_gameView.SlotReels.RestoreHiddenScatterSymbols();
                }

                await this.m_gameView.EffectPlate.SymbolWinEffect(awardDataVec, hasAnyMult);


                // ── 各 award 乘倍流程（並行） ──
                let promises: Promise<void>[] = [];
                let cannonFired = !hasAnyMult; // 無乘倍時已由 scheduleOnce 處理
                // Wild 去重：同一個 pos 可能出現在多個 award 的 EliminatePos（Wild 格共用），
                // 只有「第一個遇到該 pos 的 award」才真正 POP+FLY，其他直接 resolve，
                // 防止並行 tween 互相 stopAllByTarget 導致 callback 永不觸發。
                const posOwnerMap = this._posOwnerMap;
                posOwnerMap.clear(); // GC 優化：復用 Map 而非每盤 new
                for (let i = 0; i < awardDataVec.length; i++) {
                    if (awardDataVec[i].Multiple > 1) {
                        for (const pos of awardDataVec[i].EliminatePos) {
                            if (!posOwnerMap.has(pos)) {
                                posOwnerMap.set(pos, i);
                            }
                        }
                    }
                }
                for ( let i = 0; i < awardDataVec.length; i++ )
                {
                    let col = Math.floor(awardDataVec[i].EliminatePos[0] / Game_Define.ROW);
                    let isLeft = col < Game_Define.COL / 2;
                    let pos0 = awardDataVec[i].EliminatePos[0];

                    if (awardDataVec[i].Multiple > 1) {
                        promises.push((async () => {

                            // 1. 顯示 ODD*Bet
                            let bet = Game_Define.GetNowBetValue();
                            let oddsValue = tools.times(awardDataVec[i].Odds, bet);
                            let oddsNode = await this.m_gameView.EffectPlate.ShowStaticOdds(pos0, oddsValue.toString(), isLeft);

                            // 2. 乘倍飛入
                            const oddsLabel = oddsNode.getComponentInChildren(Label);
                            let targetPos = oddsNode.getWorldPosition();
                            if (oddsLabel) {
                                oddsLabel.updateRenderData(true);
                                const halfW = oddsLabel.node.getComponent(UITransform).contentSize.width / 2;
                                targetPos = oddsLabel.node.getWorldPosition();
                                targetPos.x += halfW + 30;
                            }
                            const flyPromises: Promise<void>[] = [];
                            const flyingPositions: number[] = [];
                            for (let pos of awardDataVec[i].EliminatePos) {
                                this.m_gameView.PendingMultiplierPushPositions.push(pos);
                                // Wild 格去重：此 pos 歸屬另一個 award，跳過飛行
                                if (posOwnerMap.get(pos) !== i) {
                                    continue;
                                }
                                flyingPositions.push(pos);
                                flyPromises.push(new Promise<void>((resolve) => {
                                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM, pos,
                                        this.m_gameView.EffectPlate.GetEffctNode(Game_Define.LAYERS.MULTI_FLY));
                                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET, pos,
                                        targetPos, 0.5, () => {});
                                    // 統一等飛行時間到才 resolve（不靠 callback）
                                    this.m_gameView.scheduleOnce(() => resolve(), 0.4);
                                }));
                            }
                            // 砲台動畫：飛行開始 0.2s 後觸發
                            if (!cannonFired && flyPromises.length > 0) {
                                cannonFired = true;
                                this.m_gameView.scheduleOnce(() => {
                                    eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER,
                                        CHARACTER_ANIM_NAME.Symbol_Remove, false, () => {});
                                    const cannonDelay2 = this.m_gameView.IsLandscape ? 0 : 0.5;
                                    this.m_gameView.scheduleOnce(() => {
                                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON,
                                            CANNON_ANIM_NAME.Symbol_Remove, false, () => {});
                                    }, cannonDelay2);
                                }, 0.2);
                            }
                            // 第一個到達就繼續，其餘歸位隱藏
                            if (flyPromises.length > 0) {
                                await Promise.race(flyPromises);
                            }
                            for (const p of flyingPositions) {
                                eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.PUSH_MULITEM, p);
                            }

                            // 4. 更新文字往上飛
                            let formula = oddsValue.toString() + "X" + awardDataVec[i].Multiple.toString();
                            let resultValue = tools.times(oddsValue, awardDataVec[i].Multiple);
                            AudioManager.Play(AudioManager.AudioClips.Multiplier_add);
                            await this.m_gameView.EffectPlate.UpdateStaticAndFlyUp(oddsNode, formula, isLeft, resultValue.toString(), resultValue, bet);

                        })());
                    }

                    // 暫存結果（EXPLODE 時顯示）— 有乘倍的 award 已在算式中顯示結果，不重複播
                    let bet = Game_Define.GetNowBetValue();
                    let winValue = awardDataVec[i].Win || tools.times(awardDataVec[i].Odds || 0, bet);
                    let winDisplay = winValue.toString();
                    if (!(awardDataVec[i].Multiple > 1)) {
                        this.m_gameView.EffectPlate.AddPendingResult(pos0, winDisplay, isLeft);
                    }
                    this.m_gameView.PendingAwardResults.push({
                        pos: pos0,
                        win: winValue,
                        fullResult: winDisplay,
                        isLeft: isLeft
                    });
                }

                await Promise.all(promises);


                // 統一清除贏分特效節點並解暗
                this.m_gameView.EffectPlate.CleanPendingWinEffectNodes();
                this.m_gameView.EffectPlate.SetReelBlackMaskShow(false);
                this.m_gameView.EffectPlate.RebuildScatterSpines();

            }

            //標靶演出
            if(targetDataVec.length > 0)
            {
                await Define.Wait( this.m_gameView, 0.5 );
                // 標靶演出開始 0.5s 後播砲台動畫（非阻塞）
                this.m_gameView.scheduleOnce(() => {
                    eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
                        CHARACTER_ANIM_NAME.Symbol_Remove, false, () => {});
                    const cannonDelay2 = this.m_gameView.IsLandscape ? 0 : 0.1;
                    this.m_gameView.scheduleOnce(() => {
                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 
                            CANNON_ANIM_NAME.Symbol_Remove, false, () => {});
                    }, cannonDelay2);
                }, 1.0);
                const isExpanded = this.m_gameView.IsFreeGame && this.m_gameView.FreePickItems.indexOf(0) >= 0;
                await this.m_gameView.EffectPlate.PlayTargetExplodeEffect(
                    plateInfoData[plateIdx].TargetDataVec, isExpanded);

            }






            stateManager.NextState( Game_Define.GameState.EXPLODE );
        }
        else
        {
            stateManager.NextState( Game_Define.GameState.EFFECT_START );
        }


    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }
}

