13	
14	// ─────────────────────────────────────────────
15	//  事件定義
16	// ─────────────────────────────────────────────
17	export const FG_ROULETTE_MANAGER_EVENT = {
18	    /**
19	     * @ch 開啟轉盤畫面，並儲存指針數量與各指針的獲獎結果（不立即旋轉）
