35	     * @param spinResults FGRouletteOption[] — 本次各指針的獲獎結果（與 OPEN 傳入的相同）
36	     */
37	    SPIN_FINISH: 'FG_ROULETTE_MANAGER_SPIN_FINISH',
38	
39	    /**@ch 轉盤開始旋轉時廣播*/
40	    SPIN_START: 'FG_ROULETTE_MANAGER_SPIN_START',
41	
42	    /**@ch 僅顯示指針（不旋轉）*/
43	    SHOW_POINTER: 'FG_ROULETTE_MANAGER_SHOW_POINTER',
44	
45	    /**@ch 顯示黑章遮罩（淡入）*/
46	    SHOW_BLACK_MASK: 'FG_ROULETTE_MANAGER_SHOW_BLACK_MASK',
47	
48	    /**@ch 隱藏黑章遮罩（淡出）*/
49	    HIDE_BLACK_MASK: 'FG_ROULETTE_MANAGER_HIDE_BLACK_MASK',
50	
51	    /**@ch 不旋轉直接走完 OnAllSpinsFinish 清理（三特色全拿用）*/
52	    FINISH_WITHOUT_SPIN: 'FG_ROULETTE_MANAGER_FINISH_WITHOUT_SPIN',
53	
54	    /**@ch 鎖住 Spin 按鈕（三特色全拿用，防止玩家手動觸發旋轉）*/
