56	
57	    /**@ch 設定 RouletteSpine 的 Rudder event listener（進場結束後呼叫）*/
58	    SETUP_SPINE_LISTENER: 'FG_ROULETTE_MANAGER_SETUP_SPINE_LISTENER',
59	};
60	
61	// ─────────────────────────────────────────────
62	//  FG 轉盤強化選項
63	// ─────────────────────────────────────────────
64	/** FG 轉盤的 3 種強化選項 */
65	export enum FGRouletteOption {
66	    /** 標靶符號強化：3X3 的範圍提升至 5X5 */
67	    TargetExpand = 0,
68	    /** 懸賞令強化：FG 中會出現兩張懸賞令，效果可疊加 */
69	    BountyDouble = 1,
70	    /** SCATTER 符號強化：FG 中轉出的 SCATTER 符號，加 1 局提升為加 2 局 */
71	    ScatterBoost = 2,
72	}
73	
74	// ─────────────────────────────────────────────
75	//  主元件
76	// ─────────────────────────────────────────────
77	/**
78	 * FG 入場轉盤管理元件
79	 * - 固定 3 個區塊：標靶符號強化 / 懸賞令強化 / SCATTER 符號強化
80	 * - 繼承 RouletteRotate，直接沿用旋轉邏輯
81	 * - 每次 OPEN 只旋轉一次；多個指針同時停下，由外部 UI 呈現各指針位置
82	 * - 透過 eventManager 接收指令 / 廣播結果
83	 * - 內建 Spin 按鈕管理，點擊後觸發旋轉，旋轉期間禁用按鈕
84	 *
85	 * 指針數量對照（SCATTER 數量由外部決定，隨 OPEN 事件傳入）：
86	 *   SCATTER 3  → pointerCount = 1
87	 *   SCATTER 4  → pointerCount = 2
88	 *   SCATTER 5+ → pointerCount = 3
89	 */
90	@ccclass('FGRouletteManager')
91	export class FGRouletteManager extends RouletteRotate {
92	
93	    //#region Constants
94	    private static readonly SLOT_COUNT = 3;
95	    /** @ch 每次停輪後高亮展示時間（秒） */
96	    private static readonly DELAY_HIGHLIGHT = 1.5;
97	    /** @ch 多指針間的間隔時間（秒） */
98	    private static readonly DELAY_BETWEEN_SPINS = 1.0;
99	    /** @ch 自動開始旋轉的等待時間（秒） */
