183	    /**
184	     * @ch 事件處理（由 eventManager 呼叫）
185	     * @param event 事件名稱
186	     * @param args  事件參數
187	     */
188	    OnEvent(event: string, ...args: any[]): void {
189	        switch (event) {
190	            case FG_ROULETTE_MANAGER_EVENT.OPEN: {
191	                if (!this.ValidateOpenArgs(args)) {
192	                    error('[FGRouletteManager] OPEN event requires parameters: (pointerCount: number, spinResults: FGRouletteOption[], callback?: () => void)');
193	                    return;
194	                }
195	                const pointerCount = args[0] as number;
196	                const spinResults  = args[1] as FGRouletteOption[];
197	                const callback     = typeof args[2] === 'function' ? args[2] as () => void : null;
198	                this.Open(pointerCount, spinResults, callback);
199	                break;
200	            }
201	
202	            case FG_ROULETTE_MANAGER_EVENT.SHOW_UPGRADES: {
203	                const results = args[0] as FGRouletteOption[];
204	                const cb = typeof args[1] === 'function' ? args[1] as () => void : null;
205	                this.ShowUpgradesOnly(results, cb);
206	                break;
207	            }
208	
209	            case FG_ROULETTE_MANAGER_EVENT.SHOW_POINTER: {
210	                const count = args[0] as number;
211	                this.SetPointerByCount(count);
212	                break;
213	            }
214	
215	            case FG_ROULETTE_MANAGER_EVENT.SHOW_BLACK_MASK: {
216	                if (this.m_blackMaskNode) {
217	                    this.m_blackMaskNode.active = true;
218	                    if (this.m_blackMaskAnim && this.m_blackMaskInClip) this.m_blackMaskAnim.play(this.m_blackMaskInClip.name);
219	                }
220	                if (Common.GetGameView().IsLandscape && this.m_cannonNode_H && this.m_cannonParentUnderMask) {
221	                    this.m_cannonOriginalParent = this.m_cannonNode_H.parent;
222	                    this.m_cannonNode_H.setParent(this.m_cannonParentUnderMask, true);
223	                }
224	                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK);
225	                break;
226	            }
227	
228	            case FG_ROULETTE_MANAGER_EVENT.HIDE_BLACK_MASK: {
229	                if (Common.GetGameView().IsLandscape && this.m_cannonNode_H && this.m_cannonOriginalParent) {
230	                    this.m_cannonNode_H.setParent(this.m_cannonOriginalParent, true);
231	                    this.m_cannonOriginalParent = null;
232	                }
233	                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK);
234	                this.PlayFeatureIconOut();
235	                if (this.m_blackMaskNode) {
236	                    if (this.m_blackMaskAnim && this.m_blackMaskOutClip) {
237	                        this.m_blackMaskAnim.play(this.m_blackMaskOutClip.name);
238	                        this.m_blackMaskAnim.once(Animation.EventType.FINISHED, () => { this.m_blackMaskNode.active = false; });
239	                    } else {
240	                        this.m_blackMaskNode.active = false;
241	                    }
242	                }
243	                break;
244	            }
245	
246	            case FG_ROULETTE_MANAGER_EVENT.FINISH_WITHOUT_SPIN: {
247	                // 3 feature 全拿不走 OPEN，需在此設 spinResults
248	                if (args.length > 0 && Array.isArray(args[0])) {
249	                    this.m_spinResults = [...args[0]];
250	                }
251	                this.PlayFeatureIconBingo();
252	                this.OnAllSpinsFinish();
253	                break;
254	            }
255	
256	            case FG_ROULETTE_MANAGER_EVENT.LOCK_SPIN: {
257	                this.SetButtonInteractable(false);
258	                this.unscheduleAllCallbacks();
259	                break;
260	            }
261	
262	            case FG_ROULETTE_MANAGER_EVENT.SETUP_SPINE_LISTENER: {
263	                this.AttachRouletteSpineListener();
264	                break;
265	            }
266	
267	            default:
268	                warn(`[FGRouletteManager] OnEvent: 未知的事件 ${event}`);
269	        }
270	    }
