272	    /**
273	     * @ch 掛上轉盤 Spine 的持久 event listener（監聽 Rudder 事件）
274	     * SETUP_SPINE_LISTENER 事件與 OnClickSpinButton 共用，復用同一個 listener 實例
275	     */
276	    private m_rouletteSpineListener: (entry: sp.spine.TrackEntry, event: sp.spine.Event) => void = null;
277	
278	    private AttachRouletteSpineListener(): void {
279	        const rouletteSpine = Common.GetGameView().RouletteSpine;
280	        if (!rouletteSpine) {
281	            return;
282	        }
283	        if (!this.m_rouletteSpineListener) {
284	            this.m_rouletteSpineListener = (entry: sp.spine.TrackEntry, event: sp.spine.Event) => {
285	                this.OnRouletteSpineEvent(event.data.name);
286	            };
287	        }
288	        rouletteSpine.setEventListener(this.m_rouletteSpineListener);
289	    }
290	
291	    private RegisterEvent(): void {
292	        if (this.m_isEventRegistered) {
293	            return;
294	        }
295	
296	        FGRouletteManager.EVENTS_TO_REGISTER.forEach(eventName => {
297	            eventManager.Register(eventName, this);
298	        });
299	
300	        if (this.m_spinButton?.node) {
301	            this.m_spinButton.node.on(Button.EventType.CLICK, this.OnClickSpinButton, this);
302	        } else {
303	            error('[FGRouletteManager] m_spinButton 未綁定');
304	        }
305	
306	        this.m_isEventRegistered = true;
307	    }
308	
309	    private UnregisterEvent(): void {
310	        if (!this.m_isEventRegistered) {
311	            return;
312	        }
313	
314	        FGRouletteManager.EVENTS_TO_REGISTER.forEach(eventName => {
315	            eventManager.UnRegister(eventName, this);
316	        });
317	
318	        if (this.m_spinButton?.node) {
319	            this.m_spinButton.node.off(Button.EventType.CLICK, this.OnClickSpinButton, this);
320	        }
321	
322	        this.m_isEventRegistered = false;
323	    }
