384	    /**
385	     * @ch 點擊 Spin 按鈕後旋轉一次，多指針同時停下指向各自扇區
386	     * 指針在轉盤邊緣等距分佈（間隔 120°），轉盤只轉一次，
387	     * 以第一個結果為基準計算停止角度，其餘指針自然對齊。
388	     */
389	    private async OnClickSpinButton(): Promise<void> {
390	        if (!this.m_isDataInitialized) {
391	            warn('[FGRouletteManager] OnClickSpinButton: 尚未呼叫 OPEN，無法旋轉');
392	            return;
393	        }
394	        if (this.IsRotating()) {
395	            return;
396	        }
397	
398	        this.unscheduleAllCallbacks();
399	        this.SetButtonInteractable(false);
400	
401	        // 廣播轉盤開始旋轉
402	        eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SPIN_START);
403	
404	        // 轉盤 Spine 切 Loop
405	        const rouletteSpine = Common.GetGameView().RouletteSpine;
406	        const loopKey = Common.GetGameView().IsLandscape ? "Loop_H" : "Loop";
407	        if (rouletteSpine) {
408	            // 用持久 event listener 監聽 Rudder 事件（SpineKit callback 在 loop 動畫首圈結束後會被清除）
409	            this.AttachRouletteSpineListener();
410	            SpineKit.PlayAnimation(rouletteSpine, loopKey, true, 0);
411	        }
412	        // 橫版 RudderBase 切 Loop_H
413	        if (Common.GetGameView().IsLandscape && Common.GetGameView().RudderBaseSpine) {
414	            SpineKit.PlayAnimation(Common.GetGameView().RudderBaseSpine, "Loop_H", true, 0);
415	        }
416	        // Pointer Spine 同步切 Loop
417	        const pointerSpine = Common.GetGameView().PointerSpine;
418	        if (pointerSpine) { log(`[Roulette] PointerSpine play ${loopKey}`); SpineKit.PlayAnimation(pointerSpine, loopKey, true, 0); }
419	
420	        // 找出正確的停止角度：讓所有結果都能被指針覆蓋
421	        // 指針位置：0°, 120°（2個時）或 0°, 120°, 240°（3個時）
422	        // 轉盤轉 θ 後，指針 i 指向轉盤上 (θ + i*120°) % 360 的扇區
423	        // 找一個 θ 使得 spinResults 的角度集合 = { (θ + i*120°)%360 | i < pointerCount }
424	        const targetDeg = this.CalcStopAngle();
425	        // 加上演出圈數，套用順時針方向（負值）
426	        const finalAngle = -(targetDeg + this.m_iCircleCount * 360);
427	
428	        await new Promise<void>(resolve => {
429	            this.StartRotateByAngle(finalAngle, () => resolve());
430	        });
431	
432	        // 播放 feature icon 選定效果（track 1~3）
433	        this.PlayFeatureIconBingo();
434	
435	        await Define.Wait(this, FGRouletteManager.DELAY_HIGHLIGHT);
436	
437	        this.OnAllSpinsFinish();
438	    }
