440	    /**
441	     * @ch 直接以目標角度啟動旋轉（三段式：加速→勻速→減速，速度連續）
442	     */
443	    private StartRotateByAngle(targetAngle: number, finishCallback?: () => void): void {
444	        if (!this.m_rotateRootNode || !this.m_rotateRootNode.isValid) {
445	            finishCallback?.();
446	            return;
447	        }
448	
449	        // 旋轉前關閉 NewBoneFollow 的 Rotation 跟隨，避免衝突
450	        const boneFollow = this.m_rotateRootNode.getComponent(NewBoneFollow);
451	        if (boneFollow) boneFollow.FollowRotation = false;
452	
453	        this.Stop();
454	
455	        const rotateNode = this.m_rotateRootNode;
456	        const currentEuler = rotateNode.eulerAngles;
457	        const startAngle = ((currentEuler?.z || 0) % 360 + 360) % 360;
458	        const totalOffset = targetAngle - startAngle;
459	        const totalTime = this.m_fRotateTime;
460	
461	        // 時間分段比例
462	        const t1 = 0.12;  // 加速結束時間點 (12%)
463	        const t2 = 0.35;  // 勻速結束時間點 (35%)
464	
465	        // 播放轉盤旋轉音效（loop）
466	        this.m_wheelSpinAudioId = AudioManager.Play(AudioManager.AudioClips.Wheel_spin, true);
467	
468	        const animTarget = { t: 0 };
469	        tween(animTarget)
470	            .to(totalTime, { t: 1 }, {
471	                easing: 'linear',
472	                onUpdate: () => {
473	                    const t = animTarget.t;
474	                    const progress = this.CalcSpeedCurve(t, t1, t2);
475	                    rotateNode.setRotationFromEuler(0, 0, startAngle + totalOffset * progress);
476	
477	                    // 根據瞬時速度調整音量（速度越快音量越大）
478	                    if (this.m_wheelSpinAudioId >= 0) {
479	                        const speed = this.CalcInstantSpeed(t, t1, t2);
480	                        AudioManager.SetVolume(this.m_wheelSpinAudioId, Math.max(0.2, speed));
481	                    }
482	                }
483	            })
484	            .call(() => {
485	                // 停止轉盤旋轉音效
486	                if (this.m_wheelSpinAudioId >= 0) {
487	                    AudioManager.Stop(this.m_wheelSpinAudioId);
488	                    this.m_wheelSpinAudioId = -1;
489	                }
490	                finishCallback?.();
491	            })
492	            .start();
493	    }
