495	    /**
496	     * @ch 處理轉盤 Spine 動畫事件（Rudder_Off / Rudder_On）
497	     */
498	    private OnRouletteSpineEvent(eventName: string): void {
499	        if (!this.m_rotateRootNode || !this.m_rotateRootNode.isValid) return;
500	        if (eventName === "Rudder_Off") {
501	            log(`[Roulette] Rudder_Off → hide RotateRootNode children`);
502	            this.m_rotateRootNode.active = false;
503	            this.m_rotateRootNode.children.forEach(child => child.active = false);
504	            this.m_rotateRootNode.setRotationFromEuler(0, 0, 0);
505	            const boneFollow = this.m_rotateRootNode.getComponent(NewBoneFollow);
506	            if (boneFollow) boneFollow.FollowRotation = true;
507	        } else if (eventName === "Rudder_On") {
508	            log(`[Roulette] Rudder_On → show RotateRootNode children`);
509	            this.m_rotateRootNode.active = true;
510	            this.m_rotateRootNode.children.forEach(child => child.active = true);
511	        }
512	    }
513	
514	    /**
515	     * @ch 自訂速度曲線：加速→勻速→減速，保證速度連續
516	     * @param t 當前時間 [0,1]
517	     * @param t1 加速結束時間點
518	     * @param t2 勻速結束時間點
519	     * @returns progress [0,1]
520	     */
521	    private CalcSpeedCurve(t: number, t1: number, t2: number): number {
522	        // 勻速段的歸一化速度 v（讓總距離 = 1）
523	        // 加速段面積 = 0.5*v*t1, 勻速段面積 = v*(t2-t1), 減速段面積 = 0.5*v*(1-t2)
524	        // 總面積 = v * (0.5*t1 + (t2-t1) + 0.5*(1-t2)) = v * (0.5 + 0.5*t2 - 0.5*t1) 不對
525	        // 正確：總面積 = 0.5*v*t1 + v*(t2-t1) + 0.5*v*(1-t2) = v*(0.5*t1 + t2-t1 + 0.5-0.5*t2)
526	        //            = v * (0.5 - 0.5*t1 + 0.5*t2)
527	        const v = 1 / (0.5 * t1 + (t2 - t1) + 0.5 * (1 - t2));
528	
529	        if (t <= t1) {
530	            // 加速段：線性加速 0→v，距離 = 0.5 * v * t^2 / t1
531	            const ratio = t / t1;
532	            return 0.5 * v * t1 * ratio * ratio;
533	        } else if (t <= t2) {
534	            // 勻速段：速度恆定 v
535	            const accelDist = 0.5 * v * t1;
536	            return accelDist + v * (t - t1);
537	        } else {
538	            // 減速段：線性減速 v→0，用 1-(1-ratio)^2 曲線
539	            const accelDist = 0.5 * v * t1;
540	            const constDist = v * (t2 - t1);
541	            const decelDuration = 1 - t2;
542	            const ratio = (t - t2) / decelDuration;
543	            const decelTotalDist = 0.5 * v * decelDuration;
544	            return accelDist + constDist + decelTotalDist * (2 * ratio - ratio * ratio);
545	        }
546	    }
547	
548	    /**
549	     * @ch 計算歸一化瞬時速度 [0,1]（用於音量映射）
550	     */
551	    private CalcInstantSpeed(t: number, t1: number, t2: number): number {
552	        const v = 1 / (0.5 * t1 + (t2 - t1) + 0.5 * (1 - t2));
553	        let speed: number;
554	        if (t <= t1) {
555	            speed = v * (t / t1);  // 線性加速
556	        } else if (t <= t2) {
557	            speed = v;  // 勻速
558	        } else {
559	            speed = v * (1 - (t - t2) / (1 - t2));  // 線性減速
560	        }
561	        return Math.min(1, speed / v);  // 歸一化到 [0,1]
562	    }
