592	    private async ShowUpgradesOnly(results: FGRouletteOption[], callback: (() => void) | null): Promise<void> {
593	        if (this.m_blackMaskNode) { this.SetUIShow(true); }
594	        
595	        await Define.Wait(this, FGRouletteManager.UPGRADES_DISPLAY_DELAY);
596	
597	        if (this.m_blackMaskNode) { this.m_blackMaskNode.active = false; }
598	        callback?.();
599	    }
