608	
609	    /**
610	     * @ch 設置 Spin 按鈕互動性
611	     * @param interactable 是否可互動
612	     */
613	    private SetButtonInteractable(interactable: boolean): void {
614	        if (!this.m_spinButton) {
615	            return;
616	        }
617	        this.m_spinButton.interactable = interactable;
618	    }
619	
620	    /**
621	     * @ch 將強化選項轉換為盤面索引（0-based）
622	     * @param option 強化選項
623	     */
624	    /**
625	     * @ch 取得選項對應的轉盤停止角度
626	     * 轉盤圖物理佈局：上方(0°)=Scatter, 左下(120°)=標靶, 右下(240°)=懸賞令
627	     * 角度意義：轉盤需要旋轉多少度，讓該選項對齊上方指針
628	     */
629	    private GetAngleByOption(option: FGRouletteOption): number {
630	        switch (option) {
631	            case FGRouletteOption.ScatterBoost: return 0;    // 已在上方，不用轉
632	            case FGRouletteOption.TargetExpand: return 120;  // 從左下轉 120° 到上方
633	            case FGRouletteOption.BountyDouble: return 240;  // 從右下轉 240° 到上方
634	            default:                            return 0;
635	        }
636	    }
637	
638	    /**
639	     * @ch 計算轉盤停止角度
640	     * 指針位置：上方(0°)、左下(120°)，右下(240°)無指針
641	     * 1 個指針：直接用該結果的角度
642	     * 2 個指針：讓沒中的扇區對到右下(240°)無指針位置
643	     * 3 個指針：全中，不用轉（0°）
644	     */
645	    private CalcStopAngle(): number {
646	        if (this.m_spinResults.length === 3) {
647	            return 0;
648	        }
649	
650	        if (this.m_spinResults.length === 1) {
651	            return this.GetAngleByOption(this.m_spinResults[0]);
652	        }
653	
654	        // 2 個指針：找出沒中的扇區，讓它對到 240°（無指針位置）
655	        const allOptions = [FGRouletteOption.ScatterBoost, FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble];
656	        const missedOption = allOptions.find(o => !this.m_spinResults.includes(o))!;
657	        const missedAngle = this.GetAngleByOption(missedOption);
658	        return (missedAngle - 240 + 360) % 360;
659	    }
