663	    /**
664	     * @ch 驗證 OPEN 事件參數
665	     * @param args 事件參數陣列
666	     */
667	    private ValidateOpenArgs(args: any[]): args is [number, FGRouletteOption[], (() => void)?] {
668	        const pointerCount = args[0];
669	        const spinResults  = args[1];
670	
671	        if (typeof pointerCount !== 'number' || pointerCount < 1 || pointerCount > 3) {
672	            error('[FGRouletteManager] OPEN: 無效的 pointerCount 參數（需為 1~3）', pointerCount);
673	            return false;
674	        }
675	
676	        if (!Array.isArray(spinResults) || spinResults.length !== pointerCount) {
677	            error('[FGRouletteManager] OPEN: spinResults 長度需等於 pointerCount', spinResults);
678	            return false;
679	        }
680	
681	        for (const option of spinResults) {
682	            if (!(option in FGRouletteOption)) {
683	                error('[FGRouletteManager] OPEN: spinResults 包含無效的 FGRouletteOption', option);
684	                return false;
685	            }
686	        }
687	
688	        return true;
689	    }
