701	            switch (evt.keyCode) {
702	                case KeyCode.KEY_Q:
703	                    eventManager.Dispatch(
704	                        FG_ROULETTE_MANAGER_EVENT.OPEN,
705	                        1,
706	                        [FGRouletteOption.TargetExpand],
707	                        () => { ; }
708	                    );
709	                    break;
710	
711	                case KeyCode.KEY_W:
712	                    eventManager.Dispatch(
713	                        FG_ROULETTE_MANAGER_EVENT.OPEN,
714	                        2,
715	                        [FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble],
716	                        () => { ; }
717	                    );
718	                    
719	                    break;
720	
721	                case KeyCode.KEY_E:
722	                    eventManager.Dispatch(
723	                        FG_ROULETTE_MANAGER_EVENT.OPEN,
724	                        3,
725	                        [FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble, FGRouletteOption.ScatterBoost],
726	                        () => { ; }
727	                    );
728	                    break;
729	            }
730	        }, this);
731	    }
732	    //#endregion
733	
734	    //#region Feature Icon Animation
735	    /**
736	     * @ch 轉盤停止後：選中播 Bingo→Bingo_Idle，未選中播 Black→Black_Idle
737	     * Icon1~3 用 track 1~3
738	     * Icon1=+spin(ScatterBoost=2), Icon2=標靶(TargetExpand=0), Icon3=懸賞(BountyDouble=1)
739	     */
740	    private static readonly OPTION_TO_ICON: ReadonlyArray<number> = [2, 3, 1]; // [TargetExpand→Icon2, BountyDouble→Icon3, ScatterBoost→Icon1]
741	
742	    private PlayFeatureIconBingo(): void {
743	        AudioManager.Play(AudioManager.AudioClips.Wheel_win);
744	        const spine = Common.GetGameView().FeatureSelectSpine;
745	        if (!spine) return;
746	        spine.node.active = true;
747	
748	        const selectedSet = new Set(this.m_spinResults.map(r => FGRouletteManager.OPTION_TO_ICON[r as number]));
749	        for (let iconIdx = 1; iconIdx <= FGRouletteManager.SLOT_COUNT; iconIdx++) {
750	            const track = iconIdx;
751	            const isSelected = selectedSet.has(iconIdx);
752	            const animName = isSelected ? `Icon${iconIdx}_Bingo` : `Icon${iconIdx}_Black`;
753	            const idleName = isSelected ? `Icon${iconIdx}_Bingo_Idle` : `Icon${iconIdx}_Black_Idle`;
754	
755	            spine.setAnimation(track, animName, false);
756	            spine.addAnimation(track, idleName, true, 0);
757	        }
758	    }
