import { _decorator, Animation, AnimationClip, Button, Color, error, EventKeyboard, Input, input, KeyCode, log, Node, sp, Sprite, SpriteFrame, tween, UIOpacity, Vec3, warn } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { Define } from 'db://astarte-framework/utilis';
import { DEBUG } from 'cc/env';
import { RouletteRotate } from '../Common/RouletteRotate';
import { Common } from '../Common/Common';
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import { NewBoneFollow } from 'db://astarte-framework/Component/Spine/New/NewBoneFollow';
import { AudioManager } from '../Audio/AudioManager';
import { FREE_GAME_UI_MANAGER_EVENT } from './FreeGameUIManager';

const { ccclass, property } = _decorator;

// ─────────────────────────────────────────────
//  事件定義
// ─────────────────────────────────────────────
export const FG_ROULETTE_MANAGER_EVENT = {
    /**
     * @ch 開啟轉盤畫面，並儲存指針數量與各指針的獲獎結果（不立即旋轉）
     * @param pointerCount number             — 指針數量（SCATTER 3→1, 4→2, 5+→3）
     * @param spinResults  FGRouletteOption[] — 各指針的最終獲獎結果（長度需等於 pointerCount）
     * @param callback     () => void         — 旋轉停止後呼叫（可選）
     */
    OPEN: 'FG_ROULETTE_MANAGER_OPEN',

    /**
     * @ch 直接顯示 UPGRADES 面板（不旋轉）
     * @param spinResults FGRouletteOption[] — 獲獎結果
     * @param callback () => void — 面板關閉後呼叫
     */
    SHOW_UPGRADES: 'FG_ROULETTE_MANAGER_SHOW_UPGRADES',

    /**
     * @ch 旋轉結束後廣播
     * @param spinResults FGRouletteOption[] — 本次各指針的獲獎結果（與 OPEN 傳入的相同）
     */
    SPIN_FINISH: 'FG_ROULETTE_MANAGER_SPIN_FINISH',

    /**@ch 轉盤開始旋轉時廣播*/
    SPIN_START: 'FG_ROULETTE_MANAGER_SPIN_START',

    /**@ch 僅顯示指針（不旋轉）*/
    SHOW_POINTER: 'FG_ROULETTE_MANAGER_SHOW_POINTER',

    /**@ch 顯示黑章遮罩（淡入）*/
    SHOW_BLACK_MASK: 'FG_ROULETTE_MANAGER_SHOW_BLACK_MASK',

    /**@ch 隱藏黑章遮罩（淡出）*/
    HIDE_BLACK_MASK: 'FG_ROULETTE_MANAGER_HIDE_BLACK_MASK',

    /**@ch 不旋轉直接走完 OnAllSpinsFinish 清理（三特色全拿用）*/
    FINISH_WITHOUT_SPIN: 'FG_ROULETTE_MANAGER_FINISH_WITHOUT_SPIN',

    /**@ch 鎖住 Spin 按鈕（三特色全拿用，防止玩家手動觸發旋轉）*/
    LOCK_SPIN: 'FG_ROULETTE_MANAGER_LOCK_SPIN',

    /**@ch 設定 RouletteSpine 的 Rudder event listener（進場結束後呼叫）*/
    SETUP_SPINE_LISTENER: 'FG_ROULETTE_MANAGER_SETUP_SPINE_LISTENER',
};

// ─────────────────────────────────────────────
//  FG 轉盤強化選項
// ─────────────────────────────────────────────
/** FG 轉盤的 3 種強化選項 */
export enum FGRouletteOption {
    /** 標靶符號強化：3X3 的範圍提升至 5X5 */
    TargetExpand = 0,
    /** 懸賞令強化：FG 中會出現兩張懸賞令，效果可疊加 */
    BountyDouble = 1,
    /** SCATTER 符號強化：FG 中轉出的 SCATTER 符號，加 1 局提升為加 2 局 */
    ScatterBoost = 2,
}

// ─────────────────────────────────────────────
//  主元件
// ─────────────────────────────────────────────
/**
 * FG 入場轉盤管理元件
 * - 固定 3 個區塊：標靶符號強化 / 懸賞令強化 / SCATTER 符號強化
 * - 繼承 RouletteRotate，直接沿用旋轉邏輯
 * - 每次 OPEN 只旋轉一次；多個指針同時停下，由外部 UI 呈現各指針位置
 * - 透過 eventManager 接收指令 / 廣播結果
 * - 內建 Spin 按鈕管理，點擊後觸發旋轉，旋轉期間禁用按鈕
 *
 * 指針數量對照（SCATTER 數量由外部決定，隨 OPEN 事件傳入）：
 *   SCATTER 3  → pointerCount = 1
 *   SCATTER 4  → pointerCount = 2
 *   SCATTER 5+ → pointerCount = 3
 */
@ccclass('FGRouletteManager')
export class FGRouletteManager extends RouletteRotate {

    //#region Constants
    private static readonly SLOT_COUNT = 3;
    /** @ch 每次停輪後高亮展示時間（秒） */
    private static readonly DELAY_HIGHLIGHT = 1.5;
    /** @ch 多指針間的間隔時間（秒） */
    private static readonly DELAY_BETWEEN_SPINS = 1.0;
    /** @ch 自動開始旋轉的等待時間（秒） */
    private static readonly AUTO_START_DELAY = 5.0;
    /** @ch UPGRADES 面板展示時間（秒） */
    private static readonly UPGRADES_DISPLAY_DELAY = 3.0;

    private static readonly EVENTS_TO_REGISTER = [
        FG_ROULETTE_MANAGER_EVENT.OPEN,
        FG_ROULETTE_MANAGER_EVENT.SHOW_UPGRADES,
        FG_ROULETTE_MANAGER_EVENT.SHOW_POINTER,
        FG_ROULETTE_MANAGER_EVENT.SHOW_BLACK_MASK,
        FG_ROULETTE_MANAGER_EVENT.HIDE_BLACK_MASK,
        FG_ROULETTE_MANAGER_EVENT.FINISH_WITHOUT_SPIN,
        FG_ROULETTE_MANAGER_EVENT.LOCK_SPIN,
        FG_ROULETTE_MANAGER_EVENT.SETUP_SPINE_LISTENER,
    ];
    //#endregion

    //#region Properties
    @property({ type: Node, tooltip: '黑色遮罩節點（OPEN 後顯示，關閉時隱藏）' })
    private m_blackMaskNode: Node = null;
    public get BlackMaskNode(): Node { return this.m_blackMaskNode; }

    @property({ type: Animation, tooltip: '黑章 Animation component' })
    private m_blackMaskAnim: Animation = null;

    @property({ type: AnimationClip, tooltip: '黑章進場 clip' })
    private m_blackMaskInClip: AnimationClip = null;

    @property({ type: AnimationClip, tooltip: '黑章退場 clip' })
    private m_blackMaskOutClip: AnimationClip = null;

    @property({ type: Node, tooltip: '橫版砲台節點' })
    private m_cannonNode_H: Node = null;

    @property({ type: Node, tooltip: '黑章下砲台父物件（橫版）' })
    private m_cannonParentUnderMask: Node = null;

    @property({ type: Button, tooltip: 'Spin 按鈕元件' })
    private m_spinButton: Button = null;

    //#endregion

    //#region Variables
    /** @ch 是否已註冊事件 */
    private m_isEventRegistered: boolean = false;

    /** @ch 轉盤旋轉音效 ID（-1 表示未播放） */
    private m_wheelSpinAudioId: number = -1;

    /** @ch 砲台原始父節點 */
    private m_cannonOriginalParent: Node = null;

    /** @ch 是否已完成資料初始化（OPEN 後設為 true） */
    private m_isDataInitialized: boolean = false;

    /** @ch 本次開盤的指針數量 */
    private m_pointerCount: number = 0;

    /** @ch 本次旋轉各指針的獲獎結果（OPEN 時由外部傳入） */
    private m_spinResults: FGRouletteOption[] = [];

    /** @ch 旋轉停止後的 callback（OPEN 時由外部傳入，可選） */
    private m_onSpinFinishCallback: (() => void) | null = null;
    //#endregion

    //#region LifeCycle
    protected onLoad(): void {
        this.m_iItemCount = FGRouletteManager.SLOT_COUNT;
        this.m_iCircleCount = 9;          // 增加圈數提高勻速段速度
        this.m_fRotateTime = 4.0;         // 總旋轉時間（秒）
        this.m_easing = 'quintOut';       // 一開始快速衝頂，後段非常緩慢地停下
        this.RegisterEvent();
        this.SetUIShow(false);
        this.SetPointerRootShow(false);
        this.CheckTestKeyCode();
    }

    protected onDestroy(): void {
        this.UnregisterEvent();
        super.onDestroy();
    }
    //#endregion

    //#region EventManager
    /**
     * @ch 事件處理（由 eventManager 呼叫）
     * @param event 事件名稱
     * @param args  事件參數
     */
    OnEvent(event: string, ...args: any[]): void {
        switch (event) {
            case FG_ROULETTE_MANAGER_EVENT.OPEN: {
                if (!this.ValidateOpenArgs(args)) {
                    error('[FGRouletteManager] OPEN event requires parameters: (pointerCount: number, spinResults: FGRouletteOption[], callback?: () => void)');
                    return;
                }
                const pointerCount = args[0] as number;
                const spinResults  = args[1] as FGRouletteOption[];
                const callback     = typeof args[2] === 'function' ? args[2] as () => void : null;
                this.Open(pointerCount, spinResults, callback);
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.SHOW_UPGRADES: {
                const results = args[0] as FGRouletteOption[];
                const cb = typeof args[1] === 'function' ? args[1] as () => void : null;
                this.ShowUpgradesOnly(results, cb);
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.SHOW_POINTER: {
                const count = args[0] as number;
                this.SetPointerByCount(count);
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.SHOW_BLACK_MASK: {
                if (this.m_blackMaskNode) {
                    this.m_blackMaskNode.active = true;
                    if (this.m_blackMaskAnim && this.m_blackMaskInClip) this.m_blackMaskAnim.play(this.m_blackMaskInClip.name);
                }
                if (Common.GetGameView().IsLandscape && this.m_cannonNode_H && this.m_cannonParentUnderMask) {
                    this.m_cannonOriginalParent = this.m_cannonNode_H.parent;
                    this.m_cannonNode_H.setParent(this.m_cannonParentUnderMask, true);
                }
                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK);
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.HIDE_BLACK_MASK: {
                if (Common.GetGameView().IsLandscape && this.m_cannonNode_H && this.m_cannonOriginalParent) {
                    this.m_cannonNode_H.setParent(this.m_cannonOriginalParent, true);
                    this.m_cannonOriginalParent = null;
                }
                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK);
                this.PlayFeatureIconOut();
                if (this.m_blackMaskNode) {
                    if (this.m_blackMaskAnim && this.m_blackMaskOutClip) {
                        this.m_blackMaskAnim.play(this.m_blackMaskOutClip.name);
                        this.m_blackMaskAnim.once(Animation.EventType.FINISHED, () => { this.m_blackMaskNode.active = false; });
                    } else {
                        this.m_blackMaskNode.active = false;
                    }
                }
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.FINISH_WITHOUT_SPIN: {
                // 3 feature 全拿不走 OPEN，需在此設 spinResults
                if (args.length > 0 && Array.isArray(args[0])) {
                    this.m_spinResults = [...args[0]];
                }
                this.PlayFeatureIconBingo();
                this.OnAllSpinsFinish();
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.LOCK_SPIN: {
                this.SetButtonInteractable(false);
                this.unscheduleAllCallbacks();
                break;
            }

            case FG_ROULETTE_MANAGER_EVENT.SETUP_SPINE_LISTENER: {
                this.AttachRouletteSpineListener();
                break;
            }

            default:
                warn(`[FGRouletteManager] OnEvent: 未知的事件 ${event}`);
        }
    }

    /**
     * @ch 掛上轉盤 Spine 的持久 event listener（監聽 Rudder 事件）
     * SETUP_SPINE_LISTENER 事件與 OnClickSpinButton 共用，復用同一個 listener 實例
     */
    private m_rouletteSpineListener: (entry: sp.spine.TrackEntry, event: sp.spine.Event) => void = null;

    private AttachRouletteSpineListener(): void {
        const rouletteSpine = Common.GetGameView().RouletteSpine;
        if (!rouletteSpine) {
            return;
        }
        if (!this.m_rouletteSpineListener) {
            this.m_rouletteSpineListener = (entry: sp.spine.TrackEntry, event: sp.spine.Event) => {
                this.OnRouletteSpineEvent(event.data.name);
            };
        }
        rouletteSpine.setEventListener(this.m_rouletteSpineListener);
    }

    private RegisterEvent(): void {
        if (this.m_isEventRegistered) {
            return;
        }

        FGRouletteManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        if (this.m_spinButton?.node) {
            this.m_spinButton.node.on(Button.EventType.CLICK, this.OnClickSpinButton, this);
        } else {
            error('[FGRouletteManager] m_spinButton 未綁定');
        }

        this.m_isEventRegistered = true;
    }

    private UnregisterEvent(): void {
        if (!this.m_isEventRegistered) {
            return;
        }

        FGRouletteManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        if (this.m_spinButton?.node) {
            this.m_spinButton.node.off(Button.EventType.CLICK, this.OnClickSpinButton, this);
        }

        this.m_isEventRegistered = false;
    }
    //#endregion

    //#region Private Methods
    /**
     * @ch 開啟轉盤畫面，儲存指針數量與獲獎結果
     * @param pointerCount 指針數量
     * @param spinResults  各指針對應的獲獎選項
     */
    private Open(pointerCount: number, spinResults: FGRouletteOption[], callback: (() => void) | null = null): void {
        this.m_pointerCount            = pointerCount;
        this.m_spinResults             = [...spinResults];
        this.m_onSpinFinishCallback    = callback;
        this.m_isDataInitialized       = true;
        this.SetPointerRootShow(true);
        this.SetPointerByCount(pointerCount);
        this.SetUIShow(true);
        this.SetButtonInteractable(true);

        // 5 秒後自動開始
        this.scheduleOnce(() => {
            if (this.m_isDataInitialized && !this.IsRotating()) {
                this.OnClickSpinButton();
            }
        }, FGRouletteManager.AUTO_START_DELAY);
    }

    /**
     * @ch 設置指針根節點顯示
     * @param isShow 是否顯示
     */
    private SetPointerRootShow(isShow: boolean): void {
    }

    /**
     * @ch 根據指針數量顯示對應節點
     */
    private SetPointerByCount(count: number): void {
        // PointerSpine 根據指針數量切 skin
        const pointerSpine = Common.GetGameView().PointerSpine;
        if (pointerSpine) {
            if (count > 0) {
                pointerSpine.node.active = true;
                pointerSpine.setSkin(`Arrow_0${count}`);
                pointerSpine.setSlotsToSetupPose();
            } else {
                pointerSpine.clearTrack(0);
                pointerSpine.node.active = false;
            }
        }
    }



    /**
     * @ch 設置轉盤 UI 根節點顯示
     * @param isShow 是否顯示
     */
    private SetUIShow(isShow: boolean): void {
    }

    /**
     * @ch 點擊 Spin 按鈕後旋轉一次，多指針同時停下指向各自扇區
     * 指針在轉盤邊緣等距分佈（間隔 120°），轉盤只轉一次，
     * 以第一個結果為基準計算停止角度，其餘指針自然對齊。
     */
    private async OnClickSpinButton(): Promise<void> {
        if (!this.m_isDataInitialized) {
            warn('[FGRouletteManager] OnClickSpinButton: 尚未呼叫 OPEN，無法旋轉');
            return;
        }
        if (this.IsRotating()) {
            return;
        }

        this.unscheduleAllCallbacks();
        this.SetButtonInteractable(false);

        // 廣播轉盤開始旋轉
        eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SPIN_START);

        // 轉盤 Spine 切 Loop
        const rouletteSpine = Common.GetGameView().RouletteSpine;
        const loopKey = Common.GetGameView().IsLandscape ? "Loop_H" : "Loop";
        if (rouletteSpine) {
            // 用持久 event listener 監聽 Rudder 事件（SpineKit callback 在 loop 動畫首圈結束後會被清除）
            this.AttachRouletteSpineListener();
            SpineKit.PlayAnimation(rouletteSpine, loopKey, true, 0);
        }
        // 橫版 RudderBase 切 Loop_H
        if (Common.GetGameView().IsLandscape && Common.GetGameView().RudderBaseSpine) {
            SpineKit.PlayAnimation(Common.GetGameView().RudderBaseSpine, "Loop_H", true, 0);
        }
        // Pointer Spine 同步切 Loop
        const pointerSpine = Common.GetGameView().PointerSpine;
        if (pointerSpine) { log(`[Roulette] PointerSpine play ${loopKey}`); SpineKit.PlayAnimation(pointerSpine, loopKey, true, 0); }

        // 找出正確的停止角度：讓所有結果都能被指針覆蓋
        // 指針位置：0°, 120°（2個時）或 0°, 120°, 240°（3個時）
        // 轉盤轉 θ 後，指針 i 指向轉盤上 (θ + i*120°) % 360 的扇區
        // 找一個 θ 使得 spinResults 的角度集合 = { (θ + i*120°)%360 | i < pointerCount }
        const targetDeg = this.CalcStopAngle();
        // 加上演出圈數，套用順時針方向（負值）
        const finalAngle = -(targetDeg + this.m_iCircleCount * 360);

        await new Promise<void>(resolve => {
            this.StartRotateByAngle(finalAngle, () => resolve());
        });

        // 播放 feature icon 選定效果（track 1~3）
        this.PlayFeatureIconBingo();

        await Define.Wait(this, FGRouletteManager.DELAY_HIGHLIGHT);

        this.OnAllSpinsFinish();
    }

    /**
     * @ch 直接以目標角度啟動旋轉（三段式：加速→勻速→減速，速度連續）
     */
    private StartRotateByAngle(targetAngle: number, finishCallback?: () => void): void {
        if (!this.m_rotateRootNode || !this.m_rotateRootNode.isValid) {
            finishCallback?.();
            return;
        }

        // 旋轉前關閉 NewBoneFollow 的 Rotation 跟隨，避免衝突
        const boneFollow = this.m_rotateRootNode.getComponent(NewBoneFollow);
        if (boneFollow) boneFollow.FollowRotation = false;

        this.Stop();

        const rotateNode = this.m_rotateRootNode;
        const currentEuler = rotateNode.eulerAngles;
        const startAngle = ((currentEuler?.z || 0) % 360 + 360) % 360;
        const totalOffset = targetAngle - startAngle;
        const totalTime = this.m_fRotateTime;

        // 時間分段比例
        const t1 = 0.12;  // 加速結束時間點 (12%)
        const t2 = 0.35;  // 勻速結束時間點 (35%)

        // 播放轉盤旋轉音效（loop）
        this.m_wheelSpinAudioId = AudioManager.Play(AudioManager.AudioClips.Wheel_spin, true);

        const animTarget = { t: 0 };
        tween(animTarget)
            .to(totalTime, { t: 1 }, {
                easing: 'linear',
                onUpdate: () => {
                    const t = animTarget.t;
                    const progress = this.CalcSpeedCurve(t, t1, t2);
                    rotateNode.setRotationFromEuler(0, 0, startAngle + totalOffset * progress);

                    // 根據瞬時速度調整音量（速度越快音量越大）
                    if (this.m_wheelSpinAudioId >= 0) {
                        const speed = this.CalcInstantSpeed(t, t1, t2);
                        AudioManager.SetVolume(this.m_wheelSpinAudioId, Math.max(0.2, speed));
                    }
                }
            })
            .call(() => {
                // 停止轉盤旋轉音效
                if (this.m_wheelSpinAudioId >= 0) {
                    AudioManager.Stop(this.m_wheelSpinAudioId);
                    this.m_wheelSpinAudioId = -1;
                }
                finishCallback?.();
            })
            .start();
    }

    /**
     * @ch 處理轉盤 Spine 動畫事件（Rudder_Off / Rudder_On）
     */
    private OnRouletteSpineEvent(eventName: string): void {
        if (!this.m_rotateRootNode || !this.m_rotateRootNode.isValid) return;
        if (eventName === "Rudder_Off") {
            log(`[Roulette] Rudder_Off → hide RotateRootNode children`);
            this.m_rotateRootNode.active = false;
            this.m_rotateRootNode.children.forEach(child => child.active = false);
            this.m_rotateRootNode.setRotationFromEuler(0, 0, 0);
            const boneFollow = this.m_rotateRootNode.getComponent(NewBoneFollow);
            if (boneFollow) boneFollow.FollowRotation = true;
        } else if (eventName === "Rudder_On") {
            log(`[Roulette] Rudder_On → show RotateRootNode children`);
            this.m_rotateRootNode.active = true;
            this.m_rotateRootNode.children.forEach(child => child.active = true);
        }
    }

    /**
     * @ch 自訂速度曲線：加速→勻速→減速，保證速度連續
     * @param t 當前時間 [0,1]
     * @param t1 加速結束時間點
     * @param t2 勻速結束時間點
     * @returns progress [0,1]
     */
    private CalcSpeedCurve(t: number, t1: number, t2: number): number {
        // 勻速段的歸一化速度 v（讓總距離 = 1）
        // 加速段面積 = 0.5*v*t1, 勻速段面積 = v*(t2-t1), 減速段面積 = 0.5*v*(1-t2)
        // 總面積 = v * (0.5*t1 + (t2-t1) + 0.5*(1-t2)) = v * (0.5 + 0.5*t2 - 0.5*t1) 不對
        // 正確：總面積 = 0.5*v*t1 + v*(t2-t1) + 0.5*v*(1-t2) = v*(0.5*t1 + t2-t1 + 0.5-0.5*t2)
        //            = v * (0.5 - 0.5*t1 + 0.5*t2)
        const v = 1 / (0.5 * t1 + (t2 - t1) + 0.5 * (1 - t2));

        if (t <= t1) {
            // 加速段：線性加速 0→v，距離 = 0.5 * v * t^2 / t1
            const ratio = t / t1;
            return 0.5 * v * t1 * ratio * ratio;
        } else if (t <= t2) {
            // 勻速段：速度恆定 v
            const accelDist = 0.5 * v * t1;
            return accelDist + v * (t - t1);
        } else {
            // 減速段：線性減速 v→0，用 1-(1-ratio)^2 曲線
            const accelDist = 0.5 * v * t1;
            const constDist = v * (t2 - t1);
            const decelDuration = 1 - t2;
            const ratio = (t - t2) / decelDuration;
            const decelTotalDist = 0.5 * v * decelDuration;
            return accelDist + constDist + decelTotalDist * (2 * ratio - ratio * ratio);
        }
    }

    /**
     * @ch 計算歸一化瞬時速度 [0,1]（用於音量映射）
     */
    private CalcInstantSpeed(t: number, t1: number, t2: number): number {
        const v = 1 / (0.5 * t1 + (t2 - t1) + 0.5 * (1 - t2));
        let speed: number;
        if (t <= t1) {
            speed = v * (t / t1);  // 線性加速
        } else if (t <= t2) {
            speed = v;  // 勻速
        } else {
            speed = v * (1 - (t - t2) / (1 - t2));  // 線性減速
        }
        return Math.min(1, speed / v);  // 歸一化到 [0,1]
    }



    /**
     * @ch 選項對應 glow 節點陣列的 index（依 Prefab 中的擺放順序）
     */
    private GetGlowIndexByOption(option: FGRouletteOption): number {
        switch (option) {
            case FGRouletteOption.ScatterBoost: return 0;  // 上方
            case FGRouletteOption.TargetExpand: return 1;  // 左下
            case FGRouletteOption.BountyDouble: return 2;  // 右下
            default:                            return 0;
        }
    }

    /** @ch 所有指針旋轉完成後顯示 UPGRADES 面板，再關閉 UI 並廣播結果 */
    private async OnAllSpinsFinish(): Promise<void> {
        this.SetUIShow(false);
        this.SetPointerRootShow(false);
        this.SetButtonInteractable(true);
        this.m_isDataInitialized = false;

        eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SPIN_FINISH, this.m_spinResults);
        const cb = this.m_onSpinFinishCallback;
        this.m_onSpinFinishCallback = null;
        cb?.();
    }

    /** @ch 直接顯示 UPGRADES 面板（不旋轉），展示後回呼 */
    private async ShowUpgradesOnly(results: FGRouletteOption[], callback: (() => void) | null): Promise<void> {
        if (this.m_blackMaskNode) { this.SetUIShow(true); }

        await Define.Wait(this, FGRouletteManager.UPGRADES_DISPLAY_DELAY);

        if (this.m_blackMaskNode) { this.m_blackMaskNode.active = false; }
        callback?.();
    }









    /**
     * @ch 設置 Spin 按鈕互動性
     * @param interactable 是否可互動
     */
    private SetButtonInteractable(interactable: boolean): void {
        if (!this.m_spinButton) {
            return;
        }
        this.m_spinButton.interactable = interactable;
    }

    /**
     * @ch 將強化選項轉換為盤面索引（0-based）
     * @param option 強化選項
     */
    /**
     * @ch 取得選項對應的轉盤停止角度
     * 轉盤圖物理佈局：上方(0°)=Scatter, 左下(120°)=標靶, 右下(240°)=懸賞令
     * 角度意義：轉盤需要旋轉多少度，讓該選項對齊上方指針
     */
    private GetAngleByOption(option: FGRouletteOption): number {
        switch (option) {
            case FGRouletteOption.ScatterBoost: return 0;    // 已在上方，不用轉
            case FGRouletteOption.TargetExpand: return 120;  // 從左下轉 120° 到上方
            case FGRouletteOption.BountyDouble: return 240;  // 從右下轉 240° 到上方
            default:                            return 0;
        }
    }

    /**
     * @ch 計算轉盤停止角度
     * 指針位置：上方(0°)、左下(120°)，右下(240°)無指針
     * 1 個指針：直接用該結果的角度
     * 2 個指針：讓沒中的扇區對到右下(240°)無指針位置
     * 3 個指針：全中，不用轉（0°）
     */
    private CalcStopAngle(): number {
        if (this.m_spinResults.length === 3) {
            return 0;
        }

        if (this.m_spinResults.length === 1) {
            return this.GetAngleByOption(this.m_spinResults[0]);
        }

        // 2 個指針：找出沒中的扇區，讓它對到 240°（無指針位置）
        const allOptions = [FGRouletteOption.ScatterBoost, FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble];
        const missedOption = allOptions.find(o => !this.m_spinResults.includes(o))!;
        const missedAngle = this.GetAngleByOption(missedOption);
        return (missedAngle - 240 + 360) % 360;
    }
    //#endregion

    //#region Validators
    /**
     * @ch 驗證 OPEN 事件參數
     * @param args 事件參數陣列
     */
    private ValidateOpenArgs(args: any[]): args is [number, FGRouletteOption[], (() => void)?] {
        const pointerCount = args[0];
        const spinResults  = args[1];

        if (typeof pointerCount !== 'number' || pointerCount < 1 || pointerCount > 3) {
            error('[FGRouletteManager] OPEN: 無效的 pointerCount 參數（需為 1~3）', pointerCount);
            return false;
        }

        if (!Array.isArray(spinResults) || spinResults.length !== pointerCount) {
            error('[FGRouletteManager] OPEN: spinResults 長度需等於 pointerCount', spinResults);
            return false;
        }

        for (const option of spinResults) {
            if (!(option in FGRouletteOption)) {
                error('[FGRouletteManager] OPEN: spinResults 包含無效的 FGRouletteOption', option);
                return false;
            }
        }

        return true;
    }
    //#endregion

    //#region Debug
    /**
     * @ch 測試按鍵（僅 DEBUG 模式有效）
     * - Q：呼叫 OPEN 事件（pointerCount=1，結果為 TargetExpand）
     * - W：呼叫 OPEN 事件（pointerCount=2，結果為 TargetExpand + BountyDouble）
     * - E：呼叫 OPEN 事件（pointerCount=3，全部選項）
     */
    private CheckTestKeyCode(): void {
        input.on(Input.EventType.KEY_DOWN, (evt: EventKeyboard) => {
            switch (evt.keyCode) {
                case KeyCode.KEY_Q:
                    eventManager.Dispatch(
                        FG_ROULETTE_MANAGER_EVENT.OPEN,
                        1,
                        [FGRouletteOption.TargetExpand],
                        () => { ; }
                    );
                    break;

                case KeyCode.KEY_W:
                    eventManager.Dispatch(
                        FG_ROULETTE_MANAGER_EVENT.OPEN,
                        2,
                        [FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble],
                        () => { ; }
                    );

                    break;

                case KeyCode.KEY_E:
                    eventManager.Dispatch(
                        FG_ROULETTE_MANAGER_EVENT.OPEN,
                        3,
                        [FGRouletteOption.TargetExpand, FGRouletteOption.BountyDouble, FGRouletteOption.ScatterBoost],
                        () => { ; }
                    );
                    break;
            }
        }, this);
    }
    //#endregion

    //#region Feature Icon Animation
    /**
     * @ch 轉盤停止後：選中播 Bingo→Bingo_Idle，未選中播 Black→Black_Idle
     * Icon1~3 用 track 1~3
     * Icon1=+spin(ScatterBoost=2), Icon2=標靶(TargetExpand=0), Icon3=懸賞(BountyDouble=1)
     */
    private static readonly OPTION_TO_ICON: ReadonlyArray<number> = [2, 3, 1]; // [TargetExpand→Icon2, BountyDouble→Icon3, ScatterBoost→Icon1]

    private PlayFeatureIconBingo(): void {
        AudioManager.Play(AudioManager.AudioClips.Wheel_win);
        const spine = Common.GetGameView().FeatureSelectSpine;
        if (!spine) return;
        spine.node.active = true;

        const selectedSet = new Set(this.m_spinResults.map(r => FGRouletteManager.OPTION_TO_ICON[r as number]));
        for (let iconIdx = 1; iconIdx <= FGRouletteManager.SLOT_COUNT; iconIdx++) {
            const track = iconIdx;
            const isSelected = selectedSet.has(iconIdx);
            const animName = isSelected ? `Icon${iconIdx}_Bingo` : `Icon${iconIdx}_Black`;
            const idleName = isSelected ? `Icon${iconIdx}_Bingo_Idle` : `Icon${iconIdx}_Black_Idle`;

            spine.setAnimation(track, animName, false);
            spine.addAnimation(track, idleName, true, 0);
        }
    }

    /**
     * @ch 轉盤播 Out 時：選中播 Bingo_Out，未選中播 Black_Out
     */
    public PlayFeatureIconOut(): void {
        const spine = Common.GetGameView().FeatureSelectSpine;
        if (!spine) return;

        const selectedSet = new Set(this.m_spinResults.map(r => FGRouletteManager.OPTION_TO_ICON[r as number]));
        for (let iconIdx = 1; iconIdx <= FGRouletteManager.SLOT_COUNT; iconIdx++) {
            const track = iconIdx;
            const isSelected = selectedSet.has(iconIdx);
            const outName = isSelected ? `Icon${iconIdx}_Bingo_Out` : `Icon${iconIdx}_Black_Out`;

            spine.setAnimation(track, outName, false);
        }
        // Out 播完後關閉
        const longestTrack = spine.getCurrent(1);
        if (longestTrack) {
            spine.scheduleOnce(() => { spine.node.active = false; }, longestTrack.animationEnd);
        }
    }
    //#endregion
}

