236	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
237	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
238	                break;
239	
240	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
241	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
242	                break;
243	
244	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
245	                this.HandleGameIntroComplete();
246	                break;
247	
248	            case WANTED_POSTER_MANAGER_EVENT.PLAY_OUT_ALL:
