286	    /**
287	     * @ch 處理 PLAY_MARK 事件
288	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
289	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
290	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
291	     * EH-9：resolve callback 缺失 → error（caller bug）
292	     */
293	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
294	        if (typeof resolve !== 'function') {
295	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
296	            return;
297	        }
298	        const items = this.GetItemsByBaseSymbol(baseSymbol);
299	        if (items.length === 0) {
300	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
301	            resolve();
302	            return;
303	        }
304	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
305	    }
306	
307	    /**
308	     * @ch 處理 PLAY_MARK_ACTIVE 事件
309	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
310	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
311	     * EH-9：resolve callback 缺失 → error
312	     */
313	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
314	        if (typeof resolve !== 'function') {
315	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
316	            return;
317	        }
318	        const items = this.GetItemsByBaseSymbol(baseSymbol);
319	        if (items.length === 0) {
320	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
321	            resolve();
322	            return;
323	        }
324	        // ── 同步段（Promise.all 之前）：先清本批綁定。並行的其他 dispatch（WantedPosterState 跨 group）
325	        //    也各自同步清，故動畫完成時的 ghost 判定能看到「本波所有離場者皆已退」（§5.5 race 修正）
326	        for (const item of items) {
327	            const idx = this.m_wantedPosterItems.indexOf(item);
328	            if (idx >= 0) this.m_currentBounty[idx] = null;
329	            item.ClearBaseSymbol();
330	        }
331	        // ── 非同步段：動畫播完才切換視覺。判定移到 .then（此時全波同步段已執行完）：
332	        //    仍有 real（survivor 留場）→ 轉 ghost 撐位讓 survivor 不 snap；否則真消失（BC-G6）
333	        Promise.all(items.map(item =>
334	            item.PlayMarkActive().then(() => {
335	                if (this.m_currentBounty.some(b => b !== null)) item.SetContentVisible(false);
336	                else item.node.active = false;
337	            })
338	        )).then(() => {
339	            // 本波後若全場無 real → 釋放殘留 ghost（避免上一輪保留的 ghost 隱形殘留 · §5.3.1）
340	            if (!this.m_currentBounty.some(b => b !== null)) this.NormalizeGhosts();
341	            resolve();
342	        });
343	    }
