405	    //#region Methods
406	    /**
407	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
408	     *
409	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
410	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
411	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
412	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
413	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
414	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
415	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
416	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
417	     *
418	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
419	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
420	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
421	     */
422	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
423	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
424	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
425	            return;
426	        }
427	        this.EnsureCurrentBountySize();
428	
429	        const count = this.m_wantedPosterItems.length;
430	        // 本輪要顯示的 bounty（Multiple>0 且 BaseSymbol 非 Wanted_Empty 佔位），超量截斷至 item 數量上限
431	        // BaseSymbol === Wanted_Empty 視同空資料（懸賞海報空位），一併排除不顯示
432	        const newBounties = dataList.filter(d => d && d.Multiple > 0 && d.BaseSymbol !== Symbol.Wanted_Empty);
433	        if (newBounties.length > count) {
434	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
435	                newBounties.length, '>', count);
436	            newBounties.length = count;
437	        }
438	
439	        if (isNewRound) {
440	            this.RebuildAll(newBounties);
441	        } else {
442	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
443	        }
444	    }
445	
446	    /**
447	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
448	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
449	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
450	     */
451	    private RebuildAll(newBounties: IBountyData[]) {
452	        // 整批重建前先釋放殘留 ghost：使下方以 node.active 判退場的迴圈不被 ghost（active 但隱形）干擾（BC-G4 · D5）
453	        this.NormalizeGhosts();
454	        const count = this.m_wantedPosterItems.length;
455	
456	        const outPromises: Promise<void>[] = [];
457	        for (let i = 0; i < count; i++) {
458	            const item = this.m_wantedPosterItems[i];
459	            if (item && item.node.active) {
460	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
461	            }
462	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
463	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
464	        }
465	
466	        const enterAll = () => {
467	            for (let i = 0; i < newBounties.length; i++) {
468	                const item = this.m_wantedPosterItems[i];
469	                if (!item) continue;
470	                // 先 active 再 ShowContent 再 setSkin：inactive/Content off 時 setSkin 不重建 render data（殘留舊 skin）
471	                item.node.active = true;
472	                item.SetContentVisible(true);
473	                item.SetWantedPosterData(newBounties[i]);
474	                item.PlayIn();
475	            }
476	        };
477	
478	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
479	        else enterAll();
480	    }
481	
482	    /**
483	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
484	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
485	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
486	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
487	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
488	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
489	     */
490	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
491	        const count = this.m_wantedPosterItems.length;
492	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
493	
494	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
495	        const pool = new Map<number, IBountyData[]>();
496	        for (const b of newBounties) {
497	            const list = pool.get(b.BaseSymbol);
498	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
499	        }
500	
501	        const preFreeSlots: number[] = [];      // 更新前就空著的 item（含 pre-existing ghost），供進場立即 reuse
502	        const vacatingSlots: number[] = [];     // 本輪「真消失」騰出的 item，Out 完才可用
503	        const outPromises: Promise<void>[] = [];
504	        const deferredEnter: IBountyData[] = [];
505	        const leavingSlots: number[] = [];      // BC-22 離場者：ghost vs 真消失待 Pass A 後依 hasSurvivor 決定
506	        let hasSurvivor = false;                // 任一 BC-25 持續者（全程沒播 Out/In）→ 需 ghost 撐位防 snap
507	
508	        // Pass A：逐一決定目前已綁定 item 的命運（BC-22 離場決策延後到收尾）
509	        for (let i = 0; i < count; i++) {
510	            const cur = this.m_currentBounty[i];
511	            const item = this.m_wantedPosterItems[i];
512	            if (cur === null) {
513	                if (item) preFreeSlots.push(i);              // 空格或 pre-existing ghost（皆可被新進場 reuse）
514	                continue;
515	            }
516	            const bs = cur.BaseSymbol;
517	            const list = pool.get(bs);
518	            if (list && list.length > 0) {
519	                const onBoard = visible ? visible.has(bs) : true;
520	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
521	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
522	                if (sameIdx >= 0) {
523	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
524	                    hasSurvivor = true;                      // 連續顯示者，被搬動會被察覺 → 需 ghost 撐位
525	                } else {
526	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場（有 In 動畫遮蓋，不算 survivor）
527	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
528	                    this.m_currentBounty[i] = nb;
529	                }
530	                if (list.length === 0) pool.delete(bs);
531	            } else {
532	                leavingSlots.push(i);                        // BC-22 離場：ghost/gone 待收尾決策
533	            }
534	        }
535	
536	        // Pass A 收尾：依 hasSurvivor 對離場者統一決策（ghost 撐位 vs 真消失）
537	        for (const i of leavingSlots) {
538	            const item = this.m_wantedPosterItems[i];
539	            this.m_currentBounty[i] = null;
540	            if (hasSurvivor) {
541	                // BC-G1 轉 ghost：item root 維持 active 撐住 Layout 版位，讓 BC-25 持續者不 snap
542	                if (item) {
543	                    item.ClearBaseSymbol();
544	                    outPromises.push(item.PlayOut().then(() => { item.SetContentVisible(false); }));
545	                }
546	            } else {
547	                // 真消失：無連續 survivor 需保護
548	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
549	                vacatingSlots.push(i);
550	            }
551	        }
552	
553	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
554	        const remaining: IBountyData[] = [];
555	        for (const list of pool.values()) remaining.push(...list);
556	        for (const nb of remaining) {
557	            if (preFreeSlots.length > 0) {
558	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位/pre-existing ghost → 立即 reuse 進場
559	            } else {
560	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
561	            }
562	        }
563	
564	        // 收尾：deferredEnter 等退場騰位 + postReal===0 釋放殘留 ghost（§5.3.1）
565	        // NormalizeGhosts 只釋放「active 且綁定 null」者；先 enter 後 normalize，EnterAt 已填綁定的格不受影響
566	        const needReleaseLingering = !this.m_currentBounty.some(b => b !== null);
567	        if (deferredEnter.length > 0 || needReleaseLingering) {
568	            Promise.all(outPromises).then(() => {
569	                for (const nb of deferredEnter) {
570	                    const idx = vacatingSlots.shift();
571	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
572	                    this.EnterAt(idx, nb);
573	                }
574	                if (needReleaseLingering) this.NormalizeGhosts();
575	            });
576	        }
577	    }
578	
579	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
580	    private EnterAt(index: number, data: IBountyData) {
581	        const item = this.m_wantedPosterItems[index];
582	        if (!item) return;
583	        // 先 active 再 ShowContent 再 setSkin：reuse ghost 格時 Content 仍 off，須先開可見，
584	        // 否則 inactive 狀態下 setSkin 不會重建已渲染骨架的 render data（殘留舊 skin）
585	        item.node.active = true;
586	        item.SetContentVisible(true);
587	        item.SetWantedPosterData(data);
588	        item.PlayIn();
589	        this.m_currentBounty[index] = data;
590	    }
591	
592	    /**
593	     * @ch 釋放所有 ghost（node.active 但綁定為 null）→ 還原為真消失 + Content 預設可見。
594	     * 用於：RebuildAll / HandleGameIntroComplete 起手（整批前清殘留，使 node.active 判定不被 ghost 干擾）、
595	     *       ReconcileCascade / HandlePlayMarkActive 退到全空時（避免上一輪保留的 ghost 隱形殘留 · BC-G4）。
596	     */
597	    private NormalizeGhosts() {
598	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
599	            const item = this.m_wantedPosterItems[i];
600	            if (item && item.node.active && this.m_currentBounty[i] === null) {
601	                item.node.active = false;
602	                item.SetContentVisible(true);   // 還原 Content 預設態，供下次進場
603	                item.ClearBaseSymbol();
604	            }
605	        }
606	    }
607	
608	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
609	    private EnsureCurrentBountySize() {
610	        const count = this.m_wantedPosterItems.length;
611	        if (this.m_currentBounty.length === count) return;
612	        const next: (IBountyData | null)[] = new Array(count).fill(null);
613	        const keep = Math.min(this.m_currentBounty.length, count);
614	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
615	        this.m_currentBounty = next;
616	    }
617	
618	    /**
619	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
620	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
621	     */
622	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
623	        if (baseSymbol === null || baseSymbol === undefined) return [];
624	        const result: WantedPosterItem[] = [];
625	        for (let i = 0; i < this.m_wantedPosterItems.length; i++) {
626	            const item = this.m_wantedPosterItems[i];
627	            const cur = this.m_currentBounty[i];
628	            // 用 m_currentBounty 判斷「正在顯示真懸賞令」，排除 ghost（node.active 但綁定為 null）
629	            // — ghost 的 GetBaseSymbol() 已 ClearBaseSymbol 為 MAX，但以綁定為準更直接（BC-G5）
630	            if (item && item.node.active && cur !== null && cur.BaseSymbol === baseSymbol) {
631	                result.push(item);
632	            }
633	        }
634	        return result;
635	    }
636	    /**
637	     * @ch 設置懸賞令 UI 顯示狀態
638	     * @param isShow 是否顯示
639	     */
640	    private SetWantedPosterUIShow(isShow: boolean) {
641	        if (!this.m_rootNode) {
642	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
643	            return;
644	        }
645	        this.m_rootNode.active = isShow;
646	    }
647	    //#endregion Methods
648	
649	    //#region 測試功能
650	    /**
651	     * @ch 測試按鍵處理
652	     * - 數字鍵 1：顯示 1 個懸賞令
653	     * - 數字鍵 2：顯示 2 個懸賞令
654	     * - 數字鍵 3：顯示 UI
655	     * - 數字鍵 4：隱藏 UI
656	     */
657	    private CheckTestKeyCode(event: EventKeyboard): void {
658	        if (!DEBUG) return;
659	        switch (event.keyCode) {
660	            case KeyCode.DIGIT_1:
661	                // 測試：顯示 1 個懸賞令
662	                this.SetWantedPosterData([
663	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
664	                ], true);
665	                break;
666	
667	            case KeyCode.DIGIT_2:
668	                // 測試：顯示 2 個懸賞令
669	                this.SetWantedPosterData([
670	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
671	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
672	                ], true);
673	                break;
674	
675	            case KeyCode.DIGIT_3:
676	                // 測試：顯示 UI
677	                this.SetWantedPosterUIShow(true);
678	                break;
679	
680	            case KeyCode.DIGIT_4:
681	                // 測試：隱藏 UI
682	                this.SetWantedPosterUIShow(false);
683	                break;
684	        }
685	    }
686	    //#endregion 測試功能
687	}
688	
