1	import { _decorator, Component, EventKeyboard, Input, input, KeyCode, log, warn } from 'cc';
2	import { eventManager } from 'db://astarte-framework/Managers';
3	import { BaseSpine } from './Spine/BaseSpine';
4	import { DEBUG } from 'cc/env';
5	import { GAME_EVENT } from './Game_Define';
6	import { SpriteChange } from './Common/SpriteChange';
7	import { Common } from './Common/Common';
8	const { ccclass, property } = _decorator;
9	
10	/**@ch 背景動畫名稱*/
11	const BACKGROUND_ANIM_NAME = [
12	    "MG",
13	    "FG",
14	]
15	
16	/**@ch 背景類型*/
17	export enum BackgroundType {
18	    MainGame = 0,
19	    FreeGame = 1,
20	}
21	
22	/**@ch 背景管理器事件*/
23	export const BACKGROUND_MANAGER_EVENT = {
24	    /**
25	     * @ch 更改背景
26	     * @param BackgroundType or number 背景類型 (0: 主遊戲, 1: 免費遊戲)
27	     */
28	    CHANGE_BACKGROUND: "BACKGROUND_MANAGER_CHANGE_BACKGROUND",
29	}
30	
31	@ccclass('BackgroundManager')
32	export class BackgroundManager extends Component {
33	
34	    //#region Constants
35	    /**
36	     * @ch 需要註冊的事件列表
37	     */
38	    private static readonly EVENTS_TO_REGISTER = [
39	        BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND,
40	        GAME_EVENT.DEVICE_ROTATION,
41	    ];
42	    //#endregion Constants
43	
44	    //#region Properties
45	    @property({
46	        type: [BaseSpine],
47	        tooltip: "背景 Spine"
48	    })
49	    private m_bgSpines: BaseSpine[] = [];
50	
51	    @property({
52	        type: [SpriteChange],
53	        tooltip: "背景圖片"
54	    })
55	    private m_bgSpriteChanges: SpriteChange[] = [];
56	    //#endregion Properties
57	
58	    //#region Variables
59	    /**
60	     * @ch 是否已經初始化
61	     */
62	    private m_isInitialized: boolean = false;
63	
64	    /**
65	     * @ch 當前背景類型
66	     */
67	    private m_currentBackgroundType: BackgroundType = BackgroundType.MainGame;
68	    //#endregion Variables
69	    
70	    //#region Lifecycle
71	    /**
72	     * @ch 元件載入時調用
73	     */
74	    onLoad() {
75	        this.RegisterEvent();
76	        this.RegisterKeyboardEvents();
77	    }
78	
79	    /**
80	     * @ch 元件銷毀時調用
81	     */
82	    onDestroy() {
83	        if (!this.m_isInitialized) return;
84	        this.UnregisterEvent();
85	        this.UnregisterKeyboardEvents();
86	        this.m_isInitialized = false;
87	        this.m_bgSpines = null;
88	    }
89	    //#endregion Lifecycle
90	
91	    //#region Event Management
92	    /**
93	     * @ch 註冊事件
94	     */
95	    private RegisterEvent() {
96	        BackgroundManager.EVENTS_TO_REGISTER.forEach(eventName => {
97	            eventManager.Register(eventName, this);
98	        });
99	        this.m_isInitialized = true;
100	    }
101	
102	    /**
103	     * @ch 取消註冊事件
104	     */
105	    private UnregisterEvent() {
106	        BackgroundManager.EVENTS_TO_REGISTER.forEach(eventName => {
107	            eventManager.UnRegister(eventName, this);
108	        });
109	    }
110	
111	    /**
112	     * @ch 註冊鍵盤事件（測試用）
113	     */
114	    private RegisterKeyboardEvents(): void {
115	
116	    }
117	
118	    /**
119	     * @ch 取消註冊鍵盤事件（測試用）
120	     */
121	    private UnregisterKeyboardEvents(): void {
122	        // 暫時不需要實作
123	    }
124	
125	    /**
126	     * @ch 驗證事件名稱
127	     * @param event 事件名稱
