import { _decorator, Component, EventKeyboard, Input, input, KeyCode, log, warn } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { BaseSpine } from './Spine/BaseSpine';
import { DEBUG } from 'cc/env';
import { GAME_EVENT } from './Game_Define';
import { SpriteChange } from './Common/SpriteChange';
import { Common } from './Common/Common';
const { ccclass, property } = _decorator;

/**@ch 背景動畫名稱*/
const BACKGROUND_ANIM_NAME = [
    "MG",
    "FG",
]

/**@ch 背景類型*/
export enum BackgroundType {
    MainGame = 0,
    FreeGame = 1,
}

/**@ch 背景管理器事件*/
export const BACKGROUND_MANAGER_EVENT = {
    /**
     * @ch 更改背景
     * @param BackgroundType or number 背景類型 (0: 主遊戲, 1: 免費遊戲)
     */
    CHANGE_BACKGROUND: "BACKGROUND_MANAGER_CHANGE_BACKGROUND",
}

@ccclass('BackgroundManager')
export class BackgroundManager extends Component {

    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND,
        GAME_EVENT.DEVICE_ROTATION,
    ];
    //#endregion Constants

    //#region Properties
    @property({
        type: [BaseSpine],
        tooltip: "背景 Spine"
    })
    private m_bgSpines: BaseSpine[] = [];

    @property({
        type: [SpriteChange],
        tooltip: "背景圖片"
    })
    private m_bgSpriteChanges: SpriteChange[] = [];
    //#endregion Properties

    //#region Variables
    /**
     * @ch 是否已經初始化
     */
    private m_isInitialized: boolean = false;

    /**
     * @ch 當前背景類型
     */
    private m_currentBackgroundType: BackgroundType = BackgroundType.MainGame;
    //#endregion Variables

    //#region Lifecycle
    /**
     * @ch 元件載入時調用
     */
    onLoad() {
        this.RegisterEvent();
        this.RegisterKeyboardEvents();
    }

    /**
     * @ch 元件銷毀時調用
     */
    onDestroy() {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.UnregisterKeyboardEvents();
        this.m_isInitialized = false;
        this.m_bgSpines = null;
    }
    //#endregion Lifecycle

    //#region Event Management
    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        BackgroundManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
        this.m_isInitialized = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        BackgroundManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
    }

    /**
     * @ch 註冊鍵盤事件（測試用）
     */
    private RegisterKeyboardEvents(): void {

    }

    /**
     * @ch 取消註冊鍵盤事件（測試用）
     */
    private UnregisterKeyboardEvents(): void {
        // 暫時不需要實作
    }

    /**
     * @ch 驗證事件名稱
     * @param event 事件名稱
     * @returns 是否有效
     */
    private ValidateEventName(event: string): boolean {
        if (!event || typeof event !== 'string') {
            warn('[BackgroundManager] OnEvent: 無效的事件名稱', event);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 CHANGE_BACKGROUND 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateChangeBackgroundArgs(args: any[]): boolean {
        if (args.length === 0 || typeof args[0] !== 'number') {
            warn('[BackgroundManager] CHANGE_BACKGROUND: 無效的背景類型參數', args[0]);
            return false;
        }
        const type = args[0];
        if (type < BackgroundType.MainGame || type > BackgroundType.FreeGame) {
            warn('[BackgroundManager] CHANGE_BACKGROUND: 背景類型超出範圍', type);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證背景 Spine 是否存在
     * @param type 背景類型
     * @returns 是否有效
     */
    private ValidateBackgroundSpine(type: BackgroundType): boolean {

        if (type < BackgroundType.MainGame || type > BackgroundType.FreeGame) {
            warn('[BackgroundManager] 背景類型超出範圍', type);
            return false;
        }
        return true;
    }

    /**
     * @ch 事件回調
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]) {
        if (!this.ValidateEventName(event)) {
            return;
        }

        switch (event) {
            case BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND:
                if (this.ValidateChangeBackgroundArgs(args)) {
                    this.ChangeBackground(args[0]);
                }
                break;

            case GAME_EVENT.DEVICE_ROTATION:
                this.UpdateBackground();
                break;

            default:
                warn('[BackgroundManager] OnEvent: 未知的事件', event);
        }
    }
    //#endregion Event Management

    //#region Methods
    /**
     * @ch 更改背景
     * @param type 背景類型
     * @param isForceChange 是否強制更改
     */
    private async ChangeBackground(type: BackgroundType, isForceChange: boolean = false) {
        if (!this.ValidateBackgroundSpine(type)) {
            return;
        }

        // 更新當前背景類型
        if (this.m_currentBackgroundType === type && !isForceChange) {
            return;
        }
        this.m_currentBackgroundType = type;

        // 更改背景圖片
        this.ChangeBackgroundSprite(type);

        // 獲取動畫名稱
        const animationName = BACKGROUND_ANIM_NAME[type];
        const isLandscape = Common.GetGameView().IsLandscape;
        for (const bgSpine of this.m_bgSpines) {
            if (!bgSpine) continue;

            // 如果動畫名稱為空或不存在，隱藏背景節點
            if (!animationName || animationName === "") {
                bgSpine.SetSpineNodeActivity(false);
                continue;
            }

            // 如果是主遊戲的直版就不播放動畫


            // 顯示背景節點並播放動畫
            bgSpine.SetSpineNodeActivity(true);
            bgSpine.PlayAnimation(animationName, bgSpine.Spine, true);
        }
    }

    /**
     * @ch 更新背景
     */
    private UpdateBackground() {
        const currentBackgroundType = this.m_currentBackgroundType;
        this.ChangeBackground(currentBackgroundType, true);
        this.ChangeBackgroundSprite(currentBackgroundType);
    }

    /**
     * @ch 取得當前背景類型
     * @returns 當前背景類型
     */
    public GetCurrentBackgroundType(): BackgroundType {
        return this.m_currentBackgroundType;
    }

    /**
     * @ch 更改背景圖片
     * @param type 背景類型
     */
    private ChangeBackgroundSprite(type: BackgroundType) {
        if (!this.m_bgSpriteChanges || this.m_bgSpriteChanges.length === 0) return;

        this.m_bgSpriteChanges.forEach(spriteChange => {
            spriteChange.ChangeSpriteByIndex(type);
        });
    }
    //#endregion Methods

    //#region 測試功能
    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode() {
        if (!DEBUG) return;
        // return;
        input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {

            switch (event.keyCode) {
            }
        });
    }
    //#endregion 測試功能
}

