import { _decorator, Component, log, warn } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { BaseSpine } from './Spine/BaseSpine';

const { ccclass, property } = _decorator;

/**
 * @ch 操作目標群組
 * CHARACTER → 角色 Spine 清單
 * CANNON    → 大砲 Spine 清單
 * ALL       → 兩個清單一起操作
 */
export enum BS_SPINE_TYPE
{
    CHARACTER = 'character',
    CANNON    = 'cannon',
}

/**
 * @ch BSSpineCtrl 事件名稱列舉
 *
 * Dispatch 格式：
 *   eventManager.Dispatch(BS_SPINE_CTRL_EVENT.XXX, label, spineType, ...args)
 *
 *   label     → 對應 Inspector Label 欄位
 *   spineType → BS_SPINE_TYPE 列舉值
 */
export enum BS_SPINE_CTRL_EVENT
{
    /** args: (label, spineType, animName, isLoop?, timeScale?) */
    PLAY               = 'BSSpineCtrl_PLAY',
    /** args: (label, isLandscape) */
    SET_IS_LANDSCAPE   = 'BSSpineCtrl_SET_IS_LANDSCAPE',
    /** args: (label, spineType) */
    STOP               = 'BSSpineCtrl_STOP',
    /** args: (label, spineType) */
    PAUSE              = 'BSSpineCtrl_PAUSE',
    /** args: (label, spineType) */
    RESUME             = 'BSSpineCtrl_RESUME',
    /** args: (label, spineType, skinName) */
    SET_SKIN           = 'BSSpineCtrl_SET_SKIN',
    /** args: (label, spineType, v: boolean) */
    SET_NODE_ACTIVITY  = 'BSSpineCtrl_SET_NODE_ACTIVITY',
    /** args: (label, spineType, v: boolean) */
    SET_SPINE_ACTIVITY = 'BSSpineCtrl_SET_SPINE_ACTIVITY',
    /** args: (label, spineType, trackTime: number) — 跳到指定時間繼續播 */
    SKIP_TO_TIME       = 'BSSpineCtrl_SKIP_TO_TIME',
}

export const CHARACTER_ANIM_NAME = {
    Aim: "Aim", // 1代規格
    Aim_Idle: "Aim_Idle",
    Close: "Close",
    Idle: "Idle",
    Idle2: "Idle2", // Idle 時偶爾隨機播放
    NearWin: "NearWin",
    Symbol_Remove: "Symbol_Remove",
    Win0: "Win0",
    Win1: "Win1",
    Win2: "Win2",
};

export const CANNON_ANIM_NAME = {
    Aim: "Aim",
    Collect_1: "Collect_1",
    Collect_2: "Collect_2",
    Collect_3: "Collect_3",
    NearWin: "NearWin",
    Stop: "Stop",
    Symbol_Remove: "Symbol_Remove",
    Win1: "Win1",
    Win2: "Win2",
};

/**
 * @ch BSSpineCtrl — 角色 / 大砲 Spine 控制器
 *
 * Inspector 上分別設定「角色 Spine」與「大砲 Spine」，
 * 透過 eventManager.Dispatch 搭配 BS_SPINE_TYPE 指定目標，
 * 可遠端播放、停止、暫停、恢復、換膚或切換節點顯示。
 */
@ccclass('BSSpineCtrl')
export class BSSpineCtrl extends Component
{
    //#region Inspector Properties



    @property( {
        type: BaseSpine,
        displayName: '橫版角色 Spine',
        tooltip: '橫版角色相關的 BaseSpine'
    } )
    private m_characterSpine_H: BaseSpine = null;
    @property( {
        type: BaseSpine,
        displayName: '直版角色 Spine',
        tooltip: '直版角色相關的 BaseSpine'
    } )
    private m_characterSpine_S: BaseSpine = null;

    @property( {
        type: BaseSpine,
        displayName: '橫版大砲 Spine',
        tooltip: '橫版大砲相關的 BaseSpine'
    } )
    private m_cannonSpine_H: BaseSpine = null;

    @property( {
        type: BaseSpine,
        displayName: '直版大砲 Spine',
        tooltip: '直版大砲相關的 BaseSpine'
    } )
    private m_cannonSpine_S: BaseSpine = null;

    /** Spine 用 */
    private m_isLandscape: boolean = false;

    //#endregion

    //#region Lifecycle

    onLoad ()
    {
        this.RegisterEvents();
    }

    onDestroy ()
    {
        this.UnregisterEvents();
    }

    //#endregion

    //#region Event Registration

    private static readonly EVENTS: BS_SPINE_CTRL_EVENT[] = [
        BS_SPINE_CTRL_EVENT.PLAY,
        BS_SPINE_CTRL_EVENT.SET_IS_LANDSCAPE,
        BS_SPINE_CTRL_EVENT.STOP,
        BS_SPINE_CTRL_EVENT.PAUSE,
        BS_SPINE_CTRL_EVENT.RESUME,
        BS_SPINE_CTRL_EVENT.SET_SKIN,
        BS_SPINE_CTRL_EVENT.SET_NODE_ACTIVITY,
        BS_SPINE_CTRL_EVENT.SET_SPINE_ACTIVITY,
        BS_SPINE_CTRL_EVENT.SKIP_TO_TIME,
    ];

    private RegisterEvents ()
    {
        BSSpineCtrl.EVENTS.forEach( evt => eventManager.Register( evt, this ) );
    }

    private UnregisterEvents ()
    {
        BSSpineCtrl.EVENTS.forEach( evt => eventManager.UnRegister( evt, this ) );
    }

    //#endregion

    //#region Event Handler

    OnEvent ( event: string, ...args: any[] )
    {
        const spineType: BS_SPINE_TYPE = args[0];



        switch ( event )
        {
            case BS_SPINE_CTRL_EVENT.PLAY:
            {
                const animName: string  = args[1];
                const isLoop: boolean   = args[2] ?? false;
                const endCB: () => void = args[3] ?? null;
                const eventCB: (eventName: string) => void = args[4] ?? null;
                this.Play( spineType, animName, isLoop, endCB, eventCB );
                break;
            }
            case BS_SPINE_CTRL_EVENT.STOP:
            {
                this.StopAll( spineType );
                break;
            }
            case BS_SPINE_CTRL_EVENT.PAUSE:
            {
                this.PauseAll( spineType );
                break;
            }
            case BS_SPINE_CTRL_EVENT.RESUME:
            {
                this.ResumeAll( spineType );
                break;
            }
            case BS_SPINE_CTRL_EVENT.SET_SKIN:
            {
                const skinName: string = args[1];
                this.SetSkin( spineType, skinName );
                break;
            }
            case BS_SPINE_CTRL_EVENT.SET_NODE_ACTIVITY:
            {
                const v: boolean = args[1];
                this.SetNodeActivity( spineType, v );
                break;
            }
            case BS_SPINE_CTRL_EVENT.SET_SPINE_ACTIVITY:
            {
                const v: boolean = args[1];
                this.SetSpineActivity( spineType, v );
                break;
            }
            case BS_SPINE_CTRL_EVENT.SET_IS_LANDSCAPE:
            {
                const isLandscape: boolean = args[0];
                this.m_isLandscape = isLandscape;
                break;
            }
            case BS_SPINE_CTRL_EVENT.SKIP_TO_TIME:
            {
                const trackTime: number = args[1];
                this.SkipToTime( spineType, trackTime );
                break;
            }
        }
    }

    //#endregion

    //#region Control Methods

    /**
     * @ch 播放動畫
     * @param spineType 目標群組
     * @param animName 動畫名稱
     * @param isLoop 是否循環
     * @param timeScale 播放速度，undefined 則使用 BaseSpine 預設值
     */
    async Play (
        spineType: BS_SPINE_TYPE,
        animName: string,
        isLoop: boolean = false,
        endCB?: () => void,
        eventCB?: (eventName: string) => void
    )
    {
        this.DoTargetAction( spineType, async spine =>
        {
            if ( spineType === BS_SPINE_TYPE.CANNON )
            {
                //砲台動畫需要加上前綴(橫直版)
                if(this.m_isLandscape)
                {
                    animName = "H_" + animName;
                }
                else
                {
                    animName = "S_" + animName;
                }
                log({animName: animName});
            }
            else
            {
                //角色動畫不循環
                isLoop = false;
            }


            await spine.PlayAnimation( animName, spine.Spine, isLoop, undefined, eventCB );
            endCB?.();


            //角色動畫後須後處理其他動作
            if(spineType === BS_SPINE_TYPE.CHARACTER)
            {
                switch ( animName )
                {
                    case CHARACTER_ANIM_NAME.Idle:
                    case CHARACTER_ANIM_NAME.NearWin:
                        spine.PlayAnimation( animName, spine.Spine, true );
                        break;

                    case CHARACTER_ANIM_NAME.Aim:

                        break;

                    case CHARACTER_ANIM_NAME.Symbol_Remove:
                    case CHARACTER_ANIM_NAME.Win0:
                    case CHARACTER_ANIM_NAME.Win1:
                    case CHARACTER_ANIM_NAME.Win2:
                        spine.PlayAnimation( CHARACTER_ANIM_NAME.Idle, spine.Spine, true );
                        break;

                    default:
                        break;
                }
            }
        } );


    }

    /**
     * @ch 停止動畫
     * @param spineType 目標群組
     */
    StopAll ( spineType: BS_SPINE_TYPE )
    {
        this.DoTargetAction( spineType, spine => spine.Stop() );
    }

    /**
     * @ch 暫停動畫
     * @param spineType 目標群組
     */
    PauseAll ( spineType: BS_SPINE_TYPE )
    {
        this.DoTargetAction( spineType, spine => spine.Pause() );
    }

    /**
     * @ch 恢復動畫
     * @param spineType 目標群組
     */
    ResumeAll ( spineType: BS_SPINE_TYPE )
    {
        this.DoTargetAction( spineType, spine => spine.Resume() );
    }

    /**
     * @ch 跳到指定時間繼續播放（不重新 setAnimation，直接改 trackTime）
     * @param spineType 目標群組
     * @param trackTime 要跳到的秒數
     */
    SkipToTime ( spineType: BS_SPINE_TYPE, trackTime: number )
    {
        this.DoTargetAction( spineType, spine =>
        {
            const sk = spine.Spine;
            if ( !sk ) return;
            const track = sk.getCurrent( 0 );
            if ( track ) track.trackTime = trackTime;
        } );
    }

    /**
     * @ch 設定皮膚
     * @param spineType 目標群組
     * @param skinName 皮膚名稱
     */
    SetSkin ( spineType: BS_SPINE_TYPE, skinName: string )
    {
        this.DoTargetAction( spineType, spine => spine.SetSkin( skinName ) );
    }

    /**
     * @ch 設定節點顯示狀態
     * @param spineType 目標群組
     * @param v 是否顯示
     */
    SetNodeActivity ( spineType: BS_SPINE_TYPE, v: boolean )
    {
        this.DoTargetAction( spineType, spine => spine.SetNodeActivity( v ) );
    }

    /**
     * @ch 設定 Spine 子節點顯示狀態
     * @param spineType 目標群組
     * @param v 是否顯示
     */
    SetSpineActivity ( spineType: BS_SPINE_TYPE, v: boolean )
    {
        this.DoTargetAction( spineType, spine => spine.SetSpineNodeActivity( v ) );
    }

    //#endregion

    //#region Helpers

    private GetTarget ( spineType: BS_SPINE_TYPE ): BaseSpine
    {
        switch ( spineType )
        {
            case BS_SPINE_TYPE.CHARACTER: 
            {
                if(this.m_isLandscape)
                {
                    return this.m_characterSpine_H;
                }
                else
                {
                    return this.m_characterSpine_S;
                }

            }
            break;
            case BS_SPINE_TYPE.CANNON:   
            {
                if(this.m_isLandscape)
                {
                    return this.m_cannonSpine_H;
                }
                else
                {
                    return this.m_cannonSpine_S;
                }
            }
            break;
        }
    }

    private DoTargetAction ( spineType: BS_SPINE_TYPE, action: ( spine: BaseSpine ) => void )
    {
        const target = this.GetTarget( spineType );

        if ( target )
        {
            action( target );
        }
        else
        {
            warn( `[BSSpineCtrl][${spineType}] Spine 未設定` );
        }

    }

    //#endregion
}

