68	        FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND,
69	        FREE_GAME_UI_MANAGER_EVENT.COUNT_UP_TOTAL_ROUND,
70	        FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES,
