72	        FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT,
73	        FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK,
74	        FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK,
75	    ];
76	    //#endregion Constants
77	
78	    //#region Properties
79	    @property({
80	        type: Label,
81	        tooltip: "回合數資訊"
82	    })
83	    private m_roundInfoLabel: Label = null;
84	
85	    @property({
86	        type: [Sprite],
87	        tooltip: "Feature Icon Sprite（依序 0=Target, 1=Bounty/Wanted, 2=Scatter）"
88	    })
89	    private m_featureIconSprites: Sprite[] = [];
