145	    {
146	        if (nowRound < 0) {
147	            nowRound = 0;
148	            warn("SetRemainingRound: remainingRound is less than 0, set to 0");
149	        }
150	        this.m_nowRound = nowRound;
151	        if (this.m_roundInfoLabel) {
152	            this.m_roundInfoLabel.string = this.m_nowRound.toString() + " / " + totalRound.toString();
153	        }
154	    }
