156	    /**
157	     * @ch 總回合數 count up 演出：右邊總回合數從 fromTotal 逐步遞增到 toTotal，
158	     *     每跳一個整數播一次計數音效。左邊目前回合數（nowRound）維持不變。
159	     */
160	    private CountUpTotalRound(nowRound: number, fromTotal: number, toTotal: number, duration: number) : void
161	    {
162	        if (nowRound < 0) {
163	            nowRound = 0;
164	            warn("CountUpTotalRound: nowRound is less than 0, set to 0");
165	        }
166	        this.m_nowRound = nowRound;
167	
168	        if (!this.m_roundInfoLabel) return;
169	
170	        // 非遞增（無加局或資料異常）：直接定值，不做 count 演出
171	        if (toTotal <= fromTotal) {
172	            this.m_roundInfoLabel.string = nowRound.toString() + " / " + toTotal.toString();
173	            return;
174	        }
175	
176	        let lastShown = Math.round(fromTotal);
177	        const proxy = { v: fromTotal };
178	        Tween.stopAllByTarget(proxy);
179	        tween(proxy)
180	            .to(duration, { v: toTotal }, {
181	                onUpdate: () => {
182	                    const cur = Math.round(proxy.v);
183	                    this.m_roundInfoLabel.string = nowRound.toString() + " / " + cur.toString();
184	                    if (cur > lastShown) {
185	                        lastShown = cur;
186	                        AudioManager.Play(AudioManager.AudioClips.MG_SFX_Cash1);
187	                    }
188	                }
189	            })
190	            .call(() => {
191	                // 定在精確目標值，避免浮點誤差殘留
192	                this.m_roundInfoLabel.string = nowRound.toString() + " / " + toTotal.toString();
193	            })
194	            .start();
195	    }
196	
197	    /**
198	     * @ch 初始化
199	     */
200	    private Init() : void
201	    {
202	        this.SetRoundInfo(0,0);
203	        this.ClearActiveFeatures();
204	    }
