240	    {
241	        if (!this.m_cannonDownNode || !this.m_featureIconSprites) return;
242	        this.m_featureIconOriginalParents = [];
243	        for (const sprite of this.m_featureIconSprites) {
244	            if (!sprite) { this.m_featureIconOriginalParents.push(null); continue; }
245	            this.m_featureIconOriginalParents.push(sprite.node.parent);
246	            sprite.node.setParent(this.m_cannonDownNode, true);
247	            sprite.node.active = true;
248	        }
249	    }
