253	     */
254	    private ShowIconsFromBlackMask() : void
255	    {
256	        if (!this.m_featureIconSprites) return;
257	        for (let i = 0; i < this.m_featureIconSprites.length; i++) {
258	            const sprite = this.m_featureIconSprites[i];
259	            if (!sprite) continue;
260	            const originalParent = this.m_featureIconOriginalParents[i];
261	            if (originalParent) sprite.node.setParent(originalParent, true);
262	            sprite.node.active = true;
263	        }
264	        this.m_featureIconOriginalParents = [];
265	    }
266	
267	    /**
268	     * @ch Feature icon 放大彈回原大小特效
269	     */
270	    private PopScaleEffect() : void
271	    {
272	        if (!this.m_featureIconSprites) return;
273	        for (const sprite of this.m_featureIconSprites) {
274	            if (!sprite || !sprite.node.active) continue;
275	            sprite.node.setScale(1, 1, 1);
276	            tween(sprite.node)
277	                .to(0.15, { scale: FreeGameUIManager.SCALE_BOUNCE })
278	                .to(0.15, { scale: FreeGameUIManager.SCALE_NORMAL })
279	                .start();
280	        }
281	    }
282	
283	    
284	    /**
285	     * @ch 註冊事件
286	     */
287	    private RegisterEvent() : void
288	    {
289	        FreeGameUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
290	            eventManager.Register(eventName, this);
291	        });
292	    }
293	
294	    /**
295	     * @ch 取消註冊事件
296	     */
297	    private UnregisterEvent() : void
298	    {
299	        FreeGameUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
300	            eventManager.UnRegister(eventName, this);
301	        });
302	    }
303	
304	    /**
305	     * @ch 驗證事件名稱
306	     * @param event 事件名稱
307	     * @returns 是否有效
308	     */
309	    private ValidateEventName(event: string) : boolean
310	    {
311	        if (!event || typeof event !== 'string') {
312	            warn("[FreeGameUIManager] OnEvent: 無效的事件名稱", event);
313	            return false;
314	        }
315	        return true;
316	    }
317	
318	    /**
319	     * @ch 驗證 SET_REMAINING_ROUND 事件參數
320	     * @param args 事件參數
321	     * @returns 是否有效
322	     */
323	    private ValidateSetRemainingRoundArgs(args: any[]) : boolean
324	    {
325	        if (args[0] === undefined || typeof args[0] !== 'number') {
326	            warn("[FreeGameUIManager] SET_REMAINING_ROUND: 無效的 remainingRound 參數", args[0]);
327	            return false;
328	        }
329	        return true;
330	    }
331	
332	    
333	
334	    /**
335	     * @ch 事件處理
336	     * @param event 事件名稱
337	     * @param args 事件參數
338	     */
339	    OnEvent(event: string, ...args: any[]) : void
340	    {
341	        if (!this.ValidateEventName(event)) {
342	            return;
343	        }
344	
345	        switch (event) {
346	            case FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND:
347	                if (this.ValidateSetRemainingRoundArgs(args)) {
348	                    this.SetRoundInfo(args[0],args[1]);
349	                }
350	                break;
351	
352	            case FREE_GAME_UI_MANAGER_EVENT.COUNT_UP_TOTAL_ROUND:
353	                if (typeof args[0] === 'number' && typeof args[1] === 'number' && typeof args[2] === 'number') {
354	                    const dur = typeof args[3] === 'number' ? args[3] : COUNT_UP_DURATION;
355	                    this.CountUpTotalRound(args[0], args[1], args[2], dur);
356	                } else {
357	                    warn("[FreeGameUIManager] COUNT_UP_TOTAL_ROUND: 無效的參數", args);
358	                }
359	                break;
360	
361	            case FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES:
362	                if (args[0] && Array.isArray(args[0])) {
363	                    this.SetActiveFeatures(args[0]);
364	                }
365	                break;
366	
367	            case FREE_GAME_UI_MANAGER_EVENT.CLEAR_ACTIVE_FEATURES:
368	                this.ClearActiveFeatures();
369	                break;
370	
371	            case FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT:
372	                this.PopScaleEffect();
373	                break;
374	
375	            case FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK:
376	                this.HideIconsForBlackMask();
377	                break;
378	
379	            case FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK:
380	                this.ShowIconsFromBlackMask();
381	                break;
382	
383	            default:
384	                warn("[FreeGameUIManager] OnEvent: 未知的事件", event);
385	        }
386	    }
387	    //#endregion Methods
388	
389	    //#region 測試功能
390	    /**
391	     * @ch 檢查測試按鍵
392	     */
393	    private CheckTestKeyCode() {
394	        if (!DEBUG) return;
395	        return;
396	        input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {
397	            log("CheckTestKeyCode", event.keyCode);
398	            switch (event.keyCode) {
