import { _decorator, Component, EventKeyboard, Input, input, KeyCode, Label, log, warn, Node, Sprite, SpriteFrame, tween, Tween, UIOpacity, Vec3 } from 'cc';
import { getUIOpacity } from '../Common/NodeProperty';
