import { DEBUG } from 'cc/env';
const { ccclass, property } = _decorator;

/** @ch 總回合數 count up 預設秒數 */
const COUNT_UP_DURATION = 1.2;

export const FREE_GAME_UI_MANAGER_EVENT = {
    /**
     * @ch 設置剩餘回合數
     * @param remainingRound 剩餘回合數
     */
    SET_REMAINING_ROUND: "FREE_GAME_UI_MANAGER_SET_REMAINING_ROUND",

    /**
     * @ch 總回合數 count up 演出（加手數落點後遞增）
     * @param nowRound 目前回合數（不變）
     * @param fromTotal count 起始總回合數
     * @param toTotal count 目標總回合數
     * @param duration 演出秒數
     */
    COUNT_UP_TOTAL_ROUND: "FREE_GAME_UI_MANAGER_COUNT_UP_TOTAL_ROUND",

    /**
     * @ch 設置 FG 期間 active 的 feature icon
     * @param freePickItems number[] — FGRouletteOption 陣列（0=TargetExpand, 1=BountyDouble, 2=ScatterBoost）
     */
    SET_ACTIVE_FEATURES: "FREE_GAME_UI_MANAGER_SET_ACTIVE_FEATURES",

    /**
     * @ch 清除 active feature icon
     */
    CLEAR_ACTIVE_FEATURES: "FREE_GAME_UI_MANAGER_CLEAR_ACTIVE_FEATURES",

    /**
     * @ch Feature icon 放大彈回特效
     */
    POP_SCALE_EFFECT: "FREE_GAME_UI_MANAGER_POP_SCALE_EFFECT",

    /**
     * @ch 黑章演出開始：把 feature icon 移到 Cannon_Down 節點下並關閉
     */
    HIDE_ICONS_FOR_BLACK_MASK: "FREE_GAME_UI_MANAGER_HIDE_ICONS_FOR_BLACK_MASK",

    /**
     * @ch 黑章演出結束：恢復 feature icon 原始父節點並開啟
     */
    SHOW_ICONS_FROM_BLACK_MASK: "FREE_GAME_UI_MANAGER_SHOW_ICONS_FROM_BLACK_MASK",
}

@ccclass('FreeGameUIManager')
export class FreeGameUIManager extends Component {
    //#region Constants
    /** @ch GC 優化：tween scale 常量 */
    private static readonly SCALE_BOUNCE = new Vec3(1.3, 1.3, 1);
    private static readonly SCALE_NORMAL = new Vec3(1, 1, 1);

    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND,
        FREE_GAME_UI_MANAGER_EVENT.COUNT_UP_TOTAL_ROUND,
        FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES,
        FREE_GAME_UI_MANAGER_EVENT.CLEAR_ACTIVE_FEATURES,
        FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT,
        FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK,
        FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK,
    ];
    //#endregion Constants

    //#region Properties
    @property({
        type: Label,
        tooltip: "回合數資訊"
    })
    private m_roundInfoLabel: Label = null;

    @property({
        type: [Sprite],
        tooltip: "Feature Icon Sprite（依序 0=Target, 1=Bounty/Wanted, 2=Scatter）"
    })
    private m_featureIconSprites: Sprite[] = [];

    @property({
        type: [SpriteFrame],
        tooltip: "Feature Icon 有中版（依序 0=Target_G, 1=Wanted_D, 2=Scatter_G）"
    })
    private m_featureActiveFrames: SpriteFrame[] = [];

    @property({
        type: [SpriteFrame],
        tooltip: "Feature Icon 沒中版（依序 0=Target_R, 1=Wanted_S, 2=Scatter_S）"
    })
    private m_featureInactiveFrames: SpriteFrame[] = [];

    @property({
        type: Node,
        tooltip: "黑章演出期間 feature icon 暫存的父節點（Cannon_Down）"
    })
    private m_cannonDownNode: Node = null;
    //#endregion Properties

    //#region Variables
    /**@ch 目前回合數 */
    private m_nowRound: number = 0;

    /** @ch 黑章演出前 feature icon 的原始父節點 */
    private m_featureIconOriginalParents: Node[] = [];

    // /**@ch 進度節點的透明度 */
    // private m_progressNodesUIOpacitys: UIOpacity[] = [];

    /**@ch 動畫持續時間 */
    private m_animDuration: number = 0.3;
    //#endregion Variables

    //#region Lifecycle
    onLoad() : void
    {
        this.RegisterEvent();
        this.Init();

    }

    onDestroy() : void
    {
        this.UnregisterEvent();

    }
    //#endregion Lifecycle

    //#region Methods
    /**
     * @ch 設置剩餘回合數
     * @param nowRound 剩餘回合數
     */
    private SetRoundInfo(nowRound: number,totalRound: number)
    {
        if (nowRound < 0) {
            nowRound = 0;
            warn("SetRemainingRound: remainingRound is less than 0, set to 0");
        }
        this.m_nowRound = nowRound;
        if (this.m_roundInfoLabel) {
            this.m_roundInfoLabel.string = this.m_nowRound.toString() + " / " + totalRound.toString();
        }
    }

    /**
     * @ch 總回合數 count up 演出：右邊總回合數從 fromTotal 逐步遞增到 toTotal，
     *     每跳一個整數播一次計數音效。左邊目前回合數（nowRound）維持不變。
     */
    private CountUpTotalRound(nowRound: number, fromTotal: number, toTotal: number, duration: number) : void
    {
        if (nowRound < 0) {
            nowRound = 0;
            warn("CountUpTotalRound: nowRound is less than 0, set to 0");
        }
        this.m_nowRound = nowRound;

        if (!this.m_roundInfoLabel) return;

        // 非遞增（無加局或資料異常）：直接定值，不做 count 演出
        if (toTotal <= fromTotal) {
            this.m_roundInfoLabel.string = nowRound.toString() + " / " + toTotal.toString();
            return;
        }

        let lastShown = Math.round(fromTotal);
        const proxy = { v: fromTotal };
        Tween.stopAllByTarget(proxy);
        tween(proxy)
            .to(duration, { v: toTotal }, {
                onUpdate: () => {
                    const cur = Math.round(proxy.v);
                    this.m_roundInfoLabel.string = nowRound.toString() + " / " + cur.toString();
                    if (cur > lastShown) {
                        lastShown = cur;
                        AudioManager.Play(AudioManager.AudioClips.MG_SFX_Cash1);
                    }
                }
            })
            .call(() => {
                // 定在精確目標值，避免浮點誤差殘留
                this.m_roundInfoLabel.string = nowRound.toString() + " / " + toTotal.toString();
            })
            .start();
    }

    /**
     * @ch 初始化
     */
    private Init() : void
    {
        this.SetRoundInfo(0,0);
        this.ClearActiveFeatures();
    }

    /**
     * @ch 顯示 active feature icon（FG 期間三個都顯示，有中亮版/沒中暗版）
     * @param freePickItems FGRouletteOption 陣列（0=Target, 1=Bounty, 2=Scatter）
     */
    private SetActiveFeatures(freePickItems: number[]) : void
    {
        if (!this.m_featureIconSprites || this.m_featureIconSprites.length === 0) return;

        for (let i = 0; i < this.m_featureIconSprites.length; i++) {
            const sprite = this.m_featureIconSprites[i];
            if (!sprite) continue;
            sprite.node.active = true;
            const isActive = freePickItems.indexOf(i) >= 0;
            sprite.spriteFrame = isActive
                ? this.m_featureActiveFrames[i]
                : this.m_featureInactiveFrames[i];
        }
    }

    /**
     * @ch 清除 active feature icon（隱藏所有）
     */
    private ClearActiveFeatures() : void
    {
        if (!this.m_featureIconSprites) return;
        for (const sprite of this.m_featureIconSprites) {
            if (sprite) sprite.node.active = false;
        }
    }

    /**
     * @ch 黑章演出開始：把所有 feature icon 移到 Cannon_Down 節點下並隱藏
     */
    private HideIconsForBlackMask() : void
    {
        if (!this.m_cannonDownNode || !this.m_featureIconSprites) return;
        this.m_featureIconOriginalParents = [];
        for (const sprite of this.m_featureIconSprites) {
            if (!sprite) { this.m_featureIconOriginalParents.push(null); continue; }
            this.m_featureIconOriginalParents.push(sprite.node.parent);
            sprite.node.setParent(this.m_cannonDownNode, true);
            sprite.node.active = true;
        }
    }

    /**
     * @ch 黑章演出結束：恢復 feature icon 原始父節點並顯示（僅恢復原本 active 的節點）
     */
    private ShowIconsFromBlackMask() : void
    {
        if (!this.m_featureIconSprites) return;
        for (let i = 0; i < this.m_featureIconSprites.length; i++) {
            const sprite = this.m_featureIconSprites[i];
            if (!sprite) continue;
            const originalParent = this.m_featureIconOriginalParents[i];
            if (originalParent) sprite.node.setParent(originalParent, true);
            sprite.node.active = true;
        }
        this.m_featureIconOriginalParents = [];
    }

    /**
     * @ch Feature icon 放大彈回原大小特效
     */
    private PopScaleEffect() : void
    {
        if (!this.m_featureIconSprites) return;
        for (const sprite of this.m_featureIconSprites) {
            if (!sprite || !sprite.node.active) continue;
            sprite.node.setScale(1, 1, 1);
            tween(sprite.node)
                .to(0.15, { scale: FreeGameUIManager.SCALE_BOUNCE })
                .to(0.15, { scale: FreeGameUIManager.SCALE_NORMAL })
                .start();
        }
    }


    /**
     * @ch 註冊事件
     */
    private RegisterEvent() : void
    {
        FreeGameUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() : void
    {
        FreeGameUIManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });
    }

    /**
     * @ch 驗證事件名稱
     * @param event 事件名稱
     * @returns 是否有效
     */
    private ValidateEventName(event: string) : boolean
    {
        if (!event || typeof event !== 'string') {
            warn("[FreeGameUIManager] OnEvent: 無效的事件名稱", event);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SET_REMAINING_ROUND 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateSetRemainingRoundArgs(args: any[]) : boolean
    {
        if (args[0] === undefined || typeof args[0] !== 'number') {
            warn("[FreeGameUIManager] SET_REMAINING_ROUND: 無效的 remainingRound 參數", args[0]);
            return false;
        }
        return true;
    }



    /**
     * @ch 事件處理
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent(event: string, ...args: any[]) : void
    {
        if (!this.ValidateEventName(event)) {
            return;
        }

        switch (event) {
            case FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND:
                if (this.ValidateSetRemainingRoundArgs(args)) {
                    this.SetRoundInfo(args[0],args[1]);
                }
                break;

            case FREE_GAME_UI_MANAGER_EVENT.COUNT_UP_TOTAL_ROUND:
                if (typeof args[0] === 'number' && typeof args[1] === 'number' && typeof args[2] === 'number') {
                    const dur = typeof args[3] === 'number' ? args[3] : COUNT_UP_DURATION;
                    this.CountUpTotalRound(args[0], args[1], args[2], dur);
                } else {
                    warn("[FreeGameUIManager] COUNT_UP_TOTAL_ROUND: 無效的參數", args);
                }
                break;

            case FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES:
                if (args[0] && Array.isArray(args[0])) {
                    this.SetActiveFeatures(args[0]);
                }
                break;

            case FREE_GAME_UI_MANAGER_EVENT.CLEAR_ACTIVE_FEATURES:
                this.ClearActiveFeatures();
                break;

            case FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT:
                this.PopScaleEffect();
                break;

            case FREE_GAME_UI_MANAGER_EVENT.HIDE_ICONS_FOR_BLACK_MASK:
                this.HideIconsForBlackMask();
                break;

            case FREE_GAME_UI_MANAGER_EVENT.SHOW_ICONS_FROM_BLACK_MASK:
                this.ShowIconsFromBlackMask();
                break;

            default:
                warn("[FreeGameUIManager] OnEvent: 未知的事件", event);
        }
    }
    //#endregion Methods

    //#region 測試功能
    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode() {
        if (!DEBUG) return;
        return;
        input.on(Input.EventType.KEY_DOWN, (event: EventKeyboard) => {
            log("CheckTestKeyCode", event.keyCode);
            switch (event.keyCode) {

            }
        });
    }
    //#endregion 測試功能
}

