import { _decorator, Component, Node, ParticleSystem, ParticleSystem2D, Prefab, Tween, tween, warn } from 'cc';
import { Define } from 'db://astarte-framework/utilis';
import { PrefabPoolManager } from '../Common/PrefabPoolManager';
import { BaseSpine } from '../Spine/BaseSpine';
import { getNodeSpaceAR } from '../Common/NodeProperty';
import { AudioManager } from '../Audio/AudioManager';

const { ccclass, property } = _decorator;

/** @ch pool key（比照 EffectPlate 在地定義 pool key 的慣例） */
const ADD_SPIN_FLY_POOL_KEY = "AddSpinFly";
/** @ch 拖尾在 prefab 上的循環動畫名（移動期間持續播放；prefab 無此動畫則純位移、安全略過） */
const ADD_SPIN_FLY_ANIM = "Short_Trail_Up";
/** @ch 逾時防卡死秒數（比照 AddFreeState 既有 timeout） */
const FLY_TIMEOUT_SEC = 3;
/** @ch tween 緩動（加速飛向終點，像被吸進去） */
const FLY_EASING = "quadIn";

/**
 * @en Tween-based fly effect for free-game "add spins"
 * @ch 免費遊戲加手數：加局宣告面板 → 剩餘手數計數器 的飛行演出（tween 位移整個節點）
 */
@ccclass('AddSpinFlyEffect')
export class AddSpinFlyEffect extends Component {
    /** @ch 拖尾 prefab（可掛 BaseSpine 做循環發光，移動由本元件 tween 控制） */
    @property({ type: Prefab, tooltip: "拖尾 prefab（可掛 BaseSpine 做循環發光，移動由 tween 控制）" })
    private m_flyPrefab: Prefab = null;

    /** @ch 起點錨：加局宣告面板上的節點（需與 m_flyLayer 同一 Canvas/相機座標系） */
    @property({ type: Node, tooltip: "起點錨：加局宣告面板上的節點（需與 m_flyLayer 同一 Canvas）" })
    private m_startAnchor: Node = null;

    /** @ch 終點錨：剩餘手數計數器節點（需與 m_flyLayer 同一 Canvas/相機座標系） */
    @property({ type: Node, tooltip: "終點錨：剩餘手數計數器節點（需與 m_flyLayer 同一 Canvas）" })
    private m_endAnchor: Node = null;

    /** @ch 拖尾生成的父層（需含 UITransform，蓋在面板與計數器之上） */
    @property({ type: Node, tooltip: "拖尾生成的父層（需含 UITransform，蓋在面板與計數器之上）" })
    private m_flyLayer: Node = null;

    /** @ch 飛行時間（秒） */
    @property({ tooltip: "飛行時間（秒）" })
    private m_flyDuration: number = 0.5;

    onLoad() {
        if (this.m_flyPrefab) {
            PrefabPoolManager.GetInstance().RegisterPrefab(ADD_SPIN_FLY_POOL_KEY, this.m_flyPrefab, 1);
        } else {
            warn("[AddSpinFlyEffect] m_flyPrefab 未指派，加手數拖尾將略過");
        }
    }

    /**
     * @ch 播放「加局宣告面板 → 剩餘手數計數器」的飛行演出（tween 位移）。
     * 播完 resolve；缺資產 / 逾時 / 任何錯誤都安全 resolve（不丟例外），確保不擋住免費遊戲進程。
     * @param onArrive 粒子抵達計數器（tween 到終點）那一刻立即回呼，用來同步開始 count up 演出。
     *                 缺資產而略過拖尾時也會立即回呼，確保 count 不被跳過（只回呼一次）。
     */
    public async PlayAddSpinFly(onArrive?: () => void): Promise<void> {
        // @ch 確保 onArrive 至多觸發一次（正常落點或任何 fallback 都不重複）
        let arrived = false;
        const fireArrive = () => { if (!arrived) { arrived = true; onArrive?.(); } };

        if (!this.m_flyPrefab || !this.m_flyLayer || !this.m_startAnchor || !this.m_endAnchor) {
            console.log("[AddSpinFlyEffect] 屬性未接齊，略過拖尾演出");
            fireArrive();
            return;
        }

        const node = PrefabPoolManager.GetInstance().GetNode(ADD_SPIN_FLY_POOL_KEY, this.m_flyLayer);
        if (!node) {
            console.log("[AddSpinFlyEffect] 無法取得拖尾節點，略過");
            fireArrive();
            return;
        }

        try {
            node.setScale(1, 1, 1);
            node.active = true;

            // 起終點：錨點 world → m_flyLayer 本地座標（node.position 即相對 m_flyLayer）
            const startPos = getNodeSpaceAR(this.m_flyLayer, this.m_startAnchor.getWorldPosition());
            const endPos = getNodeSpaceAR(this.m_flyLayer, this.m_endAnchor.getWorldPosition());
            node.setPosition(startPos);
            console.log("[DEBUG][AddSpinFlyEffect] tween startPos=", startPos, "endPos=", endPos);

            // 若 prefab 上有 BaseSpine，移動期間循環播放發光動畫（無則純位移）
            const baseSpine = node.getComponent(BaseSpine);
            if (baseSpine && baseSpine.Spine) {
                baseSpine.PlayAnimation(ADD_SPIN_FLY_ANIM, baseSpine.Spine, true);
            }

            // tween 位移 start → end（含逾時保底）；到終點瞬間立即觸發 onArrive 開始 count
            await Promise.race([
                new Promise<void>((resolve) => {
                    tween(node)
                        .to(this.m_flyDuration, { position: endPos }, { easing: FLY_EASING })
                        .call(() => { fireArrive(); resolve(); })
                        .start();
                }),
                Define.Wait(this, FLY_TIMEOUT_SEC),
            ]);
            // 逾時保底情況下 tween 的 .call 不會觸發，這裡補一次（fireArrive 內部去重）
            fireArrive();

        } catch (e) {
            warn("[AddSpinFlyEffect] PlayAddSpinFly 發生例外，已略過", e);
        } finally {
            Tween.stopAllByTarget(node);
            this.ResetParticles(node);
            PrefabPoolManager.GetInstance().ReturnNode(ADD_SPIN_FLY_POOL_KEY, node);
        }
    }

    /**
     * @ch 回收前重置節點上所有粒子：停止發射並清除既有粒子，
     * 避免 World 模擬空間的粒子在節點被重用時殘留成殘影。涵蓋 3D / 2D 兩種粒子。
     */
    private ResetParticles(node: Node) {
        const ps3dList = node.getComponentsInChildren(ParticleSystem);
        for (const ps of ps3dList) {
            ps.stop();
            ps.clear();
        }
        const ps2dList = node.getComponentsInChildren(ParticleSystem2D);
        for (const ps of ps2dList) {
            ps.stopSystem();
            ps.resetSystem();
        }
    }
}

