140	                    log(`[Roulette] WheelSpine Out event: ${eventName}`);
141	                    if (eventName === "Character_FGBoard_Wheel_Out") {
142	                        rouletteSpineNode.setParent(rouletteDownParent);
143	                        if (this.m_gameView.PointerSpine) this.m_gameView.PointerSpine.node.active = false;
144	                        // 先停掉角色 Loop 動畫，避免 PlayAnimation 重入卡住
