146	                        // 角色 Wheel_Out 播完 → 播 FGBoard_Upgrades_In，Wheel_Out 動畫中 event 觸發面板
147	                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "FGBoard_Wheel_Out", false, () => {
