209	    public OnLeave() {
210	        // 解鎖旋轉由 SpinState dispatch AWARD_OUT_RT 負責
211	        // 確保 RouletteSpineNode 預設關閉
212	        const rouletteSpineNode = this.m_gameView.RouletteSpineNode;
