216	    /**
217	     * @ch 漸變切換背景：fadeOut → 切換 → fadeIn
218	     */
219	    private FadeChangeBackground(type: BackgroundType): void {
220	        const bgMgr = this.m_gameView.node.scene.getComponentInChildren(BackgroundManager);
221	        const bgNode = bgMgr ? bgMgr.node : null;
222	
223	        if (!bgNode) {
224	            eventManager.Dispatch(BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, type);
225	            return;
226	        }
227	
228	        let opacity = bgNode.getComponent(UIOpacity);
229	        if (!opacity) opacity = bgNode.addComponent(UIOpacity);
230	
231	        tween(opacity)
232	            .to(0.3, { opacity: 0 })
233	            .call(() => {
234	                eventManager.Dispatch(BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, type);
235	            })
236	            .to(0.3, { opacity: 255 })
237	            .start();
238	    }
239	
240	    /**
241	     * @ch UpdateBoard Spine 面板流程
242	     * In → Change_Layer reparent → FGBoard_Icon_Active 播 feature icon
243	     * → 等幾秒 → Cannon 動畫 → Cannon event FGBoard_Upgrades_Out 觸發 UpdateBoard Out
244	     * → Out event Symbol_Remove 播 Explode + 關 FeatureIcon → Out完歸位
245	     */
246	    private async PlayUpdateBoard(spinResults: FGRouletteOption[]): Promise<void>
247	    {
248	        const updateNode = this.m_gameView.UpdateBoardSpineNode;
249	        const rouletteParent = this.m_gameView.RouletteNode;
250	        const rouletteDownParent = this.m_gameView.RouletteDownNode;
251	        if (!updateNode) return;
252	
253	        const spine = updateNode.getComponent(sp.Skeleton);
254	        if (!spine) return;
255	
256	        updateNode.active = true;
257	        spine.node.active = true;
258	
259	        const featureIconNode = this.m_gameView.FeatureIconSpineNode;
260	        const explodeNode = this.m_gameView.ExplodeSpineNode;
261	        const featureIconSpine = featureIconNode?.getComponent(sp.Skeleton);
262	        const explodeSpine = explodeNode?.getComponent(sp.Skeleton);
263	
264	        // 1. 播 In，監聯 events
265	        const updateInKey = this.m_gameView.IsLandscape ? "In_H" : "In";
266	        await new Promise<void>((resolve) => {
267	            AudioManager.Play(AudioManager.AudioClips.FeatureBoard_in);
268	            log(`[Roulette Audio] FeatureBoard_in`);
269	            SpineKit.PlayAnimation(spine, updateInKey, false, 0, (eventName: string) => {
270	                // 2. Change_Layer → reparent 到 Roulette
271	                if (eventName === "Change_Layer") {
272	                    updateNode.setParent(rouletteParent);
273	                }
274	                // 3. FGBoard_Icon_Active → 播 feature icon 動畫 + 音效
275	                if (eventName === "FGBoard_Icon_Active") {
276	                    AudioManager.Play(AudioManager.AudioClips.FeatureBoard_show);
277	                    log(`[Roulette Audio] FeatureBoard_show`);
278	                    this.PlayFeatureIcon(featureIconSpine, spinResults);
279	                }
280	            }).then(() => resolve());
281	        });
282	
283	        // 4. In 播完切 Loop，等幾秒展示（Out 由外部角色 Symbol_Remove 時並行觸發）
284	        const updateLoopKey = this.m_gameView.IsLandscape ? "Loop_H" : "Loop";
285	        SpineKit.PlayAnimation(spine, updateLoopKey, true, 0);
286	        await Define.Wait(this.m_gameView, 3);
287	    }
288	
289	    /** @ch 轉盤面板退場（與角色 Symbol_Remove 並行） */
290	    private PlayUpdateBoardOut(): void {
291	        const updateNode = this.m_gameView.UpdateBoardSpineNode;
292	        const rouletteDownParent = this.m_gameView.RouletteDownNode;
293	        if (!updateNode) return;
294	        const spine = updateNode.getComponent(sp.Skeleton);
295	        if (!spine) return;
296	
297	        const featureIconNode = this.m_gameView.FeatureIconSpineNode;
298	        const explodeSpine = this.m_gameView.ExplodeSpineNode?.getComponent(sp.Skeleton);
299	
300	        // Feature Icon 淡出（delay 1s + fade 1s）
301	        if (featureIconNode) {
302	            let uiOpacity = featureIconNode.getComponent(UIOpacity) || featureIconNode.addComponent(UIOpacity);
303	            tween(uiOpacity)
304	                .delay(1)
305	                .to(1, { opacity: 0 })
306	                .call(() => { featureIconNode.active = false; uiOpacity.opacity = 255; })
307	                .start();
308	        }
309	
310	        const outKey = this.m_gameView.IsLandscape ? "Out_H" : "Out";
311	        AudioManager.Play(AudioManager.AudioClips.FeatureBoard_out);
312	        log(`[Roulette Audio] FeatureBoard_out`);
313	        // UpgradeCannon 同步播 Out
314	        if (this.m_gameView.UpgradeCannonSpine) {
315	            this.m_gameView.UpgradeCannonSpine.node.active = true;
316	            SpineKit.PlayAnimation(this.m_gameView.UpgradeCannonSpine, outKey, false, 0).then(() => {
317	                this.m_gameView.UpgradeCannonSpine.node.active = false;
318	            });
319	        }
320	        SpineKit.PlayAnimation(spine, outKey, false, 0, (outEvent: string) => {
321	            if (outEvent === "Symbol_Remove") {
322	                if (explodeSpine) SpineKit.PlayAnimation(explodeSpine, "Symbol_Remove", false, 0);
323	            }
324	        }).then(() => {
325	            // Out 演出結束後：換亮版 icon + pop 放大（同幀，pop 彈的就是亮版）
326	            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES, this.m_gameView.FreePickItems);
327	            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT);
328	            updateNode.setParent(rouletteDownParent);
329	            updateNode.active = false;
330	            if (this.m_gameView.RouletteNoteNode) this.m_gameView.RouletteNoteNode.active = false;
331	        });
332	    }
333	
334	    private PlayFeatureIcon(featureIconSpine: sp.Skeleton | null, spinResults: FGRouletteOption[]): void
335	    {
336	        if (!featureIconSpine) return;
337	
338	        
339	
340	        const idx = this.GetFeatureAnimIndex(spinResults);
341	        const activeAnim = `FGBoard_IconActive0${idx}`;
342	        const loopAnim = `FGBoard_IconLoop0${idx}`;
343	
344	        featureIconSpine.node.active = true;
345	        // Active 動畫開始 0.5 秒後（先不換正式 icon，等 Out 的 Symbol_Remove event 再換）
346	        SpineKit.PlayAnimation(featureIconSpine, activeAnim, false, 0).then(() => {
347	            SpineKit.PlayAnimation(featureIconSpine, loopAnim, true, 0);
348	        });
349	    }
350	
351	    /**
352	     * @ch 根據 spinResults 組合回傳動畫編號 (1~7)
353	     * 01=Scatter, 02=Target, 03=Bounty
354	     * 04=Scatter+Target, 05=Scatter+Bounty, 06=Target+Bounty, 07=全拿
355	     */
356	    private GetFeatureAnimIndex(spinResults: FGRouletteOption[]): number
357	    {
358	        const has = (o: FGRouletteOption) => spinResults.indexOf(o) >= 0;
359	        const s = has(FGRouletteOption.ScatterBoost);
360	        const t = has(FGRouletteOption.TargetExpand);
361	        const b = has(FGRouletteOption.BountyDouble);
362	
363	        if (s && t && b) return 7;
364	        if (s && t) return 4;
365	        if (s && b) return 5;
366	        if (t && b) return 6;
367	        if (s) return 1;
368	        if (t) return 2;
369	        if (b) return 3;
370	        return 1;
371	    }
372	}
