import { _decorator, log, Node, sp, tween, UIOpacity } from "cc";
import { BaseState, stateManager, eventManager, localeStringManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Define } from "db://astarte-framework/utilis";
import { Common } from "../Common/Common";
import { FG_ROULETTE_MANAGER_EVENT, FGRouletteOption } from "../FreeGame/FGRouletteManager";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';
import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CANNON_ANIM_NAME } from "../BSSpineCtrl";
import { BACKGROUND_MANAGER_EVENT, BackgroundType, BackgroundManager } from "../BackgroundManager";
import { AudioManager } from "../Audio/AudioManager";

const { ccclass } = _decorator;

@ccclass("FreePickRouletteState")
export class FreePickRouletteState extends BaseState
{
    private m_gameView: GameView = null;

    constructor(gameView: GameView)
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : FREE_PICK_ROULETTE" );
        Common.SetLockOrientation(true);
        const roundInfo = this.m_gameView.RoundInfo;
        if (!roundInfo || !roundInfo.FreePickNum || roundInfo.FreePickNum <= 0) {
            stateManager.NextState(Game_Define.GameState.ROUND_END);
            return;
        }

        const pointerCount = roundInfo.FreePickNum;
        const spinResults = roundInfo.FreePickItem as FGRouletteOption[];
        this.m_gameView.FreePickItems = roundInfo.FreePickItem as number[] || [];

        const rouletteSpineNode = this.m_gameView.RouletteSpineNode;
        const rouletteParent = this.m_gameView.RouletteNode;
        const rouletteDownParent = this.m_gameView.RouletteDownNode;
        const spine = this.m_gameView.RouletteSpine;

        // --- WheelSpine 進場 ---
        if (this.m_gameView.RouletteNoteNode) this.m_gameView.RouletteNoteNode.active = true;
        if (spine) {
            rouletteSpineNode.active = true;
            spine.node.active = true;
            if (this.m_gameView.FeatureSelectSpine) this.m_gameView.FeatureSelectSpine.node.active = true;

            // 箭頭由 FGRouletteManager.Open 根據 pointerCount 切換子物件

            const inKey = this.m_gameView.IsLandscape ? "In_H" : "In";

            // Pointer Spine 跟轉盤 In 同步，只設 skin + active（In 動畫由轉盤帶動）
            if (this.m_gameView.PointerSpine) {
                this.m_gameView.PointerSpine.node.active = true;
                this.m_gameView.PointerSpine.clearTrack(0);
                this.m_gameView.PointerSpine.setSkin(`Arrow_0${pointerCount}`);
                SpineKit.PlayAnimation(this.m_gameView.PointerSpine, inKey, false, 0);
                log(`[Roulette] PointerSpine play ${inKey}`);
            }

            // 同時播角色 FGBoard_Wheel_In → 播完接 FGBoard_Wheel_Loop
            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "FGBoard_Wheel_In", false, () => {
                eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "FGBoard_Wheel_Loop", true);
            });

            await new Promise<void>((resolve) => {
                // 黑章進場動畫（和 In 同時播）
                eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SHOW_BLACK_MASK);
                AudioManager.Play(AudioManager.AudioClips.Wheel_in);
                log(`[Roulette Audio] Wheel_in`);
                // 橫版播 RudderBase In_H
                if (this.m_gameView.IsLandscape && this.m_gameView.RudderBaseSpine) {
                    this.m_gameView.RudderBaseSpine.node.active = true;
                    SpineKit.PlayAnimation(this.m_gameView.RudderBaseSpine, "In_H", false, 0);
                }
                // FeatureSelectSpine 同步播 In
                if (this.m_gameView.FeatureSelectSpine) {
                    this.m_gameView.FeatureSelectSpine.clearTrack(1);
                    this.m_gameView.FeatureSelectSpine.clearTrack(2);
                    this.m_gameView.FeatureSelectSpine.clearTrack(3);
                    SpineKit.PlayAnimation(this.m_gameView.FeatureSelectSpine, inKey, false, 0);
                }
                SpineKit.PlayAnimation(spine, inKey, false, 0, (eventName: string) => {
                    if (eventName === "Change_Layer") {
                        rouletteSpineNode.setParent(rouletteParent);
                    }
                }).then(() => resolve());
            });

            // In 完不自動播 Loop，等轉盤旋轉時才切
            // 設定 Rudder event listener（退場 Out 時需要）
            eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SETUP_SPINE_LISTENER);
        }

        // --- 原轉輪流程（3 feature 全拿不旋轉）---
        if (pointerCount < 3) {
            await new Promise<void>((resolve) => {
                eventManager.Dispatch(
                    FG_ROULETTE_MANAGER_EVENT.OPEN,
                    pointerCount,
                    spinResults,
                    () => { resolve(); }
                );
            });
        } else {
            // 3 feature 全拿，跳過旋轉，指針進場後停 1 秒再播 Bingo 亮起，展示 1 秒後走退場
            eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.SHOW_POINTER, pointerCount);
            await Define.Wait(this.m_gameView, 1);
            eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.FINISH_WITHOUT_SPIN, spinResults);
            await Define.Wait(this.m_gameView, 1);
        }

        // --- WheelSpine 退場 ---
        let updateBoardResolve: () => void;
        const updateBoardPromise = new Promise<void>((r) => { updateBoardResolve = r; });
        if (spine) {
            await new Promise<void>((resolve) => {
                const outKey = this.m_gameView.IsLandscape ? "Out_H" : "Out";
                // 黑章淡出
                eventManager.Dispatch(FG_ROULETTE_MANAGER_EVENT.HIDE_BLACK_MASK);
                AudioManager.Play(AudioManager.AudioClips.Wheel_out);
                log(`[Roulette Audio] Wheel_out`);
                // Pointer Spine 同步播 Out
                if (this.m_gameView.PointerSpine) { log(`[Roulette] PointerSpine play ${outKey}`); SpineKit.PlayAnimation(this.m_gameView.PointerSpine, outKey, false, 0).then(() => { this.m_gameView.PointerSpine.node.active = false; }); }
                // 橫版 RudderBase 播 Out_H 後關閉
                if (this.m_gameView.IsLandscape && this.m_gameView.RudderBaseSpine) {
                    SpineKit.PlayAnimation(this.m_gameView.RudderBaseSpine, "Out_H", false, 0).then(() => { this.m_gameView.RudderBaseSpine.node.active = false; });
                }
                // 播 Out 同時延遲 0.5 秒歸零角度
                Define.Wait(this.m_gameView, 0.5).then(() => {
                    rouletteSpineNode.setRotationFromEuler(0, 0, 0);
                });
                SpineKit.PlayAnimation(spine, outKey, false, 0, (eventName: string) => {
                    log(`[Roulette] WheelSpine Out event: ${eventName}`);
                    if (eventName === "Character_FGBoard_Wheel_Out") {
                        rouletteSpineNode.setParent(rouletteDownParent);
                        if (this.m_gameView.PointerSpine) this.m_gameView.PointerSpine.node.active = false;
                        // 先停掉角色 Loop 動畫，避免 PlayAnimation 重入卡住
                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.STOP, BS_SPINE_TYPE.CHARACTER);
                        // 角色 Wheel_Out 播完 → 播 FGBoard_Upgrades_In，Wheel_Out 動畫中 event 觸發面板
                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "FGBoard_Wheel_Out", false, () => {
                            log(`[Roulette] FGBoard_Wheel_Out endCB fired`);
                            // Wheel_Out 播完 → 角色播 FGBoard_Upgrades_In + 直版 spine 同步播
                            if (!this.m_gameView.IsLandscape && this.m_gameView.UpgradesInSpine) {
                                this.m_gameView.UpgradesInSpine.node.active = true;
                                SpineKit.PlayAnimation(this.m_gameView.UpgradesInSpine, "FGBoard_Upgrades_In", false, 0).then(() => {
                                    this.m_gameView.UpgradesInSpine.node.active = false;
                                });
                            }
                            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "FGBoard_Upgrades_In", false, () => {
                                eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "Idle", true);
                            });
                        }, (evtName: string) => {
                            log(`[Roulette] FGBoard_Wheel_Out eventCB: ${evtName}`);
                            // FGBoard_Wheel_Out 動畫中的 event FGBoard_Upgrades_In → 觸發面板
                            if (evtName === "FGBoard_Upgrades_In") {
                                this.PlayUpdateBoard(spinResults).then(() => {
                                    this.PlayUpdateBoardOut();
                                    // 橫版：大砲提早 0.3 秒發動
                                    if (this.m_gameView.IsLandscape) {
                                        Define.Wait(this.m_gameView, 0.3).then(() => {
                                            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON,
                                                CANNON_ANIM_NAME.Symbol_Remove, false);
                                        });
                                    }
                                    eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "Symbol_Remove", false, () => {
                                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, "Idle", true);
                                        updateBoardResolve();
                                    }, (cannonEvt: string) => {
                                        // 直版：由 spine event 觸發大砲
                                        if (!this.m_gameView.IsLandscape && cannonEvt === "FGBoard_Upgrades_Cannon") {
                                            eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON,
                                                CANNON_ANIM_NAME.Symbol_Remove, false);
                                        }
                                    });
                                });
                            }
                        });
                    }
                }).then(() => {
                    rouletteSpineNode.active = false;
                    resolve();
                });
            });
        } else {
            updateBoardResolve();
        }

        // 等轉盤面板流程完成（由角色 Upgrades_In event 驅動），加 timeout 防卡
        const updateBoardTimeout = new Promise<void>((resolve) => {
            this.m_gameView.scheduleOnce(() => {
                log(`[Roulette] updateBoardPromise TIMEOUT (10s) — force resolve`);
                resolve();
            }, 10);
        });
        await Promise.race([updateBoardPromise, updateBoardTimeout]);

        stateManager.NextState(Game_Define.GameState.ROUND_END);
    }

    public OnProcess() {}

    public OnLeave() {
        // 解鎖旋轉由 SpinState dispatch AWARD_OUT_RT 負責
        // 確保 RouletteSpineNode 預設關閉
        const rouletteSpineNode = this.m_gameView.RouletteSpineNode;
        if (rouletteSpineNode) rouletteSpineNode.active = false;
    }

    /**
     * @ch 漸變切換背景：fadeOut → 切換 → fadeIn
     */
    private FadeChangeBackground(type: BackgroundType): void {
        const bgMgr = this.m_gameView.node.scene.getComponentInChildren(BackgroundManager);
        const bgNode = bgMgr ? bgMgr.node : null;

        if (!bgNode) {
            eventManager.Dispatch(BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, type);
            return;
        }

        let opacity = bgNode.getComponent(UIOpacity);
        if (!opacity) opacity = bgNode.addComponent(UIOpacity);

        tween(opacity)
            .to(0.3, { opacity: 0 })
            .call(() => {
                eventManager.Dispatch(BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, type);
            })
            .to(0.3, { opacity: 255 })
            .start();
    }

    /**
     * @ch UpdateBoard Spine 面板流程
     * In → Change_Layer reparent → FGBoard_Icon_Active 播 feature icon
     * → 等幾秒 → Cannon 動畫 → Cannon event FGBoard_Upgrades_Out 觸發 UpdateBoard Out
     * → Out event Symbol_Remove 播 Explode + 關 FeatureIcon → Out完歸位
     */
    private async PlayUpdateBoard(spinResults: FGRouletteOption[]): Promise<void>
    {
        const updateNode = this.m_gameView.UpdateBoardSpineNode;
        const rouletteParent = this.m_gameView.RouletteNode;
        const rouletteDownParent = this.m_gameView.RouletteDownNode;
        if (!updateNode) return;

        const spine = updateNode.getComponent(sp.Skeleton);
        if (!spine) return;

        updateNode.active = true;
        spine.node.active = true;

        const featureIconNode = this.m_gameView.FeatureIconSpineNode;
        const explodeNode = this.m_gameView.ExplodeSpineNode;
        const featureIconSpine = featureIconNode?.getComponent(sp.Skeleton);
        const explodeSpine = explodeNode?.getComponent(sp.Skeleton);

        // 1. 播 In，監聯 events
        const updateInKey = this.m_gameView.IsLandscape ? "In_H" : "In";
        await new Promise<void>((resolve) => {
            AudioManager.Play(AudioManager.AudioClips.FeatureBoard_in);
            log(`[Roulette Audio] FeatureBoard_in`);
            SpineKit.PlayAnimation(spine, updateInKey, false, 0, (eventName: string) => {
                // 2. Change_Layer → reparent 到 Roulette
                if (eventName === "Change_Layer") {
                    updateNode.setParent(rouletteParent);
                }
                // 3. FGBoard_Icon_Active → 播 feature icon 動畫 + 音效
                if (eventName === "FGBoard_Icon_Active") {
                    AudioManager.Play(AudioManager.AudioClips.FeatureBoard_show);
                    log(`[Roulette Audio] FeatureBoard_show`);
                    this.PlayFeatureIcon(featureIconSpine, spinResults);
                }
            }).then(() => resolve());
        });

        // 4. In 播完切 Loop，等幾秒展示（Out 由外部角色 Symbol_Remove 時並行觸發）
        const updateLoopKey = this.m_gameView.IsLandscape ? "Loop_H" : "Loop";
        SpineKit.PlayAnimation(spine, updateLoopKey, true, 0);
        await Define.Wait(this.m_gameView, 3);
    }

    /** @ch 轉盤面板退場（與角色 Symbol_Remove 並行） */
    private PlayUpdateBoardOut(): void {
        const updateNode = this.m_gameView.UpdateBoardSpineNode;
        const rouletteDownParent = this.m_gameView.RouletteDownNode;
        if (!updateNode) return;
        const spine = updateNode.getComponent(sp.Skeleton);
        if (!spine) return;

        const featureIconNode = this.m_gameView.FeatureIconSpineNode;
        const explodeSpine = this.m_gameView.ExplodeSpineNode?.getComponent(sp.Skeleton);

        // Feature Icon 淡出（delay 1s + fade 1s）
        if (featureIconNode) {
            let uiOpacity = featureIconNode.getComponent(UIOpacity) || featureIconNode.addComponent(UIOpacity);
            tween(uiOpacity)
                .delay(1)
                .to(1, { opacity: 0 })
                .call(() => { featureIconNode.active = false; uiOpacity.opacity = 255; })
                .start();
        }

        const outKey = this.m_gameView.IsLandscape ? "Out_H" : "Out";
        AudioManager.Play(AudioManager.AudioClips.FeatureBoard_out);
        log(`[Roulette Audio] FeatureBoard_out`);
        // UpgradeCannon 同步播 Out
        if (this.m_gameView.UpgradeCannonSpine) {
            this.m_gameView.UpgradeCannonSpine.node.active = true;
            SpineKit.PlayAnimation(this.m_gameView.UpgradeCannonSpine, outKey, false, 0).then(() => {
                this.m_gameView.UpgradeCannonSpine.node.active = false;
            });
        }
        SpineKit.PlayAnimation(spine, outKey, false, 0, (outEvent: string) => {
            if (outEvent === "Symbol_Remove") {
                if (explodeSpine) SpineKit.PlayAnimation(explodeSpine, "Symbol_Remove", false, 0);
            }
        }).then(() => {
            // Out 演出結束後：換亮版 icon + pop 放大（同幀，pop 彈的就是亮版）
            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES, this.m_gameView.FreePickItems);
            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.POP_SCALE_EFFECT);
            updateNode.setParent(rouletteDownParent);
            updateNode.active = false;
            if (this.m_gameView.RouletteNoteNode) this.m_gameView.RouletteNoteNode.active = false;
        });
    }

    private PlayFeatureIcon(featureIconSpine: sp.Skeleton | null, spinResults: FGRouletteOption[]): void
    {
        if (!featureIconSpine) return;



        const idx = this.GetFeatureAnimIndex(spinResults);
        const activeAnim = `FGBoard_IconActive0${idx}`;
        const loopAnim = `FGBoard_IconLoop0${idx}`;

        featureIconSpine.node.active = true;
        // Active 動畫開始 0.5 秒後（先不換正式 icon，等 Out 的 Symbol_Remove event 再換）
        SpineKit.PlayAnimation(featureIconSpine, activeAnim, false, 0).then(() => {
            SpineKit.PlayAnimation(featureIconSpine, loopAnim, true, 0);
        });
    }

    /**
     * @ch 根據 spinResults 組合回傳動畫編號 (1~7)
     * 01=Scatter, 02=Target, 03=Bounty
     * 04=Scatter+Target, 05=Scatter+Bounty, 06=Target+Bounty, 07=全拿
     */
    private GetFeatureAnimIndex(spinResults: FGRouletteOption[]): number
    {
        const has = (o: FGRouletteOption) => spinResults.indexOf(o) >= 0;
        const s = has(FGRouletteOption.ScatterBoost);
        const t = has(FGRouletteOption.TargetExpand);
        const b = has(FGRouletteOption.BountyDouble);

        if (s && t && b) return 7;
        if (s && t) return 4;
        if (s && b) return 5;
        if (t && b) return 6;
        if (s) return 1;
        if (t) return 2;
        if (b) return 3;
        return 1;
    }
}

