16	@ccclass( "UnshowPrepareState" )
17	export class UnshowPrepareState extends BaseState
18	{
19	    private m_gameView: GameView = null;
20	
21	    /** @ch 起始盤面索引 */
22	    private m_startRound: number = 0;
23	
24	    /** @ch 起始盤面資訊 */
25	    private m_startRoundInfo: protocol.ar2pq9Proto.IRoundInfo = null;
26	
27	    /** @ch 要還原的盤面資料 */
28	    private m_unshowSpinAckQue: protocol.ar2pq9Proto.IRoundInfo[] = [];
29	
30	    /** @ch 上一輪累積贏分 */
31	    private m_previousAccumulatedWinValue: number = 0;
32	
33	    constructor( gameView: GameView )
34	    {
35	        super();
36	        this.m_gameView = gameView;
37	    }
38	
39	    public async OnEnter()
40	    {
41	        log( "OnEnter State : UnshowPrepare" );
42	        if ( !commonGameManager.HasUnshow )
43	        {
44	            return;
45	        }
46	
47	        newExtraManager.HasUnshow = false;
48	        
49	        newBottombarManager.SetBarNodeVisiable( true );
50	        eventManager.Dispatch( GAME_INTRO_MANAGER_EVENT.HIDE_NODE );
51	        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck.RoundQueue ?? [];
52	        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);
53	
54	        // 如果有多個盤面資料，則選擇要還原的盤面
55	        if (this.m_unshowSpinAckQue.length > 0) {
56	            const lastIndex = this.m_unshowSpinAckQue.length - 1;
57	            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
58	                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
59	                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
60	            }
61	            this.m_gameView.CurRoundIndex = this.m_startRound;
62	            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
63	        }
64	        else {
65	            error("[UnshowPrepareState] RoundQueue is empty");
66	            this.m_startRound = 0;
67	            this.m_gameView.CurRoundIndex = 0;
68	            this.m_startRoundInfo = null;
69	        }
70	
71	        this.m_previousAccumulatedWinValue = 0;
72	
73	        if (
74	            this.m_unshowSpinAckQue.length > 1
75	            && this.m_startRound >= 1
76	        ) {
77	            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
78	                this.m_gameView.IsFreeGame = true;
79	                this.m_gameView.IsFirstRound = false;
80	
81	                // 還原 FreePickItems（unshow startRound>=1 時 OnRecvSpinAck 不會設定）
82	                const firstRound = this.m_unshowSpinAckQue[0];
83	                if (firstRound?.FreePickItem && (firstRound.FreePickItem as number[]).length > 0) {
84	                    this.m_gameView.FreePickItems = firstRound.FreePickItem as number[];
85	                }
86	
87	                let isUseCreateFreeGamePlate = false;
88	
89	                // 用上一局的 FeverTotalRound（加局前的值），讓本局 +spin 判定能正常觸發
90	                const prevRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
91	                this.m_gameView.FreeTotalRound = prevRoundInfo ? prevRoundInfo.FeverTotalRound : this.m_startRoundInfo.FeverTotalRound;
92	                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 
93	                    this.m_startRoundInfo.FeverNowRound - 1, 
94	                    this.m_gameView.FreeTotalRound);
95	                //this.m_gameView.FgCounter.SetCounter( remainRound, this.m_gameView.FreeTotalRound );
96	                // 如果目前是免費遊戲，且免費遊戲回合數為0，則需要重新建立免費遊戲盤面
97	                if (this.m_startRoundInfo.FeverNowRound <= 0) {
98	                    isUseCreateFreeGamePlate = true;
99	                } else {
100	                    // 取得上一輪盤面資料
101	                    const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
102	                    let previousPlateInfo = null;
103	                    if (previousRoundInfo && previousRoundInfo.PlateQueue.length > 0) {
104	                        // 取得上一輪最後一個盤面資料
105	                        previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
106	
107	                        // 設定盤面資料
108	                        this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);
109	
110	                        // 設置懸賞令資料（還原 → isNewRound=true 整批重建）
111	                        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
112	                    }
113	                    // 如果上一輪盤面資料不存在，則需要重新建立免費遊戲盤面 照理說不會發生，但還是加上去
114	                    else {
115	                        isUseCreateFreeGamePlate = true;
116	                    }
117	                }
118	
119	                // 如果需要重新建立免費遊戲盤面，則建立免費遊戲盤面
120	                if (isUseCreateFreeGamePlate) {
121	                    this.m_gameView.SlotReels.SetFreeGamePlate();
122	                }
123	            }
124	            else {
125	                // MG 模式：恢復上一輪最終盤面（tumble 消除補位後的結果）
126	                const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
127	                if (previousRoundInfo && previousRoundInfo.PlateQueue && previousRoundInfo.PlateQueue.length > 0) {
128	                    const previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
129	                    this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);
130	                    // 還原 → isNewRound=true 整批重建
131	                    eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
132	                }
133	            }
134	
135	            // 計算上一輪累積贏分
136	            for (let i = 0; i < this.m_startRound; i++) {
137	                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
138	            }
139	        }
140	
141	        // 清除上一局殘留的特效（unshow 跳過了正常報獎清除流程）
142	        this.m_gameView.EffectPlate.ReturnAllTargetStopNodes();
143	        this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();
144	        this.m_gameView.SlotReels.RestoreHiddenScatterSymbols();
145	
146	        // 恢復UI
147	        await this.RestoreUI();
148	
149	        // ExtraBet 僅主遊戲顯示，此路徑繞過 EnterFreeState；須在 RestoreUI 之後隱藏，
150	        // 避免 RestoreExtraBetState 的動畫在 inactive node 上 await 不 resolve
151	        if ( this.m_gameView.IsFreeGame ) {
152	            this.m_gameView.SetExtraBetVisible( false );
153	        }
154	
155	        // 恢復背景音樂
156	        this.RestoreBgm();
157	
158	        msgBoxManager.ShowMessageBox(
159	            Define.StringKey.MSGBOX_UNSHOW_BACK,
160	            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
161	            () => {
162	                stateManager.NextState(CommonState.SPIN);
163	            }
164	        );
165	    }
166	
167	    public OnProcess()
168	    {
169	    }
170	
171	    public OnLeave()
172	    {
173	        this.m_startRoundInfo = null;
174	        this.m_previousAccumulatedWinValue = 0;
175	    }
176	
177	    /**
178	     * @ch 恢復免費遊戲UI
179	     */
180	    private RestoreFreeGameUI()
181	    {
182	        // 設定下bar為免費遊戲狀態
