import { _decorator, error, log } from "cc";
import GameView from "../GameView";
import { BaseState, commonGameManager, eventManager, msgBoxManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
import { CommonState, Define } from "db://astarte-framework/utilis";
import { FeverGameType } from "../Game_Define";
import { GAME_INTRO_MANAGER_EVENT } from "../GameIntroManager";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { REEL_UI_MANAGER_EVENT, UIType } from "../Reel/ReelManager";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { BACKGROUND_MANAGER_EVENT, BackgroundType } from "../BackgroundManager";
import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";

const { ccclass } = _decorator;

@ccclass( "UnshowPrepareState" )
export class UnshowPrepareState extends BaseState
{
    private m_gameView: GameView = null;

    /** @ch 起始盤面索引 */
    private m_startRound: number = 0;

    /** @ch 起始盤面資訊 */
    private m_startRoundInfo: protocol.ar2pq9Proto.IRoundInfo = null;

    /** @ch 要還原的盤面資料 */
    private m_unshowSpinAckQue: protocol.ar2pq9Proto.IRoundInfo[] = [];

    /** @ch 上一輪累積贏分 */
    private m_previousAccumulatedWinValue: number = 0;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        log( "OnEnter State : UnshowPrepare" );
        if ( !commonGameManager.HasUnshow )
        {
            return;
        }

        newExtraManager.HasUnshow = false;

        newBottombarManager.SetBarNodeVisiable( true );
        eventManager.Dispatch( GAME_INTRO_MANAGER_EVENT.HIDE_NODE );
        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck.RoundQueue ?? [];
        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);

        // 如果有多個盤面資料，則選擇要還原的盤面
        if (this.m_unshowSpinAckQue.length > 0) {
            const lastIndex = this.m_unshowSpinAckQue.length - 1;
            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
            }
            this.m_gameView.CurRoundIndex = this.m_startRound;
            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
        }
        else {
            error("[UnshowPrepareState] RoundQueue is empty");
            this.m_startRound = 0;
            this.m_gameView.CurRoundIndex = 0;
            this.m_startRoundInfo = null;
        }

        this.m_previousAccumulatedWinValue = 0;

        if (
            this.m_unshowSpinAckQue.length > 1
            && this.m_startRound >= 1
        ) {
            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
                this.m_gameView.IsFreeGame = true;
                this.m_gameView.IsFirstRound = false;

                // 還原 FreePickItems（unshow startRound>=1 時 OnRecvSpinAck 不會設定）
                const firstRound = this.m_unshowSpinAckQue[0];
                if (firstRound?.FreePickItem && (firstRound.FreePickItem as number[]).length > 0) {
                    this.m_gameView.FreePickItems = firstRound.FreePickItem as number[];
                }

                let isUseCreateFreeGamePlate = false;

                // 用上一局的 FeverTotalRound（加局前的值），讓本局 +spin 判定能正常觸發
                const prevRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
                this.m_gameView.FreeTotalRound = prevRoundInfo ? prevRoundInfo.FeverTotalRound : this.m_startRoundInfo.FeverTotalRound;
                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 
                    this.m_startRoundInfo.FeverNowRound - 1, 
                    this.m_gameView.FreeTotalRound);
                //this.m_gameView.FgCounter.SetCounter( remainRound, this.m_gameView.FreeTotalRound );
                // 如果目前是免費遊戲，且免費遊戲回合數為0，則需要重新建立免費遊戲盤面
                if (this.m_startRoundInfo.FeverNowRound <= 0) {
                    isUseCreateFreeGamePlate = true;
                } else {
                    // 取得上一輪盤面資料
                    const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
                    let previousPlateInfo = null;
                    if (previousRoundInfo && previousRoundInfo.PlateQueue.length > 0) {
                        // 取得上一輪最後一個盤面資料
                        previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];

                        // 設定盤面資料
                        this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);

                        // 設置懸賞令資料（還原 → isNewRound=true 整批重建）
                        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
                    }
                    // 如果上一輪盤面資料不存在，則需要重新建立免費遊戲盤面 照理說不會發生，但還是加上去
                    else {
                        isUseCreateFreeGamePlate = true;
                    }
                }

                // 如果需要重新建立免費遊戲盤面，則建立免費遊戲盤面
                if (isUseCreateFreeGamePlate) {
                    this.m_gameView.SlotReels.SetFreeGamePlate();
                }
            }
            else {
                // MG 模式：恢復上一輪最終盤面（tumble 消除補位後的結果）
                const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
                if (previousRoundInfo && previousRoundInfo.PlateQueue && previousRoundInfo.PlateQueue.length > 0) {
                    const previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
                    this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);
                    // 還原 → isNewRound=true 整批重建
                    eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
                }
            }

            // 計算上一輪累積贏分
            for (let i = 0; i < this.m_startRound; i++) {
                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
            }
        }

        // 清除上一局殘留的特效（unshow 跳過了正常報獎清除流程）
        this.m_gameView.EffectPlate.ReturnAllTargetStopNodes();
        this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();
        this.m_gameView.SlotReels.RestoreHiddenScatterSymbols();

        // 恢復UI
        await this.RestoreUI();

        // ExtraBet 僅主遊戲顯示，此路徑繞過 EnterFreeState；須在 RestoreUI 之後隱藏，
        // 避免 RestoreExtraBetState 的動畫在 inactive node 上 await 不 resolve
        if ( this.m_gameView.IsFreeGame ) {
            this.m_gameView.SetExtraBetVisible( false );
        }

        // 恢復背景音樂
        this.RestoreBgm();

        msgBoxManager.ShowMessageBox(
            Define.StringKey.MSGBOX_UNSHOW_BACK,
            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
            () => {
                stateManager.NextState(CommonState.SPIN);
            }
        );
    }

    public OnProcess()
    {
    }

    public OnLeave()
    {
        this.m_startRoundInfo = null;
        this.m_previousAccumulatedWinValue = 0;
    }

    /**
     * @ch 恢復免費遊戲UI
     */
    private RestoreFreeGameUI()
    {
        // 設定下bar為免費遊戲狀態
        newBottombarManager.SetEnterFree();

        // 切換到免費遊戲UI
        eventManager.Dispatch( REEL_UI_MANAGER_EVENT.CHANGE_UI, UIType.FreeGame );
        eventManager.Dispatch( BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, BackgroundType.FreeGame );

        // 還原 feature icon 狀態
        if (this.m_gameView.FreePickItems && this.m_gameView.FreePickItems.length > 0) {
            if (this.m_gameView.FeatureIconSpineNode) this.m_gameView.FeatureIconSpineNode.active = true;
            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES, this.m_gameView.FreePickItems);
        }

        // 還原 symbol 底板（MultiplierBase）
        if (this.m_startRound >= 1) {
            const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
            if (previousRoundInfo && previousRoundInfo.PlateQueue && previousRoundInfo.PlateQueue.length > 0) {
                const lastPlate = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
                if (lastPlate.BasePlateIndex && lastPlate.BasePlateIndex.length > 0) {
                    // 展平 IIntAry[] → number[]（col-major: col0row0, col0row1, ... col1row0, ...）
                    const flatList: number[] = [];
                    for (const col of lastPlate.BasePlateIndex) {
                        if (col.Data) {
                            for (const val of col.Data) {
                                flatList.push(val);
                            }
                        }
                    }
                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true);
                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST, flatList);
                }
            }
        }
    }

    /**
     * @ch 恢復所有UI
     */
    private async RestoreUI()
    {
        if (this.m_gameView.IsFreeGame) {
            this.RestoreFreeGameUI();
        }

        this.RestoreWinValue();

        if (this.m_gameView.UnshowSpinAck != null && commonGameManager.UnshowBaseBet < commonGameManager.UnshowRealBet) {
            await this.m_gameView.RestoreExtraBetState();
        }
    }

    /**
     * @ch 恢復贏分
     */
    private RestoreWinValue()
    {

        const totalWin = this.m_gameView.UnshowSpinAck?.TotalWin ?? 0;
        this.m_gameView.AccumulatedWin = this.m_previousAccumulatedWinValue;
        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_gameView.AccumulatedWin } );
    }

    /**
     * @ch 恢復背景音樂
     */
    private RestoreBgm()
    {
        this.m_gameView.PlayMainGameBgm();
        if (this.m_gameView.IsFreeGame) {
            this.m_gameView.PauseMainGameBgm();
            this.m_gameView.PlayFreeGameBgm();
        }
    }
}

