import { log, Node, Vec3, warn } from "cc";
import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
import { Define } from "db://astarte-framework/utilis";
import { AudioManager } from "../Audio/AudioManager";

export class WantedPosterState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : WANTED_POSTER" );
        const plateInfo = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ]
            .PlateQueue[ this.m_gameView.CurPlateIndex ];

        const awardDataVec = plateInfo.AwardDataVec ?? [];
        const bountyDataVec = plateInfo.BountyDataVec ?? [];

        // BC-3：找出被消除的符號中，有哪些命中懸賞令的 BaseSymbol
        const triggeredBounties = this.FindTriggeredBounties( awardDataVec, bountyDataVec );

        if ( triggeredBounties.length === 0 )
        {

            stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
            return;
        }

        // 以 BaseSymbol 分組，同組合併成一隻 spine（連乘）
        const basePlateIndexes = plateInfo.BasePlateIndex ?? [];
        const groups = this.GroupBountiesByBaseSymbol( triggeredBounties );

        // 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本狀態只播懸賞令 spine 演出；
        // 多個不同 BaseSymbol 群組改為「並行」一起演出（不再逐組序列）。
        await Promise.all( groups.map( group => this.PlayBountyGroupPerform(
            group, awardDataVec, plateInfo.PlateSymbol, basePlateIndexes
        ) ) );

        stateManager.NextState( Game_Define.GameState.MATCHING_PATCH_UP );
    }

    public OnProcess() { }

    public OnLeave() { }

    /**
     * @ch 對「一組同 BaseSymbol 的懸賞」執行 ①Mark → ②Symbol_In → ③(Mark_Active ∥ Symbol_Active) → ④底板SET
     *
     * 透過 WANTED_POSTER_MANAGER_EVENT 與常駐 WantedPosterManager 溝通；
     * 場上 Wanted Spine 由 EffectPlate.SpawnAndPlayWantedSymbolIn / PlayWantedSymbolActiveAndRecycle 直接呼叫
     *
     * 合併語意：同組所有 bounty 共用同一 BaseSymbol（前提②）與同一組位置
     * （同 BaseSymbol → awardDataVec 對應唯一一筆 award），故 spawn 只跑一次。
     *
     * BC-4：對該 BaseSymbol 的所有常駐 item 同時播 Mark → Mark_Active，最後各自 active=false（Manager.OnEvent 內處理）
     * BC-6：階段 ③ Mark_Active 與 Symbol_Active 同 Promise.all 起播
     * BC-7：場上 spine 顯示組內 Multiple 連乘（純表演）
     * 新流程③：symbol/wild 消除已在 ExplodeState 步驟①完成，本方法不再消除，只播 spine 演出。
     * EH-1：找不到對應 item 由 Manager 內部 warn + 立刻 resolve，不阻斷流程
     */
    private async PlayBountyGroupPerform(
        group: protocol.ar2pq9Proto.IBountyData[],
        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
        curPlateSymbol: protocol.ar2pq9Proto.IColumn[],
        basePlateIndexes: protocol.ar2pq9Proto.IIntAry[]
    ): Promise<void>
    {
        if ( group.length === 0 ) return;

        // 組內共同 BaseSymbol（前提②：同 BaseSymbol 的 BountySymbol 一定相同）
        const baseSymbol = group[ 0 ].BaseSymbol;
        if ( baseSymbol === null || baseSymbol === undefined )
        {
            warn( '[WantedPosterState] PlayBountyGroupPerform: BaseSymbol 為空，跳過' );
            return;
        }

        // 位置由組內共同 BaseSymbol 單次取得（與組內筆數無關）
        const matchedAward = awardDataVec.find(
            award => award.Symbol === baseSymbol
                && award.EliminatePos
                && award.EliminatePos.length > 0
        );
        if ( !matchedAward ) return;

        // 過濾掉 Wild 位置（spine 與 ④底板只跑非 wild；wild 的消除/底板已在 ExplodeState 處理）
        const filteredPositions = this.FilterNonWildPositions(
            matchedAward.EliminatePos!, curPlateSymbol
        );
        // 無非 wild 位置 → 無 spine 可演（wild 消除已在 ExplodeState 完成）
        if ( filteredPositions.length === 0 ) return;

        // 場上 spine 顯示倍率 = 組內 Multiple 連乘（純表演）
        const multiplier = this.ComputeGroupMultiplier( group );

        // 把 positions(一維索引) 轉為世界座標（事件 payload 用世界座標，避免在 manager 跨越 SlotReels 依賴）
        const worldPositions = filteredPositions.map( pos => {
            const col = Math.floor( pos / Game_Define.ROW );
            const row = pos % Game_Define.ROW;
            return this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( col, row );
        } );

        // ① Mark — 事件 + Promise wrapper（同 EffectPlate 對 MULTIPLIER_BASE_MANAGER 的風格）
        await new Promise<void>( resolve => {
            eventManager.Dispatch(
                WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
                baseSymbol,
                resolve
            );
        } );

        // ② 懸賞令 spine 進場（Symbol_In）。symbol/wild 消除已在 ExplodeState 步驟①完成，此處不再消除
        const spawnedNodes: Node[] = await this.m_gameView.EffectPlate.SpawnAndPlayWantedSymbolIn(
            worldPositions, baseSymbol, multiplier
        );

        // ③ Mark_Active ∥ Symbol_Active 同時起播
        await Promise.all( [
            new Promise<void>( resolve => {
                eventManager.Dispatch(
                    WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
                    baseSymbol,
                    resolve
                );
            } ),
            this.m_gameView.EffectPlate.PlayWantedSymbolActiveAndRecycle( spawnedNodes ),
        ] );

        // ④ 場上 Wanted 表演完成後，更新懸賞令位置的乘倍底板（帶 Spine 動畫）
        // 移到組末才升底板，避免被階段②/③的 Spine 動畫分散視覺焦點
        // await Define.Wait( this.m_gameView, 0.5 );
        eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true );
        // 燃燒表演完成後刷新乘倍底板，同時播放刷新倍數音效（每組一次，並發限制避免多組重疊）
        AudioManager.Play( AudioManager.AudioClips.Wanted_MultiAdd );
        const upgradePromises: Promise<void>[] = [];
        for ( const pos of filteredPositions )
        {
            const col = Math.floor( pos / Game_Define.ROW );
            const row = pos % Game_Define.ROW;
            upgradePromises.push( new Promise<void>( resolve =>
            {
                eventManager.Dispatch(
                    MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_WITH_ANIM,
                    pos,
                    basePlateIndexes[ col ].Data[ row ],
                    resolve
                );
            } ) );
        }
        await Promise.all( upgradePromises );
    }

    /**
     * @ch BC-1：將已觸發的 bounty 以 BaseSymbol 分組
     * 同 BaseSymbol 歸同組；組順序依各 BaseSymbol 首次出現順序，組內保留原順序。
     * 輸入契約：吃 FindTriggeredBounties 的輸出（已觸發子集），非原始 bountyDataVec。
     */
    private GroupBountiesByBaseSymbol(
        bounties: protocol.ar2pq9Proto.IBountyData[]
    ): protocol.ar2pq9Proto.IBountyData[][]
    {
        const groups: protocol.ar2pq9Proto.IBountyData[][] = [];
        const groupIndexByBaseSymbol = new Map<number, number>();
        for ( const bounty of bounties )
        {
            const key = bounty.BaseSymbol;
            if ( key === null || key === undefined ) continue;
            const existing = groupIndexByBaseSymbol.get( key );
            if ( existing !== undefined )
            {
                groups[ existing ].push( bounty );
            }
            else
            {
                groupIndexByBaseSymbol.set( key, groups.length );
                groups.push( [ bounty ] );
            }
        }
        return groups;
    }

    /**
     * @ch BC-2：組內 Multiple 連乘（純函式）
     * DR-9：Multiple 為 null/undefined/非有限數 → 視為中性值 1（跳過不計），避免連乘塌成 0。
     * 空組回 1。
     */
    private ComputeGroupMultiplier(
        group: protocol.ar2pq9Proto.IBountyData[]
    ): number
    {
        let product = 1;
        for ( const bounty of group )
        {
            const m = bounty.Multiple;
            if ( m !== null && m !== undefined && Number.isFinite( m ) )
            {
                product *= m;
            }
        }
        return product;
    }

    /**
     * @ch 找出被消除的符號中命中懸賞令的資料
     * BC-3：EliminatePos.length > 0 代表該符號有被消除；
     *       若其 Symbol 值等於某懸賞令的 BaseSymbol，則該懸賞令被觸發。
     * R-4：award.Symbol / bounty.BaseSymbol 在 proto 是 number|null，過濾掉 null/undefined 避免污染 Set
     */
    private FindTriggeredBounties(
        awardDataVec: protocol.ar2pq9Proto.IAwardData[],
        bountyDataVec: protocol.ar2pq9Proto.IBountyData[]
    ): protocol.ar2pq9Proto.IBountyData[]
    {
        if ( awardDataVec.length === 0 || bountyDataVec.length === 0 )
        {
            return [];
        }

        // 收集本次被消除的符號 ID
        const eliminatedSymbols = new Set<number>();
        for ( const award of awardDataVec )
        {
            if ( award.EliminatePos && award.EliminatePos.length > 0
                && award.Symbol !== null && award.Symbol !== undefined )
            {
                eliminatedSymbols.add( award.Symbol );
            }
        }

        // 比對懸賞令的 BaseSymbol
        return bountyDataVec.filter( bounty =>
            bounty.BaseSymbol !== null && bounty.BaseSymbol !== undefined
            && eliminatedSymbols.has( bounty.BaseSymbol )
        );
    }

    /**
     * @ch 過濾掉 Wild 位置，只保留實際為 BaseSymbol 的位置
     */
    private FilterNonWildPositions(
        positions: number[],
        curPlateSymbol: protocol.ar2pq9Proto.IColumn[]
    ): number[]
    {
        return positions.filter( pos =>
        {
            const col = Math.floor( pos / Game_Define.ROW );
            const row = pos % Game_Define.ROW;
            const sym = curPlateSymbol?.[ col ]?.Col?.[ row ] ?? -1;
            return sym !== Game_Define.Symbol.Wild;
        } );
    }

}

