import { _decorator, log, warn, tween } from "cc";
import { stateManager, BaseState, eventManager } from "db://astarte-framework/Managers";
import { Define } from "db://astarte-framework/utilis";
import GameView from "../GameView";
import Game_Define, { FeaturePosQueueType } from "../Game_Define";
import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
import { AudioManager } from "../Audio/AudioManager";
import { Common } from "../Common/Common";
import { BS_SPINE_CTRL_EVENT, BS_SPINE_TYPE, CANNON_ANIM_NAME, CHARACTER_ANIM_NAME } from "../BSSpineCtrl";
import { RT_EVENT } from "../RTCtrl";

const { ccclass } = _decorator;
@ccclass( "AddFreeState" )
export class AddFreeState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : AddFreeState" );

        let roundInfo = this.m_gameView.RoundInfo;
        let addRound = roundInfo.FeverTotalRound - this.m_gameView.FreeTotalRound;

        // 播放音效
        AudioManager.Play(AudioManager.AudioClips.FG_Scatter_trigger);

        // 恢復 scatter effect（AwardState 等 win 期間可能隱藏了）
        this.m_gameView.EffectPlate.SetScatterSpinesVisible( true );

        // 播放 Scatter Collect 動畫
        const positions = this.GetScatterPositions();
        const scatterLevel = this.m_gameView.HasScatterBoost ? 2 : 1;

        let winPromises: Promise<void>[] = [];
        for ( const pos of positions )
        {
            const { col, row } = Common.GetColRowFromPosition( pos );
            this.m_gameView.SlotReels.SetSymbolShow( col, row, false );
            const animPromise = this.m_gameView.EffectPlate.PlayScatterWinAnimation( scatterLevel, col, row, true );
            const timeoutPromise = Define.Wait( this.m_gameView, 3 ).then( () => {} );
            winPromises.push( Promise.race( [ animPromise, timeoutPromise ] ) );
        }
        await Promise.all( winPromises );

        // RT 鎖旋轉：Scatter 演出停在最後一張後鎖，到出場解
        eventManager.Dispatch(RT_EVENT.AWARD_IN_RT);

        // 顯示加局宣告面板（Start → Loop）
        AudioManager.Play(AudioManager.AudioClips.FG_Win_on);
        await Promise.race( [
            this.m_gameView.PopupBoard.ShowMoreSpinsDeclare( addRound ),
            new Promise<void>( r => Define.Wait( this.m_gameView, 3 ).then( () => { warn( "[AddFreeState] WARNING: ShowMoreSpinsDeclare TIMEOUT" ); r(); } ) )
        ] );

        // 面板進場後等 1 秒
        await Define.Wait( this.m_gameView, 1 );

        // 角色 Aim 動畫
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, CHARACTER_ANIM_NAME.Aim, false);
        await Define.Wait( this.m_gameView, 0.5 );

        // 砲台+角色 Win2 + repeat 逐顆加局（pirate2 風格）
        // 每炮固定 0.32s，最多 5 炮；超過 5 局的在最後一炮一次加完
        // 角色動畫：加 1 局播 Win0；2~4 局播 Win2 截斷跳到 1.8s；5+ 局播 Win2 全段
        const fireInterval = 0.32;
        const fireCount = Math.min(addRound, 5);
        let firedCount = 0;

        // 砲台 Win2
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, CANNON_ANIM_NAME.Win2, false);

        // 角色動畫：全部用 Win2，2~4 局砲台結束後截斷跳 1.8s，1 局也截斷，5+ 局全段播完
        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, CHARACTER_ANIM_NAME.Win2, false);

        // 用 Promise 包住 tween repeat 確保等待完成
        // 每發一次砲播放一次 FG_Freespin_Add
        await new Promise<void>((resolve) => {
            tween( this.m_gameView.PopupBoard.node )
                .repeat( fireCount,
                    tween( this.m_gameView.PopupBoard.node )
                        .call( () =>
                        {
                            // 每發砲播一次音效（提前到 delay 前，與砲台動畫同步）
                            AudioManager.Play(AudioManager.AudioClips.FG_Freespin_Add);
                        } )
                        .delay( fireInterval )
                        .call( () =>
                        {
                            firedCount++;
                            const add = (firedCount === fireCount) ? (addRound - (fireCount - 1)) : 1;
                            this.m_gameView.FreeTotalRound += add;
                            this.m_gameView.PopupBoard.SetRound( addRound - firedCount - (add - 1) );
                            eventManager.Dispatch(
                                FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND,
                                this.m_gameView.RoundInfo.FeverNowRound,
                                this.m_gameView.FreeTotalRound
                            );
                        } )
                )
                .call( () => {
                    // 加局結束，砲台回到靜止
                    eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, CANNON_ANIM_NAME.Stop, false);
                    // 角色 Win2 截斷：1~4 局時跳到 1.8s（開槍段結束）讓後半段收尾動作正常播
                    // 5+ 局不截斷，讓 Win2 自然播完
                    if (addRound < 5) {
                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.SKIP_TO_TIME, BS_SPINE_TYPE.CHARACTER, 1.8);
                    }
                    resolve();
                } )
                .start();
        });

        // 播放加局結束動畫
        await Promise.race( [
            this.m_gameView.PopupBoard.PlayMoreSpinsEnd(),
            new Promise<void>( r => Define.Wait( this.m_gameView, 3 ).then( () => { warn( "[AddFreeState] WARNING: PlayMoreSpinsEnd TIMEOUT" ); r(); } ) )
        ] );

        // 恢復 symbol
        for (const pos of positions) {
            const { col, row } = Common.GetColRowFromPosition( pos );
            this.m_gameView.SlotReels.SetSymbolShow( col, row, true );
        }
        this.m_gameView.SlotReels.RestoreHiddenScatterSymbols();
        this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();

        // RT 解鎖：加局演出全部結束
        eventManager.Dispatch(RT_EVENT.AWARD_OUT_RT);

        stateManager.NextState( Game_Define.GameState.AWARD );
    }

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }

    /**
     * @ch 取得最後一個 plate 的 Scatter 位置
     */
    private GetScatterPositions(): number[]
    {
        let positions: number[] = [];
        let plateQueue = this.m_gameView.RoundInfo.PlateQueue;
        if ( !plateQueue || plateQueue.length === 0 ) return positions;

        // 取最後一個 plate 的 Scatter position（消除後 Scatter 可能掉落到新位置）
        const lastPlate = plateQueue[ plateQueue.length - 1 ];
        if ( lastPlate.FeaturePosQueue && lastPlate.FeaturePosQueue.length > 0 )
        {
            const scatterQueue = lastPlate.FeaturePosQueue[ FeaturePosQueueType.Scatter ];
            if ( scatterQueue && scatterQueue.Data && scatterQueue.Data.length > 0 )
            {
                for ( let pos of scatterQueue.Data )
                {
                    if ( positions.indexOf( pos ) === -1 ) positions.push( pos );
                }
            }
        }
        // fallback: ScatterDataVec
        if ( positions.length === 0 && lastPlate.ScatterDataVec && lastPlate.ScatterDataVec.length > 0 )
        {
            for ( let scatter of lastPlate.ScatterDataVec )
            {
                if ( scatter.Pos != null && positions.indexOf( scatter.Pos ) === -1 )
                {
                    positions.push( scatter.Pos );
                }
            }
        }
        return positions;
    }
}

