/**
 * Timeline Event System — 事件派發與 handler 註冊
 */
import type { EventData, EventAction } from "./TimelineData";

export type EventHandler = (event: EventData) => void;

export class TimelineEventBus {
  private handlers = new Map<string, EventHandler[]>();
  private actionHandlers = new Map<EventAction, EventHandler[]>();
  private firedSet = new Set<number>(); // 用 event index 防重複觸發

  /** 註冊特定 key 的 handler */
  on(key: string, handler: EventHandler): void {
    const list = this.handlers.get(key) ?? [];
    list.push(handler);
    this.handlers.set(key, list);
  }

  /** 註冊特定 action 類型的 handler */
  onAction(action: EventAction, handler: EventHandler): void {
    const list = this.actionHandlers.get(action) ?? [];
    list.push(handler);
    this.actionHandlers.set(action, list);
  }

  /** 派發事件（由 player 呼叫） */
  /** 派發事件（由 player 呼叫）。index < 0 表示不做防重複（如 spine event） */
  emit(event: EventData, index: number): void {
    if (index >= 0) {
      if (this.firedSet.has(index)) return;
      this.firedSet.add(index);
    }

    // key-specific handlers
    const keyHandlers = this.handlers.get(event.key);
    if (keyHandlers) keyHandlers.forEach((h) => h(event));

    // action-type handlers
    const actHandlers = this.actionHandlers.get(event.action);
    if (actHandlers) actHandlers.forEach((h) => h(event));
  }

  /** 重置（timeline 重播時呼叫） */
  reset(): void {
    this.firedSet.clear();
  }

  /** 清除所有 handler */
  clear(): void {
    this.handlers.clear();
    this.actionHandlers.clear();
    this.firedSet.clear();
  }
}

