1	/**
2	 * Timeline Executor — Cocos 3.6.2 整合層
3	 * 
4	 * 使用方式：
5	 * 1. 掛在場景節點上
6	 * 2. 把所有會用到的 timeline JSON 拖進 timelines 陣列
7	 *    — targets 會自動根據所有 JSON 的 targetUuid 填入
8	 * 3. Runtime 呼叫 play(index) 或 playByName(name)
9	 */
10	import { _decorator, Component, Node, TextAsset, director, Layers } from "cc";
11	import { TimelinePlayer, ClipChangeInfo, PlayerCallbacks } from "./TimelinePlayer";
12	import { TimelineAsset, EventAction, EventData, TrackData, PlayState } from "./TimelineData";
13	
14	declare const CC_EDITOR: boolean;
15	
16	const { ccclass, property, executeInEditMode } = _decorator;
17	
18	/** 序列化用：trackId → targets 陣列的 index */
19	interface TrackMapping { trackId: string; targetIndex: number; }
20	
21	@ccclass("TimelineExecutor")
22	@executeInEditMode
23	export class TimelineExecutor extends Component {
24	  @property({ type: [TextAsset] })
25	  timelines: TextAsset[] = [];
26	
27	  @property([Node])
28	  targets: Node[] = [];
29	
30	  @property({ visible: false })
31	  private _trackMap: string = "[]"; // JSON string of TrackMapping[]
32	
33	  private player = new TimelinePlayer();
34	  private trackNodeMap = new Map<string, Node>();
35	
36	  onLoad() {
37	    if (CC_EDITOR) this._autoBindTargets();
38	  }
39	
40	  /** 播放第 N 個 timeline */
41	  play(index: number = 0): void {
42	    if (index >= this.timelines.length) { console.warn(`[Executor] No timeline at index ${index}`); return; }
43	    this.playTimeline(JSON.parse(this.timelines[index].text!) as TimelineAsset);
44	  }
45	
46	  /** 用 name 播放 */
47	  playByName(name: string): void {
48	    for (const t of this.timelines) {
49	      if (!t) continue;
50	      const asset = JSON.parse(t.text!) as TimelineAsset;
51	      if (asset.name === name) { this.playTimeline(asset); return; }
52	    }
53	    console.warn(`[Executor] Timeline "${name}" not found`);
54	  }
55	
56	  /** 直接傳入 asset 播放 */
57	  playTimeline(asset: TimelineAsset): void {
58	    this.buildTrackNodeMap(asset);
59	    this.player.load(asset, this.buildCallbacks());
60	    this.registerBuiltinActions();
61	    this.player.play();
62	  }
